                        <TabButton tabId="tax">Tributação</TabButton>
                    </nav>
                </div>

                {/* Aba de Dados Principais */}
                <div className={activeTab === 'main' ? 'block' : 'hidden'}>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-4">
