import ProductLinkModal from './ProductLinkModal';
import { Upload, Link, PlusCircle, CheckCircle, AlertTriangle, ChevronsRight, X, FileQuestion, BadgeCheck, Pencil } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

// --- FUNÇÕES UTILITÁRIAS ---
const normalizeProductName = (name: string): string => {
  return name
    .toLowerCase()
    .replace(/\b(kg|g|ml|l|un|unid|unidade|saco|caixa|pacote|pct|cx)\b/g, '')
    .replace(/\d+[.,]?\d*/g, '')
    .replace(/[^\w\s]/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
};

const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

// --- SUB-COMPONENTES DA UI ---
const StatusBadge: React.FC<{ status: NFeItemStatus }> = ({ status }) => {
    const statusConfig = {
        LINKED: { text: 'Vinculado', color: 'green', icon: BadgeCheck },
        UNLINKED: { text: 'Não Vinculado', color: 'yellow', icon: FileQuestion },
        NEW: { text: 'Novo Produto', color: 'orange', icon: PlusCircle },
    };
    const config = statusConfig[status];
    const Icon = config.icon;
    return (
        <span className={`inline-flex items-center gap-1.5 py-1 px-2.5 rounded-full text-xs font-medium bg-${config.color}-100 text-${config.color}-800 dark:bg-${config.color}-900/50 dark:text-${config.color}-300`}>
            <Icon size={14} />
            {config.text}
        </span>
    );
};


// --- COMPONENTE PRINCIPAL ---
const NFeImport: React.FC = () => {
    const [nfeData, setNfeData] = useState<NFeData | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
    const [linkingItem, setLinkingItem] = useState<{ item: NFeItem; index: number } | null>(null);

    const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        setIsLoading(true);
        setError(null);
        setNfeData(null);
        setSuccess(null);
        setSelectedItems(new Set());

        try {
            const allDbProducts = await db.getAll('products');
            const productMapById = new Map(allDbProducts.map(p => [p.id, p]));
            const productMapByNormalizedName = new Map(allDbProducts.map(p => [normalizeProductName(p.name), p]));

            const fileContent = await file.text();
            const parser = new DOMParser();
            const xmlDoc = parser.parseFromString(fileContent, 'application/xml');

            if (xmlDoc.querySelector('parsererror')) throw new Error('Arquivo XML inválido ou mal formatado.');

            const getTagValue = (parent: Element, tagName: string) => parent.querySelector(tagName)?.textContent || '';
            const ide = xmlDoc.querySelector('ide');
            const emit = xmlDoc.querySelector('emit');
            const prods = xmlDoc.querySelectorAll('det');
            const total = xmlDoc.querySelector('total > ICMSTot > vNF');

            if (!emit || !prods.length || !total || !ide) throw new Error('XML não parece ser uma NF-e válida.');

            const nextYear = new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString().split('T')[0];

            const parsedItems: NFeItem[] = Array.from(prods).map((p): NFeItem => {
                const prodNode = p.querySelector('prod')!;

                const code = getTagValue(prodNode, 'cProd');
                const name = getTagValue(prodNode, 'xProd');
                const ncm = getTagValue(prodNode, 'NCM');
                const quantity = parseFloat(getTagValue(prodNode, 'qCom'));
                const unitPrice = parseFloat(getTagValue(prodNode, 'vUnCom'));
                const totalPrice = parseFloat(getTagValue(prodNode, 'vProd'));

                const foundProduct = productMapById.get(code) || productMapByNormalizedName.get(normalizeProductName(name));

                const baseItemData = {
                    code, name, ncm, quantity, unitPrice, totalPrice,
                    expirationDate: nextYear,
                    conversionFactor: 1,
                };

                if (foundProduct) {
                    return {
                        ...baseItemData,
                        status: 'LINKED',
                        linkedProductDetails: foundProduct,
                    };
                } else {
                    return {
                        ...baseItemData,
                        status: 'UNLINKED',
                        linkedProductDetails: undefined,
                    };
                }
            });

            setNfeData({
                supplier: { cnpj: getTagValue(emit, 'CNPJ'), name: getTagValue(emit, 'xNome') },
                items: parsedItems,
                totalAmount: parseFloat(total.textContent || '0'),
                issueDate: new Date(getTagValue(ide, 'dhEmi')),
            });

        } catch (err) {
            setError((err as Error).message);
        } finally {
            setIsLoading(false);
        }
    };

    const handleItemStatusChange = (index: number, newStatus: NFeItemStatus) => {
        if (!nfeData) return;
        const newItems = [...nfeData.items];
        newItems[index].status = newStatus;
        if (newStatus !== 'LINKED') {
            newItems[index].linkedProductDetails = undefined;
        }
        setNfeData({ ...nfeData, items: newItems });
    };

    const handleSelectionChange = (index: number) => {
        setSelectedItems(prev => {
            const newSet = new Set(prev);
            if (newSet.has(index)) {
                newSet.delete(index);
            } else {
                newSet.add(index);
            }
            return newSet;
        });
    };

    const handleBatchMarkAsNew = () => {
        if (!nfeData) return;
        const newItems = nfeData.items.map((item, index) => {
            if (selectedItems.has(index) && item.status === 'UNLINKED') {
                return { ...item, status: 'NEW' as NFeItemStatus };
            }
            return item;
        });
        setNfeData({ ...nfeData, items: newItems });
        setSelectedItems(new Set());
    };

    const handleOpenLinkModal = (item: NFeItem, index: number) => {
        setLinkingItem({ item, index });
    };

    const handleProductLink = (linkedProduct: Product) => {
        if (!nfeData || linkingItem === null) return;

        const newItems = [...nfeData.items];
        const itemToUpdate = newItems[linkingItem.index];

        itemToUpdate.status = 'LINKED';
        itemToUpdate.linkedProductDetails = linkedProduct;

        setNfeData({ ...nfeData, items: newItems });
        setLinkingItem(null); // Close modal
    };

    const handleConfirmImport = async () => {
        if (!nfeData) return;
        if (nfeData.items.some(p => p.status === 'UNLINKED')) {
            setError("Todos os itens devem ser vinculados ou marcados como 'Novo Produto' antes de importar.");
            return;
        }

        setIsLoading(true);
        setError(null);

        try {
            const tx = db.transaction(['products', 'inventoryLots', 'suppliers', 'expenses'], 'readwrite');
            const productsStore = tx.objectStore('products');
            const lotsStore = tx.objectStore('inventoryLots');
            const suppliersStore = tx.objectStore('suppliers');
            const expensesStore = tx.objectStore('expenses');

            // 1. Processar fornecedor (usando o novo índice 'cnpj')
            let supplierId = '';
            const existingSupplier = await suppliersStore.index('cnpj').get(nfeData.supplier.cnpj!);
            if (existingSupplier) {
                supplierId = existingSupplier.id;
            } else {
                supplierId = uuidv4();
                await suppliersStore.add({ id: supplierId, cnpj: nfeData.supplier.cnpj!, name: nfeData.supplier.name! });
            }

            // 2. Processar produtos e lotes
            for (const item of nfeData.items) {
                let productToUpdate: Product | undefined;

                if (item.status === 'NEW') {
                    // CORREÇÃO DO ERRO "Key already exists":
                    // Verifica se o produto já existe antes de tentar adicioná-lo.
                    const existingProduct = await productsStore.get(item.code);
                    if (existingProduct) {
                         productToUpdate = existingProduct;
                    } else {
                        const newProduct: Product = {
                            id: item.code,
                            name: item.name,
                            price: item.unitPrice * 1.5, // Sugestão de preço de venda
                            costPrice: item.unitPrice / item.conversionFactor,
                            isBulk: false,
                            stock: 0, // Será atualizado pelo lote
                            ncm: item.ncm,
                            image: 'https://picsum.photos/seed/newproduct/200'
                        };
                        await productsStore.add(newProduct);
                        productToUpdate = newProduct;
                    }
                } else if (item.status === 'LINKED') {
                    productToUpdate = await productsStore.get(item.linkedProductDetails!.id);
                }

                if (productToUpdate) {
                    const convertedQuantity = item.quantity * item.conversionFactor;
                    const convertedUnitPrice = item.unitPrice / item.conversionFactor;

                    productToUpdate.costPrice = convertedUnitPrice;
                    productToUpdate.stock = (productToUpdate.stock || 0) + convertedQuantity;
                    await productsStore.put(productToUpdate);

                    await lotsStore.add({
                        id: uuidv4(),
                        productId: productToUpdate.id,
                        quantity: convertedQuantity,
                        entryDate: new Date(),
                        expirationDate: new Date(item.expirationDate),
                        costPrice: convertedUnitPrice
                    });
                }
            }

            await expensesStore.add({
                id: uuidv4(),
                description: `Compra NF-e - Fornecedor: ${nfeData.supplier.name}`,
                amount: nfeData.totalAmount,
                supplierId,
                dueDate: nfeData.issueDate,
                status: 'PENDING'
            });

            await tx.done;
            setSuccess(`Importação concluída! ${nfeData.items.length} itens processados.`);
            setNfeData(null);

        } catch(err) {
            console.error("Erro detalhado na importação:", err);
            setError(`Falha na importação: ${(err as Error).message}. Verifique o console para mais detalhes.`);
        } finally {
            setIsLoading(false);
        }
    };

    const unlinkedCount = useMemo(() => nfeData?.items.filter(i => i.status === 'UNLINKED').length || 0, [nfeData]);

    // Lógica para o "Selecionar Todos"
    const unlinkedIndices = useMemo(() => {
        if (!nfeData) return [];
        return nfeData.items
            .map((item, index) => (item.status === 'UNLINKED' ? index : -1))
            .filter(index => index !== -1);
    }, [nfeData]);

    const areAllSelected = useMemo(() => {
        if (unlinkedIndices.length === 0) return false;
        return unlinkedIndices.every(index => selectedItems.has(index));
    }, [unlinkedIndices, selectedItems]);

    const handleSelectAllChange = () => {
        if (areAllSelected) {
            setSelectedItems(new Set());
        } else {
            setSelectedItems(new Set(unlinkedIndices));
        }
    };

    const handleConversionFactorChange = (index: number, factor: string) => {
        if (!nfeData) return;
        const newItems = [...nfeData.items];
        const newFactor = parseInt(factor, 10);
        newItems[index].conversionFactor = isNaN(newFactor) || newFactor < 1 ? 1 : newFactor;
        setNfeData({ ...nfeData, items: newItems });
    };

    return (
        <div className="space-y-6">
            <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow">
                <h2 className="text-xl font-bold mb-2">Importar Compra (NF-e XML)</h2>
                <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">Carregue o arquivo para dar entrada automática nos produtos, atualizar o estoque e lançar a fatura no contas a pagar.</p>
                <div className="flex items-center gap-4">
                     <label htmlFor="xml-upload" className="flex-grow cursor-pointer">
                        <div className="flex items-center justify-center w-full px-4 py-3 text-center border-2 border-dashed rounded-lg border-gray-300 dark:border-gray-600 hover:border-theme-primary dark:hover:border-theme-primary transition-colors">
                            <Upload className="w-5 h-5 mr-2 text-gray-500"/>
                            <span className="font-medium text-gray-700 dark:text-gray-300">{nfeData ? 'Arquivo Carregado!' : 'Clique aqui para selecionar o arquivo XML'}</span>
                        </div>
                        <input id="xml-upload" type="file" accept=".xml" onChange={handleFileChange} className="hidden"/>
                    </label>
                    {nfeData && <Button variant="danger" onClick={() => setNfeData(null)}><X className="mr-1"/>Cancelar</Button>}
                </div>
            </div>

            {isLoading && <p className="text-center">Processando XML...</p>}
            {error && <div className="p-4 bg-red-100 dark:bg-red-900/50 text-red-700 dark:text-red-200 rounded-lg flex items-center gap-2"><AlertTriangle size={20}/> {error}</div>}
            {success && <div className="p-4 bg-green-100 dark:bg-green-900/50 text-green-700 dark:text-green-200 rounded-lg flex items-center gap-2"><CheckCircle size={20}/> {success}</div>}

            {nfeData && (
                <div className="bg-white dark:bg-gray-800 rounded-lg shadow">
                    <div className="p-4 border-b dark:border-gray-700 space-y-2">
                        <div className="flex justify-between items-center">
                            <h3 className="text-lg font-semibold">Itens da Nota Fiscal ({nfeData.items.length})</h3>
                             <div className="text-sm">
                                <strong>Fornecedor:</strong> {nfeData.supplier.name} | <strong>Total:</strong> {formatCurrency(nfeData.totalAmount)}
                            </div>
                        </div>
                        {unlinkedCount > 0 && (
                            <div className="flex items-center justify-between p-2 bg-yellow-50 dark:bg-yellow-900/40 rounded-md">
                                <p className="text-sm text-yellow-800 dark:text-yellow-200">
                                    <strong className="font-semibold">{unlinkedCount} item(ns)</strong> precisam de sua atenção.
                                </p>
                                <Button size="sm" variant="secondary" onClick={handleBatchMarkAsNew} disabled={selectedItems.size === 0}>
                                    <PlusCircle size={16} className="mr-1"/> Marcar Selecionados como Novos
                                </Button>
                            </div>
                        )}
                    </div>

                    <div className="overflow-auto">
                        <table className="w-full text-sm">
                            <thead className="bg-gray-50 dark:bg-gray-700/50">
                                <tr>
                                    <th className="p-2 w-8 text-center">
                                        <input 
                                            type="checkbox"
                                            checked={areAllSelected}
                                            onChange={handleSelectAllChange}
                                            disabled={unlinkedIndices.length === 0}
                                            title="Selecionar todos os itens não vinculados"
                                            className="cursor-pointer"
                                        />
                                    </th>
                                    <th className="p-2 text-left">Item da NFe</th>
                                    <th className="p-2 text-center w-28">Fator Conv.</th>
                                    <th className="p-2 text-left">Entrada Estoque</th>
                                    <th className="p-2 text-center">Status</th>
                                    <th className="p-2 text-left">Produto no Sistema</th>
                                    <th className="p-2 text-center">Ações</th>
                                </tr>
                            </thead>
                            <tbody>
                                {nfeData.items.map((item, index) => {
                                    const stockEntry = item.quantity * item.conversionFactor;
                                    const newCostPrice = item.unitPrice / item.conversionFactor;
                                    return (
                                    <tr key={index} className="border-b dark:border-gray-700">
                                        <td className="p-2 text-center">
                                            {item.status === 'UNLINKED' && (
                                                <input type="checkbox" checked={selectedItems.has(index)} onChange={() => handleSelectionChange(index)} className="cursor-pointer"/>
                                            )}
                                        </td>
                                        <td className="p-2">
                                            <p className="font-semibold">{item.name}</p>
                                            <p className="text-xs text-gray-500">
                                                {item.quantity} un @ {formatCurrency(item.unitPrice)}
                                            </p>
                                        </td>
                                         <td className="p-2 text-center">
                                            <input
                                                type="number"
                                                value={item.conversionFactor}
                                                onChange={(e) => handleConversionFactorChange(index, e.target.value)}
                                                className="w-20 text-center bg-gray-100 dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-md py-1"
                                                min="1"
                                                disabled={item.status === 'UNLINKED'}
                                            />
                                        </td>
                                        <td className="p-2">
                                            <p className="font-semibold">{stockEntry.toFixed(3)} un</p>
                                            <p className="text-xs text-gray-500">
                                                Custo: {formatCurrency(newCostPrice)}/un
                                            </p>
                                        </td>
                                        <td className="p-2 text-center"><StatusBadge status={item.status} /></td>
                                        <td className="p-2">
                                            {item.status === 'LINKED' && item.linkedProductDetails && (
                                                <div>
                                                     <p className="font-semibold">{item.linkedProductDetails.name}</p>
                                                     <p className="text-xs text-gray-500">ID: {item.linkedProductDetails.id}</p>
                                                </div>
                                            )}
                                        </td>
                                        <td className="p-2">
                                            <div className="flex justify-center gap-1">
                                                {item.status === 'UNLINKED' && (
                                                    <>
                                                        <Button size="sm" variant="secondary" onClick={() => handleItemStatusChange(index, 'NEW')}><PlusCircle size={14} className="mr-1"/>Marcar Novo</Button>
                                                        <Button size="sm" variant="secondary" onClick={() => handleOpenLinkModal(item, index)}><Link size={14} className="mr-1"/>Vincular</Button>
                                                    </>
                                                )}
                                                {(item.status === 'LINKED' || item.status === 'NEW') && (
                                                     <Button size="sm" variant="secondary" onClick={() => handleItemStatusChange(index, 'UNLINKED')}><Pencil size={14} className="mr-1"/>Alterar</Button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                )})}
                            </tbody>
                        </table>
                    </div>

                    <div className="flex justify-end p-4">
                        <Button onClick={handleConfirmImport} variant="success" size="lg" disabled={isLoading || unlinkedCount > 0}>
                            {isLoading ? 'Importando...' : 'Confirmar e Dar Entrada no Estoque'}
                        </Button>
                    </div>
                </div>
            )}

            <ProductLinkModal
                isOpen={linkingItem !== null}
                onClose={() => setLinkingItem(null)}
                onLinkProduct={handleProductLink}
                nfeItem={linkingItem?.item}
            />
        </div>
    );
};

export default NFeImport;

// types.ts
// Este arquivo centraliza todas as definições de tipos e interfaces do sistema,
// garantindo consistência e um único ponto de referência para os modelos de dados.

// Define os possíveis métodos de pagamento aceitos no PDV.
// Usar um enum torna o código mais legível e menos propenso a erros de digitação.
export enum PaymentMethod {
  DINHEIRO = 'Dinheiro',
  PIX = 'PIX',
  DEBITO = 'Débito',
  CREDITO = 'Crédito',
  FIADO = 'Fiado', // Venda a prazo
}

// Interface para um produto no sistema.
// Expandido com campos para o ERP.
export interface Product {
  id: string; // Identificador único do produto (ex: código de barras).
  name: string; // Nome do produto.
  price: number; // Preço de venda unitário.
  costPrice?: number; // Preço de custo (para cálculo de margem).
  isBulk: boolean; // Flag para indicar se é um produto a granel (vendido por peso/kg).
  scaleCode?: string; // Código de 6 dígitos para balanças de pesagem (se 'isBulk' for true).
  stock: number; // Quantidade em estoque.
  minStock?: number; // Quantidade mínima para alerta de recompra.
  ncm?: string; // Nomenclatura Comum do Mercosul (código fiscal).
  cfop?: string; // Código Fiscal de Operações e Prestações.
  origin?: string; // Origem da mercadoria (código numérico).
  csosn_cst?: string; // Código de Situação da Operação no Simples Nacional / Código de Situação Tributária.
  image?: string; // URL da imagem do produto.
  categoryId?: string; // ID da categoria à qual o produto pertence.
  supplierId?: string; // ID do fornecedor padrão deste produto.
}

// Interface para um item dentro do carrinho de compras (e posteriormente, na venda).
export interface SaleItem {
  productId: string; // ID do produto associado.
  productName: string; // Nome do produto (denormalizado para facilitar a exibição).
  productImage?: string; // URL da imagem do produto (denormalizado).
  unitPrice: number; // Preço unitário no momento da venda.
  quantity: number; // Quantidade vendida (pode ser fracionada para produtos a granel).
  discount: number; // Desconto aplicado a este item específico (valor, não percentual).
  total: number; // Preço total do item (unitPrice * quantity - discount).
  lotNumber?: string; // Opcional: Para rastrear de qual lote o item saiu.
  expirationDate?: Date; // Opcional: Data de validade do lote.
}

// Interface para um pagamento realizado em uma venda.
// Uma única venda pode ter múltiplos pagamentos.
export interface Payment {
  method: PaymentMethod; // O método de pagamento utilizado.
  amount: number; // O valor pago com este método.
  customerId?: string; // ID do cliente para vendas 'Fiado'.
}

// Interface que representa uma venda completa.
export interface Sale {
  id: string; // ID único da venda (gerado no momento da finalização).
  date: Date; // Data e hora em que a venda foi concluída.
  items: SaleItem[]; // Lista de itens vendidos.
  subtotal: number; // Soma dos totais de todos os itens antes dos descontos gerais.
  totalDiscount: number; // Desconto aplicado sobre o total da venda.
  totalAmount: number; // Valor final da venda (subtotal - totalDiscount).
  payments: Payment[]; // Lista de pagamentos realizados.
  change: number; // Troco devolvido ao cliente (relevante para pagamento em dinheiro).
  customerCPF?: string; // CPF do cliente (opcional).
  customerId?: string; // ID do cliente associado à venda.
  isSynced: boolean; // Flag para controlar a sincronização com o ERP.
  couponCodeApplied?: string; // Código do cupom usado na venda.
  manualDiscountType?: 'PERCENTAGE' | 'FIXED_AMOUNT'; // Tipo de desconto manual.
  manualDiscountValue?: number; // Valor do desconto manual.
}

// Interface para um carrinho salvo (venda pendente).
export interface ParkedSale {
  id: string;
  createdAt: Date;
  items: SaleItem[];
  total: number;
  customerId?: string;
  customerName?: string;
  notes?: string;
}


// Interface para uma transação de caixa (reforço ou sangria).
export interface CashTransaction {
  type: 'SUPRIMENTO' | 'SANGRIA' | 'REFORCO'; // Tipo de transação.
  amount: number; // Valor da transação.
  date: Date; // Data e hora da transação.
  description: string; // Motivo/descrição da transação.
}

// Interface que representa uma sessão (turno) de caixa.
export interface CashSession {
  id: 'active' | string; // ID da sessão. 'active' é um ID especial para a sessão em andamento.
  startDate: Date; // Data e hora de abertura.
  endDate?: Date; // Data e hora de fechamento (opcional).
  initialAmount: number; // Valor inicial de troco (suprimento).
  transactions: CashTransaction[]; // Lista de suprimentos, sangrias e reforços.
  sales: Sale[]; // Lista de todas as vendas realizadas na sessão.
  status: 'OPEN' | 'CLOSED'; // Status da sessão.
}


// --- NOVOS TIPOS PARA O MÓULO ERP ---

// Interface para uma Categoria de Produto.
export interface Category {
  id: string;
  name: string;
}

// Interface para um Fornecedor.
export interface Supplier {
    id: string; // ID único (pode ser gerado com uuid).
    name: string; // Nome do fornecedor.
    cnpj: string; // CNPJ do fornecedor.
    contactPerson?: string; // Pessoa de contato.
    phone?: string; // Telefone.
    email?: string; // E-mail.
}

// Interface para um Cliente.
export interface Customer {
    id: string; // ID único.
    name: string; // Nome do cliente.
    cpf: string; // CPF do cliente.
    phone?: string; // Telefone.
    email?: string; // E-mail.
    address?: string; // Endereço.
    birthDate?: Date; // Data de nascimento.
    creditLimit?: number; // Limite de crédito para vendas 'Fiado'.
}

// Interface para uma Despesa (Contas a Pagar).
export interface Expense {
    id: string; // ID único.
    description: string; // Descrição da despesa.
    amount: number; // Valor da despesa.
    supplierId?: string; // ID do fornecedor associado.
    dueDate: Date; // Data de vencimento.
    paidDate?: Date; // Data de pagamento (se já foi paga).
    status: 'PENDING' | 'PAID'; // Status da conta.
}


// --- NOVOS TIPOS PARA O MÓDULO DE ESTOQUE ---

// Interface para um Lote de Inventário.
// Cada entrada de um produto no estoque (compra) gera um lote.
export interface InventoryLot {
  id: string; // ID único do lote.
  productId: string; // ID do produto ao qual o lote pertence.
  quantity: number; // Quantidade de itens/kg neste lote.
  expirationDate?: Date; // Data de validade do lote.
  entryDate: Date; // Data em que o lote entrou no estoque.
  costPrice: number; // Preço de custo unitário neste lote.
}

// Interface para um Ajuste Manual de Inventário.
// Registra entradas ou saídas manuais para acerto de contagem.
export interface InventoryAdjustment {
  id: string; // ID único do ajuste.
  productId: string; // ID do produto ajustado.
  lotId: string; // ID do lote que foi ajustado.
  quantityChange: number; // A mudança na quantidade (positiva para entrada, negativa para saída).
  reason: string; // Motivo do ajuste (ex: "Contagem de inventário", "Perda").
  date: Date; // Data do ajuste.
}


// --- NOVOS TIPOS PARA O MÓDULO CRM ---

// Interface para um Cupom de Desconto.
export interface Coupon {
  id: string;
  code: string; // Código do cupom (ex: VERAO10)
  type: 'PERCENTAGE' | 'FIXED_AMOUNT';
  value: number; // Valor do desconto (10 para 10% ou 10 para R$10)
  expiryDate: Date;
  maxUses: number; // Limite de usos totais.
  currentUses: number; // Quantos usos já foram feitos.
  isActive: number; // 1 para ativo, 0 para inativo.
}

// Define os tipos de regras de segmentação disponíveis.
export type SegmentRuleType = 
    | 'BIRTHDAY_MONTH' // Aniversariantes do mês
    | 'INACTIVE_CUSTOMERS' // Clientes inativos
    | 'VIP_CUSTOMERS' // Clientes com alto valor de compra
    | 'PRODUCT_BUYERS'; // Compradores de um produto específico

// Interface para uma regra de segmentação.
export interface SegmentRule {
    type: SegmentRuleType;
    // Parâmetros opcionais dependendo do tipo de regra.
    // Ex: para 'INACTIVE_CUSTOMERS', value pode ser o número de dias.
    // Ex: para 'VIP_CUSTOMERS', value pode ser o valor mínimo gasto.
    // Ex: para 'PRODUCT_BUYERS', value pode ser o ID do produto.
    value?: number | string; 
}

// Interface para um Segmento de Clientes.
export interface Segment {
    id: string; // ID único do segmento.
    name: string; // Nome do segmento (ex: "Clientes Sumidos").
    rules: SegmentRule[]; // Conjunto de regras que definem o segmento.
    description: string; // Descrição do que o segmento representa.
}

// Define os canais de comunicação para as campanhas.
export type CampaignChannel = 'EMAIL' | 'WHATSAPP';

// Interface para uma Campanha de Marketing.
export interface Campaign {
    id: string; // ID único da campanha.
    name: string; // Nome da campanha.
    segmentId: string; // ID do segmento de público-alvo.
    channel: CampaignChannel; // Canal de envio (Email ou WhatsApp).
    subject?: string; // Assunto (para campanhas de Email).
    messageTemplate: string; // O conteúdo da mensagem com variáveis (ex: "[Nome do Cliente]").
    status: 'DRAFT' | 'SENT'; // Status da campanha.
}

// Define os tipos de gatilhos para automações.
export type AutomationTriggerType = 'NEW_CUSTOMER' | 'CUSTOMER_BIRTHDAY';

// Interface para uma Regra de Automação.
export interface AutomationRule {
    id: string; // ID único da regra.
    name: string; // Nome da automação (ex: "Boas-vindas ao novo cliente").
    trigger: AutomationTriggerType; // O gatilho que dispara a ação.
    campaignId: string; // A campanha a ser enviada quando o gatilho é ativado.
    // Fix: Changed isActive from boolean to number to be a valid IndexedDB key.
    isActive: number; // Flag para ativar/desativar a automação (1 for true, 0 for false).
}

// --- NOVOS TIPOS PARA IMPORTAÇÃO DE NF-e ---

export type NFeItemStatus = 'LINKED' | 'UNLINKED' | 'NEW';

export interface NFeItem {
  code: string;
  name: string;
  ncm: string;
  quantity: number;
  unitPrice: number;
  totalPrice: number;
  expirationDate: string;
  conversionFactor: number; // Fator de conversão (ex: 1 caixa = 12 unidades)
  // Campos para a UI
  status: NFeItemStatus;
  linkedProductDetails?: Product;
}

export interface NFeData {
