import type { Expense, Supplier } from '../../types';
import Button from '../shared/Button';
import { PlusCircle, Edit, Trash2, Filter, AlertCircle, CheckCircle, Clock } from 'lucide-react';

interface ExpenseManagementProps {
    onNewExpense: () => void;
    onEditExpense: (id: string) => void;
}

const ExpenseManagement: React.FC<ExpenseManagementProps> = ({ onNewExpense, onEditExpense }) => {
    const [expenses, setExpenses] = useState<Expense[]>([]);
    const [suppliers, setSuppliers] = useState<Map<string, string>>(new Map());
    const [filterStatus, setFilterStatus] = useState<'ALL' | 'PENDING' | 'PAID' | 'OVERDUE'>('ALL');

    const fetchData = useCallback(async () => {
        const [allExpenses, allSuppliers] = await Promise.all([
            db.getAll('expenses'),
            db.getAll('suppliers')
        ]);

        // Mapeia ID -> Nome do fornecedor para exibição rápida
        const supplierMap = new Map<string, string>();
        allSuppliers.forEach(s => supplierMap.set(s.id, s.name));
        setSuppliers(supplierMap);

        // Ordena por vencimento (mais recentes/próximos primeiro)
        setExpenses(allExpenses.sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime()));
    }, []);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleDelete = async (id: string) => {
        if (confirm('Tem certeza que deseja excluir esta despesa?')) {
            await db.delete('expenses', id);
            fetchData();
        }
    };

    const handleMarkAsPaid = async (expense: Expense) => {
        const updatedExpense = { ...expense, status: 'PAID' as const, paidDate: new Date() };
        await db.put('expenses', updatedExpense);
        fetchData();
    };

    // --- LÓGICA DE FILTRAGEM E CÁLCULO ---
    const today = new Date();
    today.setHours(0,0,0,0);

    const filteredExpenses = useMemo(() => {
        return expenses.filter(exp => {
            const dueDate = new Date(exp.dueDate);
            dueDate.setHours(0,0,0,0);

            if (filterStatus === 'ALL') return true;
            if (filterStatus === 'PAID') return exp.status === 'PAID';
            if (filterStatus === 'PENDING') return exp.status === 'PENDING';
            if (filterStatus === 'OVERDUE') return exp.status === 'PENDING' && dueDate < today;
            return true;
        });
    }, [expenses, filterStatus, today]);

    const totals = useMemo(() => {
        let pending = 0;
        let overdue = 0;
        let paid = 0;

        expenses.forEach(exp => {
            const dueDate = new Date(exp.dueDate);
            dueDate.setHours(0,0,0,0);

            if (exp.status === 'PAID') {
                paid += exp.amount;
            } else {
                pending += exp.amount;
                if (dueDate < today) {
                    overdue += exp.amount;
                }
            }
        });
        return { pending, overdue, paid };
    }, [expenses, today]);

    const formatCurrency = (val: number) => val.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
    const formatDate = (date: Date) => new Date(date).toLocaleDateString('pt-BR');

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <h2 className="text-2xl font-semibold">Contas a Pagar</h2>
                <Button onClick={onNewExpense}><PlusCircle size={18}/> Nova Despesa</Button>
            </div>

            {/* DASHBOARD RESUMO */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow border-l-4 border-blue-500">
                    <p className="text-sm text-gray-500 dark:text-gray-400">Total Pendente (Geral)</p>
                    <p className="text-2xl font-bold text-blue-600">{formatCurrency(totals.pending)}</p>
                </div>
                <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow border-l-4 border-red-500">
                    <p className="text-sm text-gray-500 dark:text-gray-400">Vencido / Atrasado</p>
                    <p className="text-2xl font-bold text-red-600">{formatCurrency(totals.overdue)}</p>
                </div>
                <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow border-l-4 border-green-500">
                    <p className="text-sm text-gray-500 dark:text-gray-400">Pago (Total Histórico)</p>
                    <p className="text-2xl font-bold text-green-600">{formatCurrency(totals.paid)}</p>
                </div>
            </div>

            {/* BARRA DE FILTROS */}
            <div className="flex gap-2 overflow-x-auto pb-2">
                <button onClick={() => setFilterStatus('ALL')} className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${filterStatus === 'ALL' ? 'bg-gray-800 text-white dark:bg-gray-200 dark:text-gray-900' : 'bg-gray-200 text-gray-700 dark:bg-gray-700 dark:text-gray-300'}`}>
                    Todas
                </button>
                <button onClick={() => setFilterStatus('PENDING')} className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${filterStatus === 'PENDING' ? 'bg-blue-600 text-white' : 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300'}`}>
                    Pendentes
                </button>
                <button onClick={() => setFilterStatus('OVERDUE')} className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${filterStatus === 'OVERDUE' ? 'bg-red-600 text-white' : 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300'}`}>
                    Vencidas
                </button>
                 <button onClick={() => setFilterStatus('PAID')} className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${filterStatus === 'PAID' ? 'bg-green-600 text-white' : 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300'}`}>
                    Pagas
                </button>
            </div>

            {/* TABELA DE DESPESAS */}
            <div className="overflow-x-auto bg-white dark:bg-gray-800 rounded-lg shadow">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 dark:bg-gray-700 dark:text-gray-400">
                        <tr>
                            <th className="px-6 py-3">Descrição</th>
                            <th className="px-6 py-3">Fornecedor</th>
                            <th className="px-6 py-3">Vencimento</th>
                            <th className="px-6 py-3 text-right">Valor</th>
                            <th className="px-6 py-3 text-center">Status</th>
                            <th className="px-6 py-3 text-center">Ações</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredExpenses.map(expense => {
                            const dueDate = new Date(expense.dueDate);
                            dueDate.setHours(0,0,0,0);
                            const isOverdue = expense.status === 'PENDING' && dueDate < today;

                            return (
                                <tr key={expense.id} className="border-b dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600/20">
                                    <td className="px-6 py-3 font-medium">{expense.description}</td>
                                    <td className="px-6 py-3">{expense.supplierId ? suppliers.get(expense.supplierId) || 'Fornecedor Excluído' : '-'}</td>
                                    <td className={`px-6 py-3 ${isOverdue ? 'text-red-600 font-bold' : ''}`}>
                                        {formatDate(expense.dueDate)}
                                        {isOverdue && <span className="text-xs block">Vencido</span>}
                                    </td>
                                    <td className="px-6 py-3 text-right font-mono text-base">{formatCurrency(expense.amount)}</td>
                                    <td className="px-6 py-3 text-center">
                                        {expense.status === 'PAID' ? (
                                            <span className="inline-flex items-center gap-1 text-green-600 bg-green-100 dark:bg-green-900/30 px-2 py-1 rounded-full text-xs font-semibold">
                                                <CheckCircle size={14}/> Pago
                                            </span>
                                        ) : isOverdue ? (
                                             <span className="inline-flex items-center gap-1 text-red-600 bg-red-100 dark:bg-red-900/30 px-2 py-1 rounded-full text-xs font-semibold">
                                                <AlertCircle size={14}/> Atrasado
                                            </span>
                                        ) : (
                                            <span className="inline-flex items-center gap-1 text-blue-600 bg-blue-100 dark:bg-blue-900/30 px-2 py-1 rounded-full text-xs font-semibold">
                                                <Clock size={14}/> Aberto
                                            </span>
                                        )}
                                    </td>
                                    <td className="px-6 py-3 text-center">
                                        <div className="flex justify-center gap-2">
                                            {expense.status === 'PENDING' && (
                                                <Button size="sm" variant="success" className="p-2 h-auto" onClick={() => handleMarkAsPaid(expense)} title="Marcar como Pago">
                                                    <DollarSign size={16} />
                                                </Button>
                                            )}
                                            <Button variant="secondary" size="sm" className="p-2 h-auto" onClick={() => onEditExpense(expense.id)}><Edit size={16}/></Button>
                                            <Button variant="danger" size="sm" className="p-2 h-auto" onClick={() => handleDelete(expense.id)}><Trash2 size={16}/></Button>
                                        </div>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
                {filteredExpenses.length === 0 && (
                    <div className="text-center p-8 text-gray-500">
                        Nenhuma conta encontrada com este filtro.
                    </div>
                )}
            </div>
        </div>
    );
};

export default ExpenseManagement;

import React, { useState, useEffect } from 'react';
import { ShoppingCart, Users, BarChart, FileText, Boxes, ChevronDown, ChevronUp, ArrowLeft } from 'lucide-react';
import { db } from '../../services/databaseService';
import type { Category } from '../../types';
import Button from '../shared/Button';

// Importa os componentes de cada módulo do ERP
import ProductManagement from './ProductManagement';
import CategoryManagement from './CategoryManagement';
import NFeImport from './NFeImport';
import InventoryReport from './InventoryReport';
import CustomerManagement from './CustomerManagement';
import ProductFormPage from './ProductFormPage';
import CustomerFormPage from './CustomerFormPage'; 
import CategoryFormPage from './CategoryFormPage'; 
import GenerateOrder from './GenerateOrder'; 
import ExpenseManagement from './ExpenseManagement'; // Importa novo componente
import ExpenseFormPage from './ExpenseFormPage'; // Importa novo componente

interface ERPScreenProps {
    setView: (view: 'pos' | 'erp' | 'crm' | 'fiscal') => void;
}

type ActiveModule = 'products' | 'categories' | 'customers' | 'suppliers' | 'financial' | 'expenses' | 'reports' | 'nfeImport' | 'inventory' | 'generateOrder';

// Novo tipo para controlar a visualização dentro do ERP
type ERPView = 
  | { type: 'module', id: ActiveModule }
  | { type: 'product_form', productId?: string }
  | { type: 'customer_form', customerId?: string }
  | { type: 'category_form', categoryId?: string }
  | { type: 'expense_form', expenseId?: string }; // Adicionado novo tipo de form


// Estrutura do menu refatorada com módulos agrupados
interface MenuItem {
    id: ActiveModule;
    label: string;
}

interface MenuModule {
    id: string;
    label: string;
    icon: React.ElementType;
    items: MenuItem[];
}

const menuModules: MenuModule[] = [
    {
        id: 'estoque',
        label: 'Estoque',
        icon: Boxes,
        items: [
            { id: 'products', label: 'Produtos' },
            { id: 'categories', label: 'Categorias' },
            { id: 'inventory', label: 'Inventário' },
        ],
    },
    {
        id: 'compras',
        label: 'Compras',
        icon: ShoppingCart,
        items: [
            { id: 'generateOrder', label: 'Pedidos' },
            { id: 'nfeImport', label: 'Importar NF-e' },
        ],
    },
    {
        id: 'clientes',
        label: 'Clientes',
        icon: Users,
        items: [
            { id: 'customers', label: 'Clientes' },
        ],
    },
    {
        id: 'financeiro',
        label: 'Financeiro',
        icon: BarChart,
        items: [
            { id: 'financial', label: 'Visão Geral' },
            { id: 'expenses', label: 'Contas a Pagar' }, // Novo item de menu
        ],
    },
    {
        id: 'relatorios',
        label: 'Relatórios',
        icon: FileText,
        items: [
            { id: 'reports', label: 'Relatórios' },
        ],
    },
];

// Componente principal para a tela de Retaguarda (ERP).
const ERPScreen: React.FC<ERPScreenProps> = ({ setView }) => {
    const [currentErpView, setCurrentErpView] = useState<ERPView>({ type: 'module', id: 'products' });
    const [expandedSections, setExpandedSections] = useState<Set<string>>(new Set(['estoque', 'compras', 'financeiro']));
    const [categories, setCategories] = useState<Category[]>([]);

    useEffect(() => {
        db.getAll('categories').then(cats => setCategories(cats.sort((a,b) => a.name.localeCompare(b.name))));
    }, []);

    const toggleSection = (sectionId: string) => {
        setExpandedSections(prev => {
            const newSet = new Set(prev);
            if (newSet.has(sectionId)) newSet.delete(sectionId);
            else newSet.add(sectionId);
            return newSet;
        });
    };

    const renderActiveModule = () => {
        switch(currentErpView.type) {
            case 'product_form':
                return <ProductFormPage 
                    productId={currentErpView.productId} 
                    categories={categories} 
                    onBack={() => setCurrentErpView({ type: 'module', id: 'products' })} 
                />;
            case 'customer_form':
                return <CustomerFormPage 
                    customerId={currentErpView.customerId} 
                    onBack={() => setCurrentErpView({ type: 'module', id: 'customers' })} 
                />;
            case 'category_form':
                return <CategoryFormPage 
                    categoryId={currentErpView.categoryId} 
                    onBack={() => setCurrentErpView({ type: 'module', id: 'categories' })} 
                />;
            case 'expense_form': // Renderiza o form de despesa
                return <ExpenseFormPage 
                    expenseId={currentErpView.expenseId} 
                    onBack={() => setCurrentErpView({ type: 'module', id: 'expenses' })} 
                />;
            case 'module':
                switch(currentErpView.id) {
                    case 'products':
                        return <ProductManagement 
                            onNewProduct={() => setCurrentErpView({ type: 'product_form' })}
                            onEditProduct={(id) => setCurrentErpView({ type: 'product_form', productId: id })}
                        />;
                    case 'categories':
                        return <CategoryManagement 
                            onNewCategory={() => setCurrentErpView({ type: 'category_form' })}
                            onEditCategory={(id) => setCurrentErpView({ type: 'category_form', categoryId: id })}
                        />;
                    case 'customers':
                        return <CustomerManagement 
                            onNewCustomer={() => setCurrentErpView({ type: 'customer_form' })}
                            onEditCustomer={(id) => setCurrentErpView({ type: 'customer_form', customerId: id })}
                        />;
                    case 'expenses': // Renderiza a lista de despesas
                        return <ExpenseManagement 
                            onNewExpense={() => setCurrentErpView({ type: 'expense_form' })}
                            onEditExpense={(id) => setCurrentErpView({ type: 'expense_form', expenseId: id })}
                        />;
                    case 'nfeImport': return <NFeImport />;
                    case 'generateOrder': return <GenerateOrder />;
                    case 'inventory': return <InventoryReport />;
                    default:
                        return <div className="p-8"><h2 className="text-2xl font-semibold">Módulo em construção</h2><p>Esta funcionalidade ainda não foi implementada.</p></div>;
                }
        }
    };

    const getHeaderInfo = () => {
        switch(currentErpView.type) {
            case 'product_form': return { title: currentErpView.productId ? 'Editar Produto' : 'Novo Produto', activeModule: 'products' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'products' }) };
            case 'customer_form': return { title: currentErpView.customerId ? 'Editar Cliente' : 'Novo Cliente', activeModule: 'customers' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'customers' }) };
            case 'category_form': return { title: currentErpView.categoryId ? 'Editar Categoria' : 'Nova Categoria', activeModule: 'categories' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'categories' }) };
            case 'expense_form': return { title: currentErpView.expenseId ? 'Editar Despesa' : 'Nova Conta a Pagar', activeModule: 'expenses' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'expenses' }) };
            case 'module':
            default:
                const label = menuModules.flatMap(m => m.items).find(i => i.id === currentErpView.id)?.label || 'Dashboard';
                return { title: label, activeModule: currentErpView.id, backAction: null };
        }
    };

    const { title, activeModule, backAction } = getHeaderInfo();

    return (
        <div className="flex flex-col md:flex-row h-full bg-gray-100 dark:bg-gray-900">
            {/* 
                MENU RESPONSIVO: 
                - Mobile: Barra horizontal rolável no topo
                - Desktop: Sidebar vertical à esquerda
            */}
            <aside className="
                w-full md:w-64 
                bg-white dark:bg-gray-800 
                shadow-md md:shadow-none md:border-r dark:border-gray-700
                flex flex-col
                order-1
            ">
                <div className="hidden md:block p-4 border-b dark:border-gray-700">
                    <h1 className="text-xl font-bold text-gray-800 dark:text-gray-100">Gestão ERP</h1>
                    <span className="text-sm text-gray-500">UseNatural</span>
                </div>

                {/* Container de navegação */}
                <nav className="flex-grow md:p-2 overflow-x-auto md:overflow-y-auto whitespace-nowrap md:whitespace-normal">
                    <ul className="flex md:flex-col p-2 md:p-0 gap-2 md:gap-1 items-center md:items-stretch">
                        {menuModules.map(module => {
                            const isExpanded = expandedSections.has(module.id);
                            return (
                                <li key={module.id} className="inline-flex md:block md:flex-col">
                                    {/* Botão do Módulo (Cabeçalho da Seção) - Hidden on Mobile */}
                                    <button 
                                        onClick={() => toggleSection(module.id)} 
                                        className="hidden md:flex items-center justify-between w-full gap-3 px-4 py-2 rounded-md text-sm font-semibold transition-colors text-gray-700 hover:bg-gray-100 dark:text-gray-200 dark:hover:bg-gray-700 focus:outline-none"
                                    >
                                        <div className="flex items-center gap-3"><module.icon className="w-5 h-5" /><span>{module.label}</span></div>
                                        {isExpanded ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                                    </button>

                                    {/* Lista de Itens do Módulo 
                                        CORREÇÃO CRÍTICA: 
                                        - Mobile (padrão): 'flex' (sempre visível, layout horizontal).
                                        - Desktop (md): 'hidden' se não expandido, 'block' se expandido.
                                    */}
                                    <ul className={`
                                        flex flex-row md:flex-col gap-2 md:gap-1 md:pl-6 md:mt-1
                                        ${!isExpanded ? 'md:hidden' : 'md:block'}
                                    `}>
                                        {module.items.map(item => (
                                            <li key={item.id} className="inline-block md:block">
                                                <a 
                                                    href="#" 
                                                    onClick={(e) => { e.preventDefault(); setCurrentErpView({ type: 'module', id: item.id }); }} 
                                                    className={`
                                                        flex items-center gap-2 px-3 py-2 md:px-4 rounded-md text-sm font-medium transition-colors border md:border-0
                                                        ${activeModule === item.id 
                                                            ? 'bg-theme-primary text-white md:bg-theme-primary/10 md:text-theme-primary border-theme-primary' 
                                                            : 'bg-gray-50 text-gray-600 border-gray-200 hover:bg-gray-100 dark:bg-gray-700 dark:border-gray-600 dark:text-gray-300 dark:hover:bg-gray-600'}
                                                    `}
                                                >
                                                    {/* Ícone no mobile para ajudar contexto, já que o cabeçalho está oculto */}
                                                    <span className="md:hidden opacity-70">
                                                        <module.icon size={14} />
                                                    </span>
                                                    <span>{item.label}</span>
                                                </a>
                                            </li>
                                        ))}
                                    </ul>
                                </li>
                            );
                        })}
                    </ul>
                </nav>
            </aside>

            {/* CONTEÚDO PRINCIPAL */}
            <main className="flex-1 flex flex-col overflow-hidden order-2 h-full">
                <header className="bg-white dark:bg-gray-800 shadow-sm p-4 flex items-center gap-4 shrink-0">
                    {backAction && (
                        <Button variant="secondary" onClick={backAction} className="!py-2 !px-3">
                            <ArrowLeft size={16} className="mr-2"/> Voltar
                        </Button>
                    )}
                    <h2 className="text-xl md:text-2xl font-bold text-gray-800 dark:text-gray-100 capitalize truncate">{title}</h2>
                </header>
                <div className="flex-1 overflow-y-auto p-4 md:p-6">
                    {renderActiveModule()}
                </div>
            </main>
        </div>
    );
};

export default ERPScreen;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { db } from '../../services/databaseService';
import type { Expense, Supplier } from '../../types';
import Button from '../shared/Button';
import { PlusCircle, Edit, Trash2, Filter, AlertCircle, CheckCircle, Clock, DollarSign } from 'lucide-react';

interface ExpenseManagementProps {
    onNewExpense: () => void;
    onEditExpense: (id: string) => void;
}

const ExpenseManagement: React.FC<ExpenseManagementProps> = ({ onNewExpense, onEditExpense }) => {
    const [expenses, setExpenses] = useState<Expense[]>([]);
    const [suppliers, setSuppliers] = useState<Map<string, string>>(new Map());
    const [filterStatus, setFilterStatus] = useState<'ALL' | 'PENDING' | 'PAID' | 'OVERDUE'>('ALL');

    const fetchData = useCallback(async () => {
        const [allExpenses, allSuppliers] = await Promise.all([
            db.getAll('expenses'),
            db.getAll('suppliers')
        ]);

        // Mapeia ID -> Nome do fornecedor para exibição rápida
        const supplierMap = new Map<string, string>();
        allSuppliers.forEach(s => supplierMap.set(s.id, s.name));
        setSuppliers(supplierMap);

        // Ordena por vencimento (mais recentes/próximos primeiro)
        setExpenses(allExpenses.sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime()));
    }, []);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleDelete = async (id: string) => {
        if (confirm('Tem certeza que deseja excluir esta despesa?')) {
            await db.delete('expenses', id);
            fetchData();
        }
    };

    const handleMarkAsPaid = async (expense: Expense) => {
        const updatedExpense = { ...expense, status: 'PAID' as const, paidDate: new Date() };
        await db.put('expenses', updatedExpense);
        fetchData();
    };

    // --- LÓGICA DE FILTRAGEM E CÁLCULO ---
    const today = new Date();
    today.setHours(0,0,0,0);

    const filteredExpenses = useMemo(() => {
        return expenses.filter(exp => {
            const dueDate = new Date(exp.dueDate);
            dueDate.setHours(0,0,0,0);

            if (filterStatus === 'ALL') return true;
            if (filterStatus === 'PAID') return exp.status === 'PAID';
            if (filterStatus === 'PENDING') return exp.status === 'PENDING';
            if (filterStatus === 'OVERDUE') return exp.status === 'PENDING' && dueDate < today;
            return true;
        });
    }, [expenses, filterStatus, today]);

    const totals = useMemo(() => {
        let pending = 0;
        let overdue = 0;
        let paid = 0;

        expenses.forEach(exp => {
            const dueDate = new Date(exp.dueDate);
            dueDate.setHours(0,0,0,0);

            if (exp.status === 'PAID') {
                paid += exp.amount;
            } else {
                pending += exp.amount;
                if (dueDate < today) {
                    overdue += exp.amount;
                }
            }
        });
        return { pending, overdue, paid };
    }, [expenses, today]);

    const formatCurrency = (val: number) => val.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
    const formatDate = (date: Date) => new Date(date).toLocaleDateString('pt-BR');

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <h2 className="text-2xl font-semibold">Contas a Pagar</h2>
                <Button onClick={onNewExpense}><PlusCircle size={18}/> Nova Despesa</Button>
            </div>

            {/* DASHBOARD RESUMO */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow border-l-4 border-blue-500">
                    <p className="text-sm text-gray-500 dark:text-gray-400">Total Pendente (Geral)</p>
                    <p className="text-2xl font-bold text-blue-600">{formatCurrency(totals.pending)}</p>
                </div>
                <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow border-l-4 border-red-500">
                    <p className="text-sm text-gray-500 dark:text-gray-400">Vencido / Atrasado</p>
                    <p className="text-2xl font-bold text-red-600">{formatCurrency(totals.overdue)}</p>
                </div>
                <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow border-l-4 border-green-500">
                    <p className="text-sm text-gray-500 dark:text-gray-400">Pago (Total Histórico)</p>
                    <p className="text-2xl font-bold text-green-600">{formatCurrency(totals.paid)}</p>
                </div>
            </div>

            {/* BARRA DE FILTROS */}
            <div className="flex gap-2 overflow-x-auto pb-2">
