import React, { useState, useEffect, useMemo } from 'react';
import Modal from '../shared/Modal';
import Button from '../shared/Button';
import { PaymentMethod } from '../../types';
import type { Payment } from '../../types';
import { DollarSign, Smartphone, CreditCard, User, Check, ArrowRight, Wallet } from 'lucide-react';

interface PaymentModalProps {
  isOpen: boolean;
  onClose: () => void;
  totalAmount: number;
  onFinalize: (payments: Payment[], change: number) => void;
}

const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

const PaymentModal: React.FC<PaymentModalProps> = ({ isOpen, onClose, totalAmount, onFinalize }) => {
  // Estado para armazenar os valores de cada método como string para facilitar a digitação
  const [methodValues, setMethodValues] = useState<Record<PaymentMethod, string>>({
    [PaymentMethod.DINHEIRO]: '',
    [PaymentMethod.PIX]: '',
    [PaymentMethod.DEBITO]: '',
    [PaymentMethod.CREDITO]: '',
    [PaymentMethod.FIADO]: '',
  });

  // Reseta ao abrir
  useEffect(() => {
    if (isOpen) {
      setMethodValues({
        [PaymentMethod.DINHEIRO]: '',
        [PaymentMethod.PIX]: '',
        [PaymentMethod.DEBITO]: '',
        [PaymentMethod.CREDITO]: '',
        [PaymentMethod.FIADO]: '',
      });
    }
  }, [isOpen]);

  // Converte as strings para números e calcula o total recebido
  const totalReceived = useMemo(() => {
    return Object.values(methodValues).reduce((sum, val) => {
      const num = parseFloat(val.replace(',', '.')) || 0;
      return sum + num;
    }, 0);
  }, [methodValues]);

  const remaining = Math.max(0, totalAmount - totalReceived);
  const change = Math.max(0, totalReceived - totalAmount);
  const isPaid = totalReceived >= totalAmount - 0.001; // Tolerância para float

  const handleValueChange = (method: PaymentMethod, value: string) => {
    // Permite apenas números, vírgula e ponto
    if (/^[0-9.,]*$/.test(value)) {
      setMethodValues(prev => ({ ...prev, [method]: value }));
    }
  };

  const fillRemaining = (method: PaymentMethod) => {
    if (remaining > 0) {
      const currentVal = parseFloat(methodValues[method].replace(',', '.')) || 0;
      const newVal = (currentVal + remaining).toFixed(2).replace('.', ',');
      setMethodValues(prev => ({ ...prev, [method]: newVal }));
    }
  };

  const clearMethod = (method: PaymentMethod) => {
    setMethodValues(prev => ({ ...prev, [method]: '' }));
  };

  const handleFinalize = () => {
    if (!isPaid) return;

    // Converte o objeto de valores para o array de pagamentos esperado pela API
    const payments: Payment[] = Object.entries(methodValues)
      .map(([method, value]) => ({
        method: method as PaymentMethod,
        amount: parseFloat(value.replace(',', '.')) || 0
      }))
      .filter(p => p.amount > 0);

    onFinalize(payments, change);
  };

  const getMethodIcon = (method: PaymentMethod) => {
    switch (method) {
      case PaymentMethod.DINHEIRO: return <Wallet size={20} className="text-green-600" />;
      case PaymentMethod.PIX: return <Smartphone size={20} className="text-theme-green" />;
      case PaymentMethod.DEBITO: return <CreditCard size={20} className="text-theme-darkblue" />;
      case PaymentMethod.CREDITO: return <CreditCard size={20} className="text-theme-secondary" />;
      case PaymentMethod.FIADO: return <User size={20} className="text-red-500" />;
      default: return <DollarSign size={20} />;
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Finalizar Pagamento"
      footer={
        <>
          <Button variant="secondary" onClick={onClose}>Cancelar</Button>
          <Button 
            variant="success" 
            onClick={handleFinalize} 
            disabled={!isPaid}
            className="px-8 py-3 text-lg"
          >
            <Check size={20} /> Finalizar Venda
          </Button>
        </>
      }
    >
      <div className="space-y-6">
        {/* Placar de Valores */}
        <div className="grid grid-cols-2 gap-4">
          <div className="bg-gray-100 dark:bg-gray-700/50 p-4 rounded-xl border-b-4 border-theme-primary">
            <p className="text-xs font-bold text-gray-500 uppercase">Total da Venda</p>
            <p className="text-3xl font-black text-theme-primary">{formatCurrency(totalAmount)}</p>
          </div>

          {change > 0 ? (
            <div className="bg-blue-50 dark:bg-blue-900/30 p-4 rounded-xl border-b-4 border-blue-500 animate-pulse">
              <p className="text-xs font-bold text-blue-700 dark:text-blue-300 uppercase">Troco a Devolver</p>
              <p className="text-3xl font-black text-blue-700 dark:text-blue-300">{formatCurrency(change)}</p>
            </div>
          ) : (
            <div className={`p-4 rounded-xl border-b-4 transition-colors ${isPaid ? 'bg-green-50 border-green-500' : 'bg-red-50 border-red-500'} dark:bg-gray-800`}>
              <p className="text-xs font-bold text-gray-500 uppercase">{isPaid ? 'Total Recebido' : 'Faltando'}</p>
              <p className={`text-3xl font-black ${isPaid ? 'text-green-600' : 'text-red-600'}`}>
                {isPaid ? formatCurrency(totalReceived) : formatCurrency(remaining)}
              </p>
            </div>
          )}
        </div>

        {/* Grade de Métodos de Pagamento */}
        <div className="space-y-3">
          <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider px-1">Formas de Recebimento</h3>
          <div className="grid grid-cols-1 gap-2">
            {Object.values(PaymentMethod).map((method) => (
              <div 
                key={method} 
                className="flex items-center gap-3 p-3 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg hover:border-theme-primary transition-colors group"
              >
                <div className="flex items-center gap-3 w-32 shrink-0">
                  {getMethodIcon(method)}
                  <span className="font-bold text-sm text-gray-700 dark:text-gray-300">{method}</span>
                </div>

                <div className="relative flex-grow">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 font-mono text-sm">R$</span>
                  <input
                    type="text"
                    value={methodValues[method]}
                    onChange={(e) => handleValueChange(method, e.target.value)}
                    placeholder="0,00"
                    className="w-full pl-9 pr-3 py-2 bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-md text-right font-mono text-lg focus:ring-2 focus:ring-theme-primary outline-none transition-all"
                  />
                </div>

                <div className="flex gap-1 shrink-0">
                   <button 
                    onClick={() => fillRemaining(method)}
                    title="Preencher restante"
                    className="px-3 py-2 bg-theme-primary/10 text-theme-primary hover:bg-theme-primary hover:text-white rounded-md text-xs font-bold transition-colors"
                  >
                    TOTAL
                  </button>
                  <button 
                    onClick={() => clearMethod(method)}
                    className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-md transition-colors"
                  >
                    <ArrowRight size={16} className="rotate-180" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Atalhos Rápidos para Dinheiro */}
        <div className="flex gap-2 items-center pt-2">
            <span className="text-[10px] font-bold text-gray-400 uppercase whitespace-nowrap">Atalhos Dinheiro:</span>
            {[10, 20, 50, 100].map(val => (
                <button
                    key={val}
                    onClick={() => {
                        const current = parseFloat(methodValues[PaymentMethod.DINHEIRO].replace(',', '.')) || 0;
                        setMethodValues(prev => ({...prev, [PaymentMethod.DINHEIRO]: (current + val).toFixed(2).replace('.', ',')}));
                    }}
                    className="px-2 py-1 bg-gray-200 dark:bg-gray-700 rounded text-xs font-bold hover:bg-theme-primary hover:text-white transition-colors"
                >
                    +{val}
                </button>
            ))}
        </div>
      </div>
    </Modal>
  );
};

export default PaymentModal;

