import React, { useState, useEffect, useMemo } from 'react';
import Modal from '../shared/Modal';
import Button from '../shared/Button';
import { PaymentMethod } from '../../types';
import type { Payment } from '../../types';
import { DollarSign, Smartphone, CreditCard, User, Check, ArrowRight, Wallet } from 'lucide-react';

interface PaymentModalProps {
  isOpen: boolean;
  onClose: () => void;
  totalAmount: number;
  onFinalize: (payments: Payment[], change: number) => void;
}

const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

const PaymentModal: React.FC<PaymentModalProps> = ({ isOpen, onClose, totalAmount, onFinalize }) => {
  // Estado para armazenar os valores de cada método como string para facilitar a digitação
  const [methodValues, setMethodValues] = useState<Record<PaymentMethod, string>>({
    [PaymentMethod.DINHEIRO]: '',
    [PaymentMethod.PIX]: '',
    [PaymentMethod.DEBITO]: '',
    [PaymentMethod.CREDITO]: '',
    [PaymentMethod.NOTINHA]: '',
  });

  // Reseta ao abrir
  useEffect(() => {
    if (isOpen) {
      setMethodValues({
        [PaymentMethod.DINHEIRO]: '',
        [PaymentMethod.PIX]: '',
        [PaymentMethod.DEBITO]: '',
        [PaymentMethod.CREDITO]: '',
        [PaymentMethod.NOTINHA]: '',
      });
    }
  }, [isOpen]);

  // Converte as strings para números e calcula o total recebido
  const totalReceived = useMemo(() => {
    return Object.values(methodValues).reduce((sum, val) => {
      const num = parseFloat(val.replace(',', '.')) || 0;
      return sum + num;
    }, 0);
  }, [methodValues]);

  const remaining = Math.max(0, totalAmount - totalReceived);
  const change = Math.max(0, totalReceived - totalAmount);
  const isPaid = totalReceived >= totalAmount - 0.001; // Tolerância para float

  const handleValueChange = (method: PaymentMethod, value: string) => {
    // Permite apenas números, vírgula e ponto
    if (/^[0-9.,]*$/.test(value)) {
      setMethodValues(prev => ({ ...prev, [method]: value }));
    }
  };

  const fillRemaining = (method: PaymentMethod) => {
    if (remaining > 0) {
      const currentVal = parseFloat(methodValues[method].replace(',', '.')) || 0;
      const newVal = (currentVal + remaining).toFixed(2).replace('.', ',');
      setMethodValues(prev => ({ ...prev, [method]: newVal }));
    }
  };

  const clearMethod = (method: PaymentMethod) => {
    setMethodValues(prev => ({ ...prev, [method]: '' }));
  };

  const handleFinalize = () => {
    if (!isPaid) return;

    // Converte o objeto de valores para o array de pagamentos esperado pela API
    const payments: Payment[] = Object.entries(methodValues)
      .map(([method, value]) => ({
        method: method as PaymentMethod,
        amount: parseFloat(value.replace(',', '.')) || 0
      }))
      .filter(p => p.amount > 0);

    onFinalize(payments, change);
  };

  const getMethodIcon = (method: PaymentMethod) => {
    switch (method) {
      case PaymentMethod.DINHEIRO: return <Wallet size={20} className="text-green-600" />;
      case PaymentMethod.PIX: return <Smartphone size={20} className="text-theme-green" />;
      case PaymentMethod.DEBITO: return <CreditCard size={20} className="text-theme-darkblue" />;
      case PaymentMethod.CREDITO: return <CreditCard size={20} className="text-theme-secondary" />;
      case PaymentMethod.NOTINHA: return <User size={20} className="text-red-500" />;
      default: return <DollarSign size={20} />;
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Finalizar Pagamento"
      footer={
        <>
          <Button variant="secondary" onClick={onClose}>Cancelar</Button>
          <Button 
            variant="success" 
            onClick={handleFinalize} 
            disabled={!isPaid}
            className="px-8 py-3 text-lg"
          >
            <Check size={20} /> Finalizar Venda
          </Button>
        </>
      }
    >
      <div className="space-y-6">
        {/* Placar de Valores */}
        <div className="grid grid-cols-2 gap-4">
          <div className="bg-gray-100 dark:bg-gray-700/50 p-4 rounded-xl border-b-4 border-theme-primary">
            <p className="text-xs font-bold text-gray-500 uppercase">Total da Venda</p>
            <p className="text-3xl font-black text-theme-primary">{formatCurrency(totalAmount)}</p>
          </div>

          {change > 0 ? (
            <div className="bg-blue-50 dark:bg-blue-900/30 p-4 rounded-xl border-b-4 border-blue-500 animate-pulse">
              <p className="text-xs font-bold text-blue-700 dark:text-blue-300 uppercase">Troco a Devolver</p>
              <p className="text-3xl font-black text-blue-700 dark:text-blue-300">{formatCurrency(change)}</p>
            </div>
          ) : (
            <div className={`p-4 rounded-xl border-b-4 transition-colors ${isPaid ? 'bg-green-50 border-green-500' : 'bg-red-50 border-red-500'} dark:bg-gray-800`}>
              <p className="text-xs font-bold text-gray-500 uppercase">{isPaid ? 'Total Recebido' : 'Faltando'}</p>
              <p className={`text-3xl font-black ${isPaid ? 'text-green-600' : 'text-red-600'}`}>
                {isPaid ? formatCurrency(totalReceived) : formatCurrency(remaining)}
              </p>
            </div>
          )}
        </div>

        {/* Grade de Métodos de Pagamento */}
        <div className="space-y-3">
          <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider px-1">Formas de Recebimento</h3>
          <div className="grid grid-cols-1 gap-2">
            {Object.values(PaymentMethod).map((method) => (
              <div 
                key={method} 
                className="flex items-center gap-3 p-3 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg hover:border-theme-primary transition-colors group"
              >
                <div className="flex items-center gap-3 w-32 shrink-0">
                  {getMethodIcon(method)}
                  <span className="font-bold text-sm text-gray-700 dark:text-gray-300">{method}</span>
                </div>

                <div className="relative flex-grow">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 font-mono text-sm">R$</span>
                  <input
                    type="text"
                    value={methodValues[method]}
                    onChange={(e) => handleValueChange(method, e.target.value)}
                    placeholder="0,00"
                    className="w-full pl-9 pr-3 py-2 bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-md text-right font-mono text-lg focus:ring-2 focus:ring-theme-primary outline-none transition-all"
                  />
                </div>

                <div className="flex gap-1 shrink-0">
                   <button 
                    onClick={() => fillRemaining(method)}
                    title="Preencher restante"
                    className="px-3 py-2 bg-theme-primary/10 text-theme-primary hover:bg-theme-primary hover:text-white rounded-md text-xs font-bold transition-colors"
                  >
                    TOTAL
                  </button>
                  <button 
                    onClick={() => clearMethod(method)}
                    className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-md transition-colors"
                  >
                    <ArrowRight size={16} className="rotate-180" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Atalhos Rápidos para Dinheiro */}
        <div className="flex gap-2 items-center pt-2">
            <span className="text-[10px] font-bold text-gray-400 uppercase whitespace-nowrap">Atalhos Dinheiro:</span>
            {[10, 20, 50, 100].map(val => (
                <button
                    key={val}
                    onClick={() => {
                        const current = parseFloat(methodValues[PaymentMethod.DINHEIRO].replace(',', '.')) || 0;
                        setMethodValues(prev => ({...prev, [PaymentMethod.DINHEIRO]: (current + val).toFixed(2).replace('.', ',')}));
                    }}
                    className="px-2 py-1 bg-gray-200 dark:bg-gray-700 rounded text-xs font-bold hover:bg-theme-primary hover:text-white transition-colors"
                >
                    +{val}
                </button>
            ))}
        </div>
      </div>
    </Modal>
  );
};

export default PaymentModal;

import React, { useMemo } from 'react';
import type { CashSession, Payment, Sale } from '../../types';
import { PaymentMethod } from '../../types';
import Button from '../shared/Button';
import { BarChart, Bar, XAxis, YAxis, Tooltip, Legend, ResponsiveContainer, Cell } from 'recharts';

interface CloseCashScreenProps {
  session: CashSession;
  onClose: () => void;
}

// Cores para o gráfico, alinhadas com a identidade visual.
const COLORS = {
  [PaymentMethod.DINHEIRO]: '#E87722', // theme-secondary (Orange)
  [PaymentMethod.PIX]: '#9FCB3B',      // theme-green (Light Green)
  [PaymentMethod.DEBITO]: '#1E3A63',   // theme-darkblue (Navy Blue)
  [PaymentMethod.CREDITO]: '#F9B208', // theme-yellow (Mustard Yellow)
  [PaymentMethod.NOTINHA]: '#ef4444',     // Red
};


// Componente para a tela de Fechamento de Caixa.
// Apresenta um resumo completo do turno do operador.
const CloseCashScreen: React.FC<CloseCashScreenProps> = ({ session, onClose }) => {

  // useMemo é usado para calcular os totais apenas quando a sessão mudar.
  // Isso otimiza a performance, evitando recálculos a cada renderização.
  const summary = useMemo(() => {
    // Inicializa um mapa para armazenar o total de cada método de pagamento.
    const paymentsByMethod = new Map<PaymentMethod, number>();
    Object.values(PaymentMethod).forEach(method => paymentsByMethod.set(method, 0));

    // Itera sobre todas as vendas da sessão para somar os pagamentos.
    session.sales.forEach((sale: Sale) => {
      sale.payments.forEach((payment: Payment) => {
        const currentTotal = paymentsByMethod.get(payment.method) || 0;
        paymentsByMethod.set(payment.method, currentTotal + payment.amount);
      });
    });

    // Calcula os totais de sangrias e reforços.
    const totalSuprimento = session.transactions.filter(t => t.type === 'SUPRIMENTO' || t.type === 'REFORCO').reduce((sum, t) => sum + t.amount, 0);
    const totalSangria = session.transactions.filter(t => t.type === 'SANGRIA').reduce((sum, t) => sum + t.amount, 0);

    // Calcula o valor total de vendas.
    const totalSales = session.sales.reduce((sum, sale) => sum + sale.totalAmount, 0);

    // Calcula o valor esperado em dinheiro no caixa.
    const expectedCash = (paymentsByMethod.get(PaymentMethod.DINHEIRO) || 0) + totalSuprimento - totalSangria;

    // Formata os dados para o gráfico.
    const chartData = Array.from(paymentsByMethod.entries()).map(([name, value]) => ({ name, value }));

    return { paymentsByMethod, totalSuprimento, totalSangria, totalSales, expectedCash, chartData };
  }, [session]);

  const formatCurrency = (value: number) => {
    return value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-100 dark:bg-gray-900 p-4">
      <div className="w-full max-w-4xl bg-white dark:bg-gray-800 rounded-lg shadow-xl p-8">
        <h1 className="text-3xl font-bold text-center mb-6 text-gray-800 dark:text-gray-100">Fechamento de Caixa</h1>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">

          {/* Coluna de Resumo Financeiro */}
          <div className="space-y-4">
            <h2 className="text-xl font-semibold border-b pb-2 dark:border-gray-600">Resumo Financeiro</h2>

            <div className="p-4 bg-gray-50 dark:bg-gray-700 rounded-lg">
              <h3 className="font-bold mb-2">Vendas por Método de Pagamento</h3>
              <ul className="space-y-1">
                {Array.from(summary.paymentsByMethod.entries()).map(([method, total]) => (
                  <li key={method} className="flex justify-between">
                    <span>{method}:</span>
                    <span className="font-mono">{formatCurrency(total)}</span>
                  </li>
                ))}
              </ul>
              <hr className="my-2 border-gray-200 dark:border-gray-600"/>
              <div className="flex justify-between font-bold text-lg">
                <span>Total de Vendas:</span>
                <span className="font-mono">{formatCurrency(summary.totalSales)}</span>
              </div>
            </div>

            <div className="p-4 bg-gray-50 dark:bg-gray-700 rounded-lg">
              <h3 className="font-bold mb-2">Movimentações de Caixa</h3>
               <ul className="space-y-1">
                 <li className="flex justify-between text-green-600 dark:text-green-400">
                    <span>(+) Suprimentos / Reforços:</span>
                    <span className="font-mono">{formatCurrency(summary.totalSuprimento)}</span>
                 </li>
                 <li className="flex justify-between text-red-600 dark:text-red-400">
                    <span>(-) Sangrias:</span>
                    <span className="font-mono">{formatCurrency(summary.totalSangria)}</span>
                 </li>
               </ul>
            </div>

            <div className="p-4 bg-theme-primary/10 dark:bg-theme-primary/20 rounded-lg text-theme-primary dark:text-theme-primary/90">
              <div className="flex justify-between font-bold text-xl">
                <span>Valor Esperado em Caixa:</span>
                <span className="font-mono">{formatCurrency(summary.expectedCash)}</span>
              </div>
              <p className="text-sm mt-1">Total em Dinheiro + Suprimentos - Sangrias</p>
            </div>
          </div>

          {/* Coluna do Gráfico */}
          <div className="flex flex-col">
            <h2 className="text-xl font-semibold border-b pb-2 dark:border-gray-600 mb-4">Visualização das Vendas</h2>
            <div className="flex-grow min-h-[300px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={summary.chartData} margin={{ top: 5, right: 20, left: -10, bottom: 5 }}>
                  <XAxis dataKey="name" stroke="#9ca3af" fontSize={12} tickLine={false} axisLine={false} />
                  <YAxis stroke="#9ca3af" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(value: number) => `R$${value}`} />
                  <Tooltip
                    contentStyle={{ backgroundColor: '#1f2937', border: 'none', borderRadius: '0.5rem' }}
                    labelStyle={{ color: '#d1d5db' }}
                    itemStyle={{ fontWeight: 'bold' }}
                    formatter={(value: number) => formatCurrency(value)}
                  />
                  <Legend wrapperStyle={{fontSize: "14px"}}/>
                  <Bar dataKey="value" name="Total" radius={[4, 4, 0, 0]}>
                    {summary.chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[entry.name as PaymentMethod]} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

        </div>

        {/* Botões de Ação */}
        <div className="mt-8 flex justify-center gap-4">
          <Button onClick={() => window.location.reload()} variant="secondary">Voltar ao PDV</Button>
          <Button onClick={onClose} variant="primary">Confirmar e Fechar Caixa</Button>
        </div>
      </div>
    </div>
  );
};

export default CloseCashScreen;

