import React, { useState, useEffect, useCallback, useRef } from 'react';
import { db } from '../../services/databaseService';
import type { Customer } from '../../types';
import Button from '../shared/Button';
import { PlusCircle, Edit, Trash2, Search, Download, Upload, FileText } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface CustomerManagementProps {
    onNewCustomer: () => void;
    onEditCustomer: (customerId: string) => void;
}

const CustomerManagement: React.FC<CustomerManagementProps> = ({ onNewCustomer, onEditCustomer }) => {
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const fileInputRef = useRef<HTMLInputElement>(null);

    const fetchCustomers = useCallback(async () => {
        const allCustomers = await db.getAll('customers');
        setCustomers(allCustomers.sort((a,b) => a.name.localeCompare(b.name)));
    }, []);

    useEffect(() => {
        fetchCustomers();
    }, [fetchCustomers]);

    const handleDelete = async (id: string) => {
        if (confirm('Tem certeza que deseja excluir este cliente?')) {
            await db.delete('customers', id);
            fetchCustomers();
        }
    };

    // --- IMPORTAR CSV ---
    const handleImportCSV = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = async (event) => {
            const text = event.target?.result as string;
            const rows = text.split('\n');
            const headers = rows[0].split(',').map(h => h.trim().toLowerCase());

            const importedCustomers: Customer[] = [];

            // Pula o cabeçalho
            for (let i = 1; i < rows.length; i++) {
                if (!rows[i].trim()) continue;
                const columns = rows[i].split(',');

                const getVal = (headerName: string) => {
                    const idx = headers.indexOf(headerName);
                    return idx > -1 ? columns[idx]?.trim() : '';
                };

                const cpf = getVal('cpf');
                if (!cpf) continue; // CPF é chave primária lógica

                importedCustomers.push({
                    id: uuidv4(),
                    name: getVal('nome') || getVal('name') || 'Sem Nome',
                    cpf: cpf,
                    phone: getVal('telefone') || getVal('phone'),
                    cellphone: getVal('celular') || getVal('cellphone'),
                    email: getVal('email'),
                    address: getVal('endereco') || getVal('address'),
                    socialMedia: getVal('social') || getVal('instagram'),
                    observations: getVal('obs') || getVal('observacoes'),
                });
            }

            if (importedCustomers.length > 0) {
                const tx = db.transaction('customers', 'readwrite');
                for (const c of importedCustomers) {
                    await tx.store.put(c);
                }
                await tx.done;
                alert(`${importedCustomers.length} clientes importados com sucesso!`);
                fetchCustomers();
            }
        };
        reader.readAsText(file);
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    // --- EXPORTAR CSV ---
    const handleExportCSV = () => {
        if (customers.length === 0) return alert('Não há clientes para exportar.');

        const headers = ['Nome', 'CPF', 'Telefone', 'Celular', 'Email', 'Endereco', 'RedesSociais', 'Observacoes'];
        const csvRows = [headers.join(',')];

        customers.forEach(c => {
            const row = [
                `"${c.name}"`,
                `"${c.cpf}"`,
                `"${c.phone || ''}"`,
                `"${c.cellphone || ''}"`,
                `"${c.email || ''}"`,
                `"${c.address || ''}"`,
                `"${c.socialMedia || ''}"`,
                `"${c.observations || ''}"`
            ];
            csvRows.push(row.join(','));
        });

        const csvContent = csvRows.join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.setAttribute('href', url);
        link.setAttribute('download', `clientes_busenatural_${new Date().toISOString().split('T')[0]}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const filteredCustomers = customers.filter(c =>
        c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        c.cpf.includes(searchTerm)
    );

    return (
        <div className="space-y-4">
            <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 bg-white dark:bg-gray-800 p-4 rounded-lg shadow-sm">
                <div className="relative w-full max-w-sm">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20}/>
                    <input
                        type="text"
                        placeholder="Buscar por nome ou CPF..."
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600"
                    />
                </div>

                <div className="flex flex-wrap gap-2 w-full lg:w-auto">
                    <input type="file" accept=".csv" ref={fileInputRef} onChange={handleImportCSV} className="hidden" />
                    <Button variant="secondary" onClick={() => fileInputRef.current?.click()}>
                        <Upload size={18}/> Importar CSV
                    </Button>
                    <Button variant="secondary" onClick={handleExportCSV}>
                        <Download size={18}/> Exportar CSV
                    </Button>
                    <Button onClick={onNewCustomer}>
                        <PlusCircle size={18}/> Novo Cliente
                    </Button>
                </div>
            </div>

            <div className="overflow-x-auto bg-white dark:bg-gray-800 rounded-lg shadow">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 dark:bg-gray-700 dark:text-gray-400">
                        <tr>
                            <th className="px-6 py-3">Nome</th>
                            <th className="px-6 py-3">CPF</th>
                            <th className="px-6 py-3">Celular/Whats</th>
                            <th className="px-6 py-3">Redes Sociais</th>
                            <th className="px-6 py-3 text-center">Ações</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredCustomers.map(customer => (
                            <tr key={customer.id} className="border-b dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600/20">
                                <td className="px-6 py-3 font-medium">
                                    {customer.name}
                                    {customer.observations && <FileText size={12} className="inline ml-2 text-theme-primary" title="Possui observações" />}
                                </td>
                                <td className="px-6 py-3 font-mono">{customer.cpf}</td>
                                <td className="px-6 py-3">{customer.cellphone || customer.phone || '-'}</td>
                                <td className="px-6 py-3 text-theme-primary font-medium">{customer.socialMedia || '-'}</td>
                                <td className="px-6 py-3 text-center">
                                    <div className="flex justify-center gap-2">
                                        <Button variant="secondary" className="p-2 h-auto" onClick={() => onEditCustomer(customer.id)} title="Editar"><Edit size={16}/></Button>
                                        <Button variant="danger" className="p-2 h-auto" onClick={() => handleDelete(customer.id)} title="Excluir"><Trash2 size={16}/></Button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {filteredCustomers.length === 0 && (
                    <div className="text-center p-12 text-gray-400">
                        <Users size={48} className="mx-auto mb-2 opacity-20" />
                        Nenhum cliente encontrado.
                    </div>
                )}
            </div>
        </div>
    );
};

