import React, { useState, useEffect } from 'react';
import { db } from '../../services/databaseService';
import type { Customer } from '../../types';
import Button from '../shared/Button';
import { Save, User, Phone, MapPin, Instagram, FileText } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface CustomerFormPageProps {
  customerId?: string;
  onBack: () => void;
}

const CustomerFormPage: React.FC<CustomerFormPageProps> = ({ customerId, onBack }) => {
    const [formData, setFormData] = useState<Partial<Customer>>({});
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            if (customerId) {
                const customer = await db.get('customers', customerId);
                if (customer) {
                    setFormData(customer);
                } else {
                    console.error("Customer not found");
                    onBack();
                }
            } else {
                setFormData({
                    id: uuidv4(),
                    name: '',
                    cpf: '',
                    phone: '',
                    cellphone: '',
                    email: '',
                    address: '',
                    socialMedia: '',
                    observations: '',
                    creditLimit: 0,
                });
            }
            setIsLoading(false);
        };
        fetchData();
    }, [customerId, onBack]);


    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value, type } = e.target;
        setFormData(prev => ({ ...prev, [name]: type === 'number' ? parseFloat(value) : value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name || !formData.cpf) {
            alert('Nome e CPF são obrigatórios.');
            return;
        }
        await db.put('customers', formData as Customer);
        onBack();
    };

    if (isLoading) {
        return <div className="text-center p-8">Carregando dados do cliente...</div>;
    }

    const inputStyle = "mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-theme-primary focus:ring-theme-primary dark:border-gray-600 dark:bg-gray-700 p-2 border";

    return (
        <div className="max-w-4xl mx-auto space-y-6">
            <form onSubmit={handleSubmit} className="space-y-6">
                {/* BLOCO 1: IDENTIFICAÇÃO */}
                <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow-sm border border-gray-100 dark:border-gray-700">
                    <div className="flex items-center gap-2 mb-4 text-theme-primary border-b pb-2">
                        <User size={20} />
                        <h3 className="font-bold">Identificação Básica</h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="md:col-span-1">
                            <label className="block text-sm font-medium">Nome Completo</label>
                            <input type="text" name="name" value={formData.name} onChange={handleChange} required className={inputStyle} />
                        </div>
                        <div>
                            <label className="block text-sm font-medium">CPF (Obrigatório)</label>
                            <input type="text" name="cpf" value={formData.cpf} onChange={handleChange} required className={inputStyle} placeholder="000.000.000-00" />
                        </div>
                    </div>
                </div>

                {/* BLOCO 2: CONTATO E REDES SOCIAIS */}
                <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow-sm border border-gray-100 dark:border-gray-700">
                    <div className="flex items-center gap-2 mb-4 text-theme-primary border-b pb-2">
                        <Phone size={20} />
                        <h3 className="font-bold">Contato e Social</h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div>
                            <label className="block text-sm font-medium">Celular / WhatsApp</label>
                            <input type="text" name="cellphone" value={formData.cellphone || ''} onChange={handleChange} className={inputStyle} placeholder="(00) 99999-9999" />
                        </div>
                        <div>
                            <label className="block text-sm font-medium">Telefone Fixo</label>
                            <input type="text" name="phone" value={formData.phone || ''} onChange={handleChange} className={inputStyle} placeholder="(00) 3333-3333" />
                        </div>
                        <div>
                            <label className="block text-sm font-medium">E-mail</label>
                            <input type="email" name="email" value={formData.email || ''} onChange={handleChange} className={inputStyle} placeholder="cliente@email.com" />
                        </div>
                        <div className="md:col-span-3">
                            <label className="block text-sm font-medium flex items-center gap-2">
                                <Instagram size={14} /> Redes Sociais (Instagram/TikTok/LinkedIn)
                            </label>
                            <input type="text" name="socialMedia" value={formData.socialMedia || ''} onChange={handleChange} className={inputStyle} placeholder="@usuario ou link do perfil" />
                        </div>
                    </div>
                </div>

                {/* BLOCO 3: LOCALIZAÇÃO E NOTAS */}
                <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow-sm border border-gray-100 dark:border-gray-700">
                    <div className="flex items-center gap-2 mb-4 text-theme-primary border-b pb-2">
                        <MapPin size={20} />
                        <h3 className="font-bold">Localização e Observações</h3>
                    </div>
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium">Endereço Completo</label>
                            <input type="text" name="address" value={formData.address || ''} onChange={handleChange} className={inputStyle} placeholder="Rua, Número, Bairro, Cidade - UF" />
                        </div>
                        <div>
                            <label className="block text-sm font-medium flex items-center gap-2">
                                <FileText size={14} /> Observações Internas
                            </label>
                            <textarea 
                                name="observations" 
                                value={formData.observations || ''} 
                                onChange={handleChange} 
                                rows={4} 
                                className={`${inputStyle} resize-none`}
                                placeholder="Preferências do cliente, restrições alimentares, histórico relevante..."
                            ></textarea>
                        </div>
                    </div>
                </div>

                <div className="flex justify-end gap-2 pt-4 border-t dark:border-gray-700">
                    <Button type="button" variant="secondary" onClick={onBack}>Cancelar</Button>
                    <Button type="submit" variant="primary">
                        <Save size={16} className="mr-2" /> Salvar Cliente
                    </Button>
                </div>
            </form>
        </div>
    );
}

