      if (!database.objectStoreNames.contains('automationRules')) {
        const autoStore = database.createObjectStore('automationRules', { keyPath: 'id' });
        autoStore.createIndex('trigger', 'trigger');
        autoStore.createIndex('isActive', 'isActive');
      }

