const HRManagement: React.FC = () => {
    const [employees, setEmployees] = useState<Employee[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Partial<Employee> | null>(null);
    const [expandedInfo, setExpandedInfo] = useState<string | null>(null);

    const fetchEmployees = useCallback(async () => {
        const allEmployees = await db.getAll('employees');
        setEmployees(allEmployees.sort((a, b) => a.name.localeCompare(b.name)));
    }, []);

    useEffect(() => {
        fetchEmployees();
    }, [fetchEmployees]);

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!editingEmployee?.name || !editingEmployee?.roleId || editingEmployee?.salary === undefined) {
            alert('Preencha todos os campos obrigatórios.');
            return;
        }

        const employeeData: Employee = {
            id: editingEmployee.id || uuidv4(),
            name: editingEmployee.name,
            roleId: editingEmployee.roleId,
            salary: editingEmployee.salary,
            status: editingEmployee.status || 'ACTIVE',
            hireDate: editingEmployee.hireDate || new Date(),
            contractEndDate: editingEmployee.contractEndDate,
            lastVacationDate: editingEmployee.lastVacationDate,
        };

        await db.put('employees', employeeData);
        setIsModalOpen(false);
        setEditingEmployee(null);
        fetchEmployees();
    };

    const handleDelete = async (id: string) => {
        if (confirm('Deseja realmente remover este funcionário?')) {
            await db.delete('employees', id);
            fetchEmployees();
        }
    };

    const toggleStatus = async (employee: Employee) => {
        const updated = { ...employee, status: employee.status === 'ACTIVE' ? 'INACTIVE' : 'ACTIVE' };
        await db.put('employees', updated as Employee);
        fetchEmployees();
    };

    // Lógica CLT: Férias vencem 1 ano após admissão (ou últimas férias). Aviso com 11 meses.
    const getVacationStatus = (emp: Employee) => {
        const baseDate = emp.lastVacationDate ? new Date(emp.lastVacationDate) : new Date(emp.hireDate);
        const today = new Date();

        // Calcula diferença em meses
        const months = (today.getFullYear() - baseDate.getFullYear()) * 12 + (today.getMonth() - baseDate.getMonth());

        if (months >= 11) {
            return { 
                alert: true, 
                msg: months >= 12 ? 'Férias Vencidas!' : 'Férias a vencer (11 meses)', 
                months 
            };
        }
        return { alert: false, months };
    };

    const formatCurrency = (val: number) => val.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-black text-gray-800 dark:text-gray-100 uppercase tracking-tight">Gestão de Equipe</h2>
                    <p className="text-xs text-gray-500 font-bold uppercase tracking-widest">Manual de Cargos e Controle CLT</p>
                </div>
                <Button onClick={() => { setEditingEmployee({ hireDate: new Date() }); setIsModalOpen(true); }}>
                    <PlusCircle size={18}/> Novo Funcionário
                </Button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                {employees.map(emp => {
                    const role = ROLE_DEFINITIONS.find(r => r.id === emp.roleId);
                    const vacation = getVacationStatus(emp);
                    const isExpanded = expandedInfo === emp.id;

                    return (
                        <div key={emp.id} className={`bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border-2 transition-all ${emp.status === 'ACTIVE' ? 'border-transparent' : 'border-gray-200 opacity-60'}`}>
                            <div className="flex justify-between items-start mb-4">
                                <div className="flex items-center gap-3">
                                    <div className={`p-3 rounded-full ${role?.level === 'ESTRATEGICO' ? 'bg-purple-100 text-purple-600' : role?.level === 'TATICO' ? 'bg-blue-100 text-blue-600' : 'bg-theme-primary/10 text-theme-primary'}`}>
                                        <UserCog size={24} />
                                    </div>
                                    <div>
                                        <h3 className="font-black text-gray-800 dark:text-gray-100 uppercase text-sm leading-tight">{emp.name}</h3>
                                        <div className="flex items-center gap-2">
                                            <p className="text-[10px] font-black text-gray-400 uppercase tracking-tighter">{role?.title || 'Cargo não definido'}</p>
                                            <span className="text-[8px] px-1 bg-gray-100 dark:bg-gray-700 rounded text-gray-500 font-bold">{role?.level}</span>
                                        </div>
                                    </div>
                                </div>
                                <div className="flex flex-col items-end gap-1">
                                    <span className={`text-[10px] font-black px-2 py-1 rounded-full uppercase ${emp.status === 'ACTIVE' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                                        {emp.status === 'ACTIVE' ? 'Ativo' : 'Inativo'}
                                    </span>
                                    {vacation.alert && (
                                        <span className={`flex items-center gap-1 text-[9px] font-black px-2 py-0.5 rounded-full uppercase animate-pulse ${vacation.months >= 12 ? 'bg-red-500 text-white' : 'bg-orange-500 text-white'}`}>
                                            <AlertTriangle size={10} /> {vacation.msg}
                                        </span>
                                    )}
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4 mb-4 bg-gray-50 dark:bg-gray-900/50 p-3 rounded-xl">
                                <div>
                                    <p className="text-[9px] font-black text-gray-400 uppercase">Salário Base</p>
                                    <p className="font-mono font-bold text-theme-primary text-sm">{formatCurrency(emp.salary)}</p>
                                </div>
                                <div>
                                    <p className="text-[9px] font-black text-gray-400 uppercase">Admissão</p>
                                    <p className="text-xs font-bold text-gray-600 dark:text-gray-400">{new Date(emp.hireDate).toLocaleDateString('pt-BR')}</p>
                                </div>
                                {emp.contractEndDate && (
                                    <div>
                                        <p className="text-[9px] font-black text-gray-400 uppercase">Término Contrato</p>
                                        <p className="text-xs font-bold text-orange-600">{new Date(emp.contractEndDate).toLocaleDateString('pt-BR')}</p>
                                    </div>
                                )}
                                <div>
                                    <p className="text-[9px] font-black text-gray-400 uppercase">Período Aquisitivo</p>
                                    <p className="text-xs font-bold text-gray-600 dark:text-gray-400">{vacation.months} meses trab.</p>
                                </div>
                            </div>

                            {/* Detalhes do Cargo Expandíveis */}
                            <div className="mb-4">
                                <button 
                                    onClick={() => setExpandedInfo(isExpanded ? null : emp.id)}
                                    className="flex items-center gap-1 text-[10px] font-black text-theme-primary uppercase hover:underline"
                                >
                                    {isExpanded ? <ChevronUp size={14}/> : <ChevronDown size={14}/>} 
                                    {isExpanded ? 'Ocultar Responsabilidades' : 'Ver Missão e Funções'}
                                </button>
                                {isExpanded && role && (
                                    <div className="mt-2 p-3 border-l-2 border-theme-primary bg-theme-primary/5 rounded-r-lg space-y-2 animate-in fade-in slide-in-from-top-1">
                                        <p className="text-[10px] text-gray-600 dark:text-gray-400 italic">" {role.mission} "</p>
                                        <ul className="grid grid-cols-1 md:grid-cols-2 gap-1">
                                            {role.functions.map((f, i) => (
                                                <li key={i} className="text-[10px] font-bold text-gray-500 flex items-center gap-1 uppercase">
                                                    <BadgeCheck size={10} className="text-theme-primary" /> {f}
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                )}
                            </div>

                            <div className="flex gap-2 pt-4 border-t dark:border-gray-700">
                                <Button variant="secondary" className="flex-1 !p-2 h-auto" onClick={() => { setEditingEmployee(emp); setIsModalOpen(true); }}>
                                    <Edit size={16}/>
                                </Button>
                                <button 
                                    onClick={() => toggleStatus(emp)}
                                    title={emp.status === 'ACTIVE' ? 'Desativar' : 'Ativar'}
                                    className={`flex-1 flex items-center justify-center p-2 rounded-lg transition-colors ${emp.status === 'ACTIVE' ? 'bg-orange-50 text-orange-600 hover:bg-orange-100' : 'bg-green-50 text-green-600 hover:bg-green-100'}`}
                                >
                                    {emp.status === 'ACTIVE' ? <XCircle size={18}/> : <BadgeCheck size={18}/>}
                                </button>
                                <Button variant="danger" className="flex-1 !p-2 h-auto" onClick={() => handleDelete(emp.id)}>
                                    <Trash2 size={16}/>
                                </Button>
                            </div>
                        </div>
                    );
                })}
            </div>

            <Modal 
                isOpen={isModalOpen} 
                onClose={() => setIsModalOpen(false)} 
                title={editingEmployee?.id ? 'Editar Ficha do Colaborador' : 'Nova Contratação'}
            >
                <form onSubmit={handleSave} className="space-y-4 max-h-[70vh] overflow-y-auto px-1">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="md:col-span-2">
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Nome Completo</label>
                            <input 
                                type="text" 
                                value={editingEmployee?.name || ''} 
                                onChange={e => setEditingEmployee(p => ({...p!, name: e.target.value}))}
                                className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-theme-primary outline-none"
                                required
                            />
                        </div>
                        <div className="md:col-span-2">
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Cargo e Responsabilidades</label>
                            <select 
                                value={editingEmployee?.roleId || ''} 
                                onChange={e => setEditingEmployee(p => ({...p!, roleId: e.target.value}))}
                                className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-theme-primary outline-none"
                                required
                            >
                                <option value="">Selecione o cargo...</option>
                                {ROLE_DEFINITIONS.map(r => (
                                    <option key={r.id} value={r.id}>{r.title} ({r.level})</option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Salário Base (R$)</label>
                            <input 
                                type="number" 
                                step="0.01"
                                value={editingEmployee?.salary || ''} 
                                onChange={e => setEditingEmployee(p => ({...p!, salary: parseFloat(e.target.value)}))}
                                className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-theme-primary outline-none font-mono"
                                required
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Data de Admissão</label>
                            <input 
                                type="date" 
                                value={editingEmployee?.hireDate ? new Date(editingEmployee.hireDate).toISOString().split('T')[0] : ''} 
                                onChange={e => setEditingEmployee(p => ({...p!, hireDate: new Date(e.target.value)}))}
                                className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-theme-primary outline-none"
                                required
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Término de Contrato (Opcional)</label>
                            <input 
                                type="date" 
                                value={editingEmployee?.contractEndDate ? new Date(editingEmployee.contractEndDate).toISOString().split('T')[0] : ''} 
                                onChange={e => setEditingEmployee(p => ({...p!, contractEndDate: new Date(e.target.value)}))}
                                className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-theme-primary outline-none"
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Últimas Férias Gozadas</label>
                            <input 
                                type="date" 
                                value={editingEmployee?.lastVacationDate ? new Date(editingEmployee.lastVacationDate).toISOString().split('T')[0] : ''} 
                                onChange={e => setEditingEmployee(p => ({...p!, lastVacationDate: new Date(e.target.value)}))}
                                className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-theme-primary outline-none"
                            />
                        </div>
                    </div>
                    <div className="flex gap-2 pt-4">
                        <Button type="button" variant="secondary" className="flex-1" onClick={() => setIsModalOpen(false)}>Cancelar</Button>
                        <Button type="submit" variant="primary" className="flex-1">Salvar na Equipe</Button>
                    </div>
                </form>
            </Modal>
        </div>
    );
};

export default HRManagement;

import React, { useState, useEffect, useMemo } from 'react';
import { db } from '../../services/databaseService';
import type { Product, Category, Supplier, InventoryLot } from '../../types';
import Button from '../shared/Button';
import { ImageOff, ReceiptText, Save, History, TrendingUp, TrendingDown, Minus } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface ProductFormPageProps {
  productId?: string;
  categories: Category[];
  onBack: () => void;
}

const ProductFormPage: React.FC<ProductFormPageProps> = ({ productId, categories, onBack }) => {
    const [formData, setFormData] = useState<Partial<Product>>({});
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [purchaseHistory, setPurchaseHistory] = useState<InventoryLot[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [imageError, setImageError] = useState(false);
    const [activeTab, setActiveTab] = useState('main');

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            const allSuppliers = await db.getAll('suppliers');
            setSuppliers(allSuppliers.sort((a,b) => a.name.localeCompare(b.name)));

            if (productId) {
                const [product, lots] = await Promise.all([
                    db.get('products', productId),
                    db.getAllFromIndex('inventoryLots', 'productId', productId)
                ]);

                if (product) {
                    // Regra específica para o produto com ID '2'
                    const productData = { ...product };
                    if (productData.id === '2') {
                        productData.ncm = '12345678';
                    }
                    setFormData(productData);
                    // Ordena histórico: mais recentes primeiro
                    setPurchaseHistory(lots.sort((a, b) => b.entryDate.getTime() - a.entryDate.getTime()));
                } else {
                    console.error("Product not found");
                    onBack();
                }
            } else {
                setFormData({
                    id: uuidv4(),
                    name: '',
                    price: 0,
                    costPrice: 0,
                    stock: 0,
                    minStock: 0,
                    isBulk: false,
                    scaleCode: '',
                    ncm: '',
                    cfop: '5102',
                    origin: '0',
                    csosn_cst: '102',
                    image: '',
                    categoryId: '',
                    supplierId: '',
                });
            }
            setIsLoading(false);
        };
        fetchData();
    }, [productId, onBack]);

    const supplierMap = useMemo(() => new Map(suppliers.map(s => [s.id, s.name])), [suppliers]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;

        if (type === 'checkbox') {
            const { checked } = e.target as HTMLInputElement;
            setFormData(prev => ({ ...prev, [name]: checked }));
        } else {
             setFormData(prev => ({ ...prev, [name]: type === 'number' ? parseFloat(value) : value }));
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name || !formData.id || formData.price === undefined || formData.price < 0) {
            alert('Preencha os campos obrigatórios: ID, Nome e Preço de Venda.');
            return;
        }
        if (formData.isBulk && (!formData.scaleCode || formData.scaleCode.length !== 6)) {
            alert('Produtos a granel devem ter um "Código da Balança" de 6 dígitos.');
            return;
        }

        await db.put('products', formData as Product);
        onBack();
    };

    const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

    if (isLoading) {
        return <div className="text-center p-8">Carregando dados do produto...</div>;
    }

    const inputStyleClasses = "mt-1 block w-full rounded-md border border-gray-300 py-2 px-3 shadow-sm focus:border-theme-primary focus:ring-theme-primary dark:border-gray-600 dark:bg-gray-700";

    const TabButton: React.FC<{ tabId: string; icon?: React.ElementType; children: React.ReactNode }> = ({ tabId, icon: Icon, children }) => (
        <button
            type="button"
            onClick={() => setActiveTab(tabId)}
            className={`px-4 py-2 text-sm font-medium rounded-t-lg border-b-2 flex items-center gap-2 transition-colors ${activeTab === tabId ? 'border-theme-primary text-theme-primary bg-theme-primary/5' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300 dark:hover:border-gray-600'}`}
        >
            {Icon && <Icon size={16} />}
            {children}
        </button>
    );

    return (
         <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow">
            <div className="border-b border-gray-200 dark:border-gray-700 mb-6">
                <nav className="-mb-px flex space-x-2 overflow-x-auto" aria-label="Tabs">
                    <TabButton tabId="main">Dados Principais</TabButton>
                    <TabButton tabId="tax" icon={ReceiptText}>Tributação</TabButton>
                    {productId && <TabButton tabId="history" icon={History}>Histórico de Compras</TabButton>}
                </nav>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
                {/* Aba de Dados Principais */}
                <div className={activeTab === 'main' ? 'block' : 'hidden'}>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium">Nome do Produto</label>
                            <input type="text" name="name" value={formData.name} onChange={handleChange} required className={inputStyleClasses}/>
                        </div>
                        <div>
                            <label className="block text-sm font-medium">Código de Barras (ID)</label>
                            <input type="text" name="id" value={formData.id} required className={`${inputStyleClasses} bg-gray-100 dark:bg-gray-800 cursor-not-allowed`} readOnly/>
                        </div>
                        <div>
                            <label className="block text-sm font-medium">Preço de Venda (R$)</label>
                            <input type="number" name="price" value={formData.price} onChange={handleChange} required min="0" step="0.01" className={inputStyleClasses}/>
                        </div>
                        <div>
                            <label className="block text-sm font-medium">Preço de Custo Médio (R$)</label>
                            <input type="number" name="costPrice" value={formData.costPrice || ''} readOnly className={`${inputStyleClasses} bg-gray-100 dark:bg-gray-800`}/>
                            <p className="text-[10px] text-gray-500 mt-1">Atualizado automaticamente via NF-e.</p>
                        </div>
                        <div>
                            <label className="block text-sm font-medium">Categoria</label>
                            <select name="categoryId" value={formData.categoryId || ''} onChange={handleChange} className={inputStyleClasses}>
                                <option value="">Nenhuma categoria</option>
                                {categories.map(cat => (
                                    <option key={cat.id} value={cat.id}>{cat.name}</option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium">Fornecedor Padrão (Último)</label>
                            <select name="supplierId" value={formData.supplierId || ''} onChange={handleChange} className={inputStyleClasses}>
                                <option value="">Nenhum / Vários</option>
                                {suppliers.map(sup => (
                                    <option key={sup.id} value={sup.id}>{sup.name}</option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium">Estoque Atual</label>
                            <input type="number" name="stock" value={formData.stock} readOnly className={`${inputStyleClasses} bg-gray-100 dark:bg-gray-800`}/>
                        </div>
                        <div>
                            <label className="block text-sm font-medium">Estoque Mínimo</label>
                            <input type="number" name="minStock" value={formData.minStock || ''} onChange={handleChange} min="0" className={inputStyleClasses}/>
                        </div>
                        <div className="flex items-center">
                            <input type="checkbox" id="isBulk" name="isBulk" checked={formData.isBulk} onChange={handleChange} className="h-4 w-4 rounded border-gray-300 text-theme-primary focus:ring-theme-primary"/>
                            <label htmlFor="isBulk" className="ml-2 block text-sm">Vendido a Granel (por kg)</label>
                        </div>
                        {formData.isBulk && (
                            <div>
                                <label className="block text-sm font-medium">Código da Balança (6 dígitos)</label>
                                <input type="text" name="scaleCode" value={formData.scaleCode || ''} onChange={handleChange} maxLength={6} className={inputStyleClasses}/>
                            </div>
                        )}
                        <div className="md:col-span-2">
                            <label className="block text-sm font-medium">URL da Imagem</label>
                            <div className="flex items-center gap-4 mt-1">
                                <input type="text" name="image" value={formData.image || ''} onChange={e => { handleChange(e); setImageError(false); }} className={inputStyleClasses + " flex-grow"}/>
                                {formData.image && !imageError ? ( <img src={formData.image} alt="Preview" className="w-16 h-16 rounded-md object-cover border dark:border-gray-600" onError={() => setImageError(true)}/> ) : ( <div className="w-16 h-16 rounded-md border dark:border-gray-600 bg-gray-100 dark:bg-gray-700 flex items-center justify-center"><ImageOff className="text-gray-400" /></div> )}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Aba de Tributação */}
                <div className={activeTab === 'tax' ? 'block space-y-4' : 'hidden'}>
                     <div className="p-4 bg-blue-50 dark:bg-blue-900/30 border-l-4 border-blue-500 rounded-r-lg mb-4">
                        <p className="text-sm text-blue-800 dark:text-blue-200">
                            Configure os dados fiscais para emissão correta da NFC-e.
                        </p>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                         <div>
                            <label className="block text-sm font-medium">NCM</label>
                            <input type="text" name="ncm" value={formData.ncm || ''} onChange={handleChange} className={inputStyleClasses}/>
                        </div>
                         <div>
                            <label className="block text-sm font-medium">CFOP</label>
                            <input type="text" name="cfop" value={formData.cfop || ''} onChange={handleChange} className={inputStyleClasses}/>
                        </div>
                        <div>
                            <label className="block text-sm font-medium">Origem</label>
                            <select name="origin" value={formData.origin || ''} onChange={handleChange} className={inputStyleClasses}>
                                <option value="0">0 - Nacional</option>
                                <option value="1">1 - Estrangeira (Direta)</option>
                                <option value="2">2 - Estrangeira (Mercado Interno)</option>
                            </select>
                        </div>
                         <div>
                            <label className="block text-sm font-medium">CSOSN / CST</label>
                            <input type="text" name="csosn_cst" value={formData.csosn_cst || ''} onChange={handleChange} className={inputStyleClasses}/>
                        </div>
                    </div>
                </div>

                {/* Aba de Histórico de Compras */}
                <div className={activeTab === 'history' ? 'block' : 'hidden'}>
                    {purchaseHistory.length === 0 ? (
                        <div className="text-center py-12 text-gray-500">
                            <History size={48} className="mx-auto mb-2 opacity-20" />
                            <p>Nenhuma compra registrada via NF-e para este produto.</p>
                        </div>
                    ) : (
                        <div className="overflow-hidden border dark:border-gray-700 rounded-lg">
                            <table className="w-full text-sm text-left">
                                <thead className="bg-gray-50 dark:bg-gray-900/50 text-xs uppercase text-gray-500">
                                    <tr>
                                        <th className="px-4 py-3">Data</th>
                                        <th className="px-4 py-3">Fornecedor</th>
                                        <th className="px-4 py-3 text-right">Qtd.</th>
                                        <th className="px-4 py-3 text-right">Custo Unit.</th>
                                        <th className="px-4 py-3 text-center">Trend</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y dark:divide-gray-700">
                                    {purchaseHistory.map((lot, index) => {
                                        const nextLot = purchaseHistory[index + 1];
                                        let TrendIcon = Minus;
                                        let trendColor = 'text-gray-400';

                                        if (nextLot) {
                                            if (lot.costPrice > nextLot.costPrice) {
                                                TrendIcon = TrendingUp;
                                                trendColor = 'text-red-500';
                                            } else if (lot.costPrice < nextLot.costPrice) {
                                                TrendIcon = TrendingDown;
                                                trendColor = 'text-green-500';
                                            }
                                        }

                                        return (
                                            <tr key={lot.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/30 transition-colors">
                                                <td className="px-4 py-3 whitespace-nowrap">
                                                    {new Date(lot.entryDate).toLocaleDateString('pt-BR')}
                                                </td>
                                                <td className="px-4 py-3 font-medium">
                                                    {lot.supplierId ? supplierMap.get(lot.supplierId) : 'Entrada Manual'}
