                     <thead className="text-[10px] text-gray-500 uppercase font-black bg-gray-50 dark:bg-gray-700/50">
                        <tr>
                            <th className="px-6 py-4">Produto</th>
                            <th className="px-6 py-4">Categoria</th>
                            <th className="px-6 py-4">Cód. Barras</th>
                            <th className="px-6 py-4 text-right">Preço Venda</th>
                            <th className="px-6 py-4 text-right">Estoque</th>
                            <th className="px-6 py-4 text-center">Ações</th>
                        </tr>
                        <tr className="bg-white dark:bg-gray-800">
                            <th className="px-4 py-2 font-normal">
                                <input type="text" name="name" placeholder="Filtrar..." value={filters.name} onChange={handleFilterChange} className={filterInputClass} />
                            </th>
                            <th className="px-4 py-2 font-normal">
                                 <select name="categoryId" value={filters.categoryId} onChange={handleFilterChange} className={filterInputClass}>
                                    <option value="">Todas</option>
                                    {categories.map(cat => ( <option key={cat.id} value={cat.id}>{cat.name}</option> ))}
                                </select>
                            </th>
                             <th className="px-4 py-2 font-normal">
                                <input type="text" name="id" placeholder="Cód..." value={filters.id} onChange={handleFilterChange} className={filterInputClass} />
                            </th>
                             <th className="px-4 py-2 font-normal"></th>
                             <th className="px-4 py-2 font-normal"></th>
                            <th className="px-4 py-2"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                        {filteredProducts.map(product => (
                            <tr key={product.id} className="hover:bg-gray-50 dark:hover:bg-gray-600/10 transition-colors">
                                <td className="px-6 py-4 font-bold text-gray-700 dark:text-gray-200">{product.name}</td>
                                <td className="px-6 py-4 text-gray-500">{categoryMap.get(product.categoryId || '') || '-'}</td>
                                <td className="px-6 py-4 font-mono text-xs text-gray-400">{product.id}</td>
                                <td className="px-6 py-4 text-right font-mono font-bold text-theme-primary">{formatCurrency(product.price)}</td>
                                <td className="px-6 py-4 text-right">
                                    <div className="flex flex-col items-end">
                                        <span className={`font-mono font-bold ${product.stock <= (product.minStock || 0) ? 'text-red-500' : 'text-gray-600 dark:text-gray-300'}`}>
                                            {product.stock.toFixed(2)} {product.isBulk ? 'kg' : 'un'}
                                        </span>
                                    </div>
                                </td>
                                <td className="px-6 py-4 text-center">
                                    <div className="flex justify-center gap-2">
                                        <Button variant="secondary" className="!p-2 h-auto" onClick={() => onEditProduct(product.id)}><Edit size={16}/></Button>
                                        <Button variant="danger" className="!p-2 h-auto" onClick={() => handleDelete(product.id)}><Trash2 size={16}/></Button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                 {filteredProducts.length === 0 && (
                    <div className="text-center p-12 text-gray-400 uppercase text-xs font-bold tracking-widest">
                        Nenhum produto encontrado.
                    </div>
                )}
            </div>
        </div>
    );
};

export default ProductManagement;

import React, { useState, useEffect } from 'react';
import { ShoppingCart, Users, BarChart, FileText, Boxes, ChevronDown, ChevronUp, ArrowLeft, BrainCircuit, Landmark, Wallet, FileCode } from 'lucide-react';
import { db } from '../../services/databaseService';
import type { Category } from '../../types';
import Button from '../shared/Button';

// Importa os componentes de cada módulo do ERP
import ProductManagement from './ProductManagement';
import CategoryManagement from './CategoryManagement';
import NFeImport from './NFeImport';
import InventoryReport from './InventoryReport';
import CustomerManagement from './CustomerManagement';
import ProductFormPage from './ProductFormPage';
import CustomerFormPage from './CustomerFormPage'; 
import CategoryFormPage from './CategoryFormPage'; 
import GenerateOrder from './GenerateOrder'; 
import ExpenseManagement from './ExpenseManagement';
import ExpenseFormPage from './ExpenseFormPage';
import DREDashboard from './DREDashboard';
import HRManagement from './HRManagement';
import CashAudit from './CashAudit';

interface ERPScreenProps {
    setView: (view: 'pos' | 'erp' | 'crm' | 'fiscal') => void;
}

type ActiveModule = 'products' | 'categories' | 'customers' | 'financial' | 'expenses' | 'reports' | 'nfeImport' | 'inventory' | 'generateOrder' | 'dre' | 'hr' | 'cashAudit';

type ERPView = 
  | { type: 'module', id: ActiveModule }
  | { type: 'product_form', productId?: string }
  | { type: 'customer_form', customerId?: string }
  | { type: 'category_form', categoryId?: string }
  | { type: 'expense_form', expenseId?: string };


interface MenuItem { id: ActiveModule; label: string; }
interface MenuModule { id: string; label: string; icon: React.ElementType; items: MenuItem[]; }

const menuModules: MenuModule[] = [
    {
        id: 'estrategico',
        label: 'Gestão Estratégica',
        icon: BrainCircuit,
        items: [
            { id: 'dre', label: 'Painel DRE / Lucro' },
            { id: 'cashAudit', label: 'Controle de Caixa' },
            { id: 'hr', label: 'Equipe e RH' },
        ],
    },
    {
        id: 'estoque',
        label: 'Estoque',
        icon: Boxes,
        items: [
            { id: 'products', label: 'Produtos' },
            { id: 'categories', label: 'Categorias' },
            { id: 'inventory', label: 'Inventário' },
        ],
    },
    {
        id: 'compras',
        label: 'Compras',
        icon: ShoppingCart,
        items: [
            { id: 'generateOrder', label: 'Pedidos' },
            { id: 'nfeImport', label: 'Importar NF-e' },
        ],
    },
    {
        id: 'clientes',
        label: 'Clientes',
        icon: Users,
        items: [ { id: 'customers', label: 'Clientes' } ],
    },
    {
        id: 'financeiro',
        label: 'Financeiro',
        icon: BarChart,
        items: [
            { id: 'expenses', label: 'Contas a Pagar' },
        ],
    },
];

const ERPScreen: React.FC<ERPScreenProps> = ({ setView }) => {
    const [currentErpView, setCurrentErpView] = useState<ERPView>({ type: 'module', id: 'dre' }); 
    const [expandedSections, setExpandedSections] = useState<Set<string>>(new Set(['estrategico', 'estoque', 'financeiro']));
    const [categories, setCategories] = useState<Category[]>([]);

    useEffect(() => {
        db.getAll('categories').then(cats => setCategories(cats.sort((a,b) => a.name.localeCompare(b.name))));
    }, []);

    const toggleSection = (sectionId: string) => {
        setExpandedSections(prev => {
            const newSet = new Set(prev);
            if (newSet.has(sectionId)) newSet.delete(sectionId);
            else newSet.add(sectionId);
            return newSet;
        });
    };

    const renderActiveModule = () => {
        switch(currentErpView.type) {
            case 'product_form': return <ProductFormPage productId={currentErpView.productId} categories={categories} onBack={() => setCurrentErpView({ type: 'module', id: 'products' })} />;
            case 'customer_form': return <CustomerFormPage customerId={currentErpView.customerId} onBack={() => setCurrentErpView({ type: 'module', id: 'customers' })} />;
            case 'category_form': return <CategoryFormPage categoryId={currentErpView.categoryId} onBack={() => setCurrentErpView({ type: 'module', id: 'categories' })} />;
            case 'expense_form': return <ExpenseFormPage expenseId={currentErpView.expenseId} onBack={() => setCurrentErpView({ type: 'module', id: 'expenses' })} />;
            case 'module':
                switch(currentErpView.id) {
                    case 'dre': return <DREDashboard />;
                    case 'hr': return <HRManagement />;
                    case 'cashAudit': return <CashAudit />;
                    case 'products': return <ProductManagement onNewProduct={() => setCurrentErpView({ type: 'product_form' })} onEditProduct={(id) => setCurrentErpView({ type: 'product_form', productId: id })} onImportXML={() => setCurrentErpView({ type: 'module', id: 'nfeImport' })} />;
                    case 'categories': return <CategoryManagement onNewCategory={() => setCurrentErpView({ type: 'category_form' })} onEditCategory={(id) => setCurrentErpView({ type: 'category_form', categoryId: id })} />;
                    case 'customers': return <CustomerManagement onNewCustomer={() => setCurrentErpView({ type: 'customer_form' })} onEditCustomer={(id) => setCurrentErpView({ type: 'customer_form', customerId: id })} />;
                    case 'expenses': return <ExpenseManagement onNewExpense={() => setCurrentErpView({ type: 'expense_form' })} onEditExpense={(id) => setCurrentErpView({ type: 'expense_form', expenseId: id })} />;
                    case 'nfeImport': return <NFeImport />;
                    case 'generateOrder': return <GenerateOrder />;
                    case 'inventory': return <InventoryReport />;
                    default: return <div className="p-8">Módulo em construção</div>;
                }
        }
    };

    const getHeaderInfo = () => {
        if (currentErpView.type === 'module') {
            const label = menuModules.flatMap(m => m.items).find(i => i.id === currentErpView.id)?.label || 'Dashboard';
            return { title: label, activeModule: currentErpView.id, backAction: null as (() => void) | null };
        }

        switch(currentErpView.type) {
            case 'product_form': 
                return { title: 'Editar Produto', activeModule: 'products' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'products' }) };
            case 'customer_form': 
                return { title: 'Editar Cliente', activeModule: 'customers' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'customers' }) };
            case 'category_form': 
                return { title: 'Editar Categoria', activeModule: 'categories' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'categories' }) };
            case 'expense_form': 
                return { title: 'Editar Despesa', activeModule: 'expenses' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'expenses' }) };
            default:
                return { title: 'ERP', activeModule: 'dre' as ActiveModule, backAction: null as (() => void) | null };
        }
    };
    const { title, activeModule, backAction } = getHeaderInfo();

    return (
        <div className="flex flex-col md:flex-row h-full bg-gray-100 dark:bg-gray-900">
            <aside className="w-full md:w-64 bg-white dark:bg-gray-800 shadow-md md:shadow-none md:border-r dark:border-gray-700 flex flex-col order-1">
                <div className="hidden md:block p-4 border-b dark:border-gray-700">
                    <h1 className="text-xl font-bold text-gray-800 dark:text-gray-100 uppercase tracking-tighter">Gestão BI</h1>
                    <span className="text-[10px] font-black text-theme-primary">USENATURAL v2.0</span>
                </div>
                <nav className="flex-grow md:p-2 overflow-x-auto md:overflow-y-auto whitespace-nowrap md:whitespace-normal">
                    <ul className="flex md:flex-col p-2 md:p-0 gap-2 md:gap-1 items-center md:items-stretch">
                        {menuModules.map(module => {
                            const isExpanded = expandedSections.has(module.id);
                            return (
                                <li key={module.id} className="inline-flex md:block md:flex-col">
                                    <button onClick={() => toggleSection(module.id)} className="hidden md:flex items-center justify-between w-full gap-3 px-4 py-2 rounded-md text-xs font-black uppercase tracking-widest text-gray-400 hover:text-theme-primary transition-all">
                                        <div className="flex items-center gap-3"><module.icon className="w-4 h-4" /><span>{module.label}</span></div>
                                        {isExpanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
                                    </button>
                                    <ul className={`flex flex-row md:flex-col gap-2 md:gap-1 md:pl-6 md:mt-1 ${!isExpanded ? 'md:hidden' : 'md:block'}`}>
                                        {module.items.map(item => (
                                            <li key={item.id} className="inline-block md:block">
                                                <a href="#" onClick={(e) => { e.preventDefault(); setCurrentErpView({ type: 'module', id: item.id }); }} 
                                                    className={`flex items-center gap-2 px-3 py-2 md:px-4 rounded-xl text-sm font-bold transition-all border md:border-0 ${activeModule === item.id ? 'bg-theme-primary text-white' : 'bg-gray-50 text-gray-600 border-gray-200 hover:bg-gray-100 dark:bg-gray-700 dark:text-gray-300'}`}>
                                                    <span>{item.label}</span>
                                                </a>
                                            </li>
                                        ))}
                                    </ul>
                                </li>
                            );
                        })}
                    </ul>
                </nav>
            </aside>
            <main className="flex-1 flex flex-col overflow-hidden order-2 h-full">
                <header className="bg-white dark:bg-gray-800 shadow-sm p-4 flex items-center gap-4 shrink-0">
                    {backAction && <Button variant="secondary" onClick={backAction} className="!py-2 !px-3"><ArrowLeft size={16} className="mr-2"/> Voltar</Button>}
                    <h2 className="text-xl md:text-2xl font-black text-gray-800 dark:text-gray-100 capitalize truncate tracking-tight">{title}</h2>
                </header>
                <div className="flex-1 overflow-y-auto p-4 md:p-6">{renderActiveModule()}</div>
            </main>
        </div>
    );
};

export default ERPScreen;

import React, { useState, useEffect } from 'react';
import Button from '../shared/Button';
import { db } from '../../services/databaseService';
import type { ParkedSale } from '../../types';
import { OrderType } from '../../types';
import { Store, Truck, MapPin, Phone, ShoppingCart, Search, Trash2, ArrowLeft, MessageCircle, Printer } from 'lucide-react';

interface ParkedSalesScreenProps {
  onBack: () => void;
  onLoadSale: (sale: ParkedSale) => void;
}

const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
const formatDateTime = (date: Date) => date.toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', year: '2-digit', hour: '2-digit', minute: '2-digit' });

const ParkedSalesScreen: React.FC<ParkedSalesScreenProps> = ({ onBack, onLoadSale }) => {
    const [parkedSales, setParkedSales] = useState<ParkedSale[]>([]);
    const [searchTerm, setSearchTerm] = useState('');

    const fetchSales = async () => {
        const sales = await db.getAllFromIndex('parkedSales', 'createdAt');
        setParkedSales(sales.reverse());
    };

    useEffect(() => {
        fetchSales();
    }, []);

    const handleDelete = async (id: string) => {
      if (confirm('Tem certeza que deseja excluir este pedido permanentemente?')) {
        await db.delete('parkedSales', id);
        fetchSales();
      }
    };

    const handlePrintReceipt = (sale: ParkedSale) => {
        const printWindow = window.open('', '', 'width=300,height=600');
        if (!printWindow) return;

        const itemsHtml = sale.items.map(item => `
            <tr>
                <td style="padding: 2px 0;">${item.productName.substring(0, 20)}</td>
                <td style="text-align: center;">${item.quantity.toFixed(2)}</td>
                <td style="text-align: right;">${formatCurrency(item.total)}</td>
            </tr>
        `).join('');

        printWindow.document.write(`
            <html>
            <head>
                <style>
                    body { font-family: 'Courier New', Courier, monospace; font-size: 12px; width: 80mm; margin: 0; padding: 10px; }
                    .header { text-align: center; font-weight: bold; border-bottom: 1px dashed #000; padding-bottom: 5px; margin-bottom: 5px; }
                    table { width: 100%; border-collapse: collapse; }
                    .total-area { border-top: 1px dashed #000; margin-top: 5px; padding-top: 5px; font-weight: bold; }
                    .customer-info { margin-top: 10px; font-size: 10px; border-top: 1px solid #eee; padding-top: 5px; }
                    @media print { @page { margin: 0; } }
                </style>
            </head>
            <body>
                <div class="header">
                    BEM ESTAR<br>GESTÃO COMERCIAL<br>
                    <small>${formatDateTime(new Date(sale.createdAt))}</small>
                </div>
                <div style="text-align: center; margin-bottom: 5px; font-weight: bold;">*** PEDIDO DE ${sale.type.toUpperCase()} ***</div>
                <table>
                    <thead>
                        <tr>
                            <th style="text-align: left;">DESC</th>
                            <th style="text-align: center;">QTD</th>
                            <th style="text-align: right;">TOTAL</th>
                        </tr>
                    </thead>
                    <tbody>${itemsHtml}</tbody>
                </table>
                <div class="total-area">
                    <div style="display: flex; justify-content: space-between;">
                        <span>TOTAL:</span>
                        <span>${formatCurrency(sale.total)}</span>
                    </div>
                </div>
                <div class="customer-info">
                    <strong>CLIENTE:</strong> ${sale.customerName}<br>
                    ${sale.contactPhone ? `<strong>TEL:</strong> ${sale.contactPhone}<br>` : ''}
                    ${sale.type === OrderType.ENTREGA ? `<strong>END:</strong> ${sale.deliveryAddress}<br>` : ''}
                    ${sale.notes ? `<strong>OBS:</strong> ${sale.notes}` : ''}
                </div>
                <div style="text-align: center; margin-top: 20px; font-size: 9px;">
                    ESTE DOCUMENTO NÃO É NOTA FISCAL<br>Obrigado pela preferência!
                </div>
                <script>window.onload = () => { window.print(); window.close(); }</script>
            </body>
            </html>
        `);
        printWindow.document.close();
    };

    const handleShareWhatsApp = (sale: ParkedSale) => {
        const line = "--------------------------------";
        let text = `*BEM ESTAR - PEDIDO* 🌿\n`;
        text += `_${formatDateTime(new Date(sale.createdAt))}_\n`;
        text += `*TIPO:* ${sale.type.toUpperCase()}\n`;
        text += `${line}\n`;

        text += `*PRODUTOS:*\n`;
        sale.items.forEach(item => {
            const qty = item.quantity.toFixed(2);
            text += `• ${qty} x ${item.productName.toUpperCase()} = ${formatCurrency(item.total)}\n`;
        });

        text += `${line}\n`;
        text += `*VALOR TOTAL: ${formatCurrency(sale.total)}*\n`;
        text += `${line}\n\n`;

        text += `*DADOS PARA ENTREGA/RETIRADA:*\n`;
        text += `👤 *NOME:* ${sale.customerName}\n`;
        if (sale.contactPhone) text += `📞 *CONTATO:* ${sale.contactPhone}\n`;

        if (sale.type === OrderType.ENTREGA) {
            text += `📍 *ENDEREÇO:* ${sale.deliveryAddress}\n`;
        }

        if (sale.notes) {
            text += `📝 *OBSERVAÇÃO:* ${sale.notes}\n`;
        }

        text += `\n*Agradecemos a preferência!*`;

        const encodedText = encodeURIComponent(text);
        const cleanPhone = sale.contactPhone?.replace(/\D/g, '');
        const whatsappUrl = cleanPhone 
            ? `https://wa.me/55${cleanPhone}?text=${encodedText}`
            : `https://wa.me/?text=${encodedText}`;

        window.open(whatsappUrl, '_blank');
    };

    const filteredSales = parkedSales.filter(s => 
      s.customerName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      s.deliveryAddress?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      s.contactPhone?.includes(searchTerm)
    );

    return (
        <div className="h-full flex flex-col bg-gray-50 dark:bg-gray-900 p-4 md:p-6">
            <div className="max-w-6xl mx-auto w-full flex flex-col h-full space-y-6">

              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                  <div>
                    <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-100">Pedidos e Encomendas</h2>
                    <p className="text-sm text-gray-500">Gerencie vendas em espera, retiradas e entregas.</p>
                  </div>
                  <div className="relative w-full md:w-96">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                    <input 
                      type="text" 
                      placeholder="Buscar por cliente, endereço ou telefone..."
                      value={searchTerm}
                      onChange={e => setSearchTerm(e.target.value)}
                      className="w-full pl-10 pr-4 py-2 rounded-lg border dark:bg-gray-800 dark:border-gray-700"
                    />
                  </div>
              </div>

              <div className="flex-grow overflow-y-auto space-y-4 pr-2">
                  {filteredSales.length === 0 ? (
                      <div className="flex flex-col items-center justify-center py-20 text-gray-400">
                        <ShoppingCart size={64} className="opacity-10 mb-4" />
                        <p className="text-lg font-medium">Nenhum pedido encontrado.</p>
                        <Button variant="secondary" className="mt-4" onClick={onBack}>Voltar ao Checkout</Button>
                      </div>
                  ) : (
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                      {filteredSales.map(sale => (
                          <div key={sale.id} className="flex flex-col gap-4 p-5 rounded-2xl bg-white dark:bg-gray-800 border-2 border-transparent hover:border-theme-primary transition-all shadow-sm group">
                              <div className="flex justify-between items-start">
                                  <div className="flex items-center gap-4">
                                    <div className={`p-3 rounded-xl ${sale.type === OrderType.ENTREGA ? 'bg-orange-100 text-orange-600 dark:bg-orange-900/30' : 'bg-green-100 text-green-600 dark:bg-green-900/30'}`}>
                                      {sale.type === OrderType.ENTREGA ? <Truck size={24} /> : <Store size={24} />}
                                    </div>
                                    <div>
                                      <p className="font-black text-lg text-gray-800 dark:text-gray-100 leading-tight">{sale.customerName}</p>
                                      <p className="text-xs text-gray-500 font-bold uppercase tracking-wider mt-1">{sale.type} • {formatDateTime(sale.createdAt)}</p>
                                    </div>
                                  </div>
                                  <div className="text-right">
                                    <p className="text-xl font-black text-theme-primary">{formatCurrency(sale.total)}</p>
                                    <p className="text-xs text-gray-500">{sale.items.length} item(ns)</p>
                                  </div>
                              </div>

                              <hr className="border-gray-100 dark:border-gray-700" />

                              <div className="space-y-2">
                                {sale.type === OrderType.ENTREGA && (
                                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3 text-sm">
                                    <div className="flex items-start gap-2 text-gray-600 dark:text-gray-400">
                                      <MapPin size={16} className="shrink-0 text-theme-primary mt-0.5" />
                                      <span className="leading-tight">{sale.deliveryAddress}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-gray-600 dark:text-gray-400">
                                      <Phone size={16} className="shrink-0 text-theme-primary" />
                                      <span className="font-mono">{sale.contactPhone}</span>
                                    </div>
                                  </div>
                                )}

                                {sale.notes && (
                                  <div className="p-3 bg-gray-50 dark:bg-gray-900/50 rounded-lg border border-dashed border-gray-200 dark:border-gray-700">
                                    <p className="text-xs italic text-gray-500 dark:text-gray-400">
                                      " {sale.notes} "
                                    </p>
                                  </div>
                                )}
                              </div>

                              <div className="flex gap-2 pt-2 mt-auto">
                                  <Button variant="danger" className="!p-3" onClick={() => handleDelete(sale.id)} title="Excluir Pedido">
                                      <Trash2 size={20} />
                                  </Button>
                                  <button 
                                      onClick={() => handlePrintReceipt(sale)}
                                      className="flex items-center justify-center gap-2 px-3 py-3 bg-gray-200 hover:bg-gray-300 text-gray-800 rounded-md font-bold transition-colors"
                                      title="Imprimir Pedido"
                                  >
                                      <Printer size={20} />
                                  </button>
                                  <button 
                                      onClick={() => handleShareWhatsApp(sale)}
                                      className="flex items-center justify-center gap-2 px-4 py-3 bg-green-500 hover:bg-green-600 text-white rounded-md font-bold transition-colors"
                                      title="Enviar para WhatsApp"
                                  >
                                      <MessageCircle size={20} /> <span className="hidden sm:inline">WhatsApp</span>
                                  </button>
                                  <Button variant="primary" className="flex-grow text-lg font-bold" onClick={() => onLoadSale(sale)}>
                                      Finalizar
                                  </Button>
                              </div>
                          </div>
                      ))}
                    </div>
                  )}
              </div>

              <div className="pt-4 border-t dark:border-gray-800 flex justify-between items-center shrink-0">
                  <span className="text-sm font-bold text-gray-400 uppercase tracking-widest">{filteredSales.length} Pedidos Ativos</span>
                  <Button variant="secondary" onClick={onBack}>
                    <ArrowLeft size={18} className="mr-2" /> Sair dos Pedidos
                  </Button>
              </div>
            </div>
        </div>
    );
};

export default ParkedSalesScreen;

import React, { useState, useEffect, useMemo } from 'react';
import { db } from '../../services/databaseService';
import type { Sale } from '../../types';
import Button from '../shared/Button';
import { ReceiptText, Clock, ShoppingBag, CreditCard, ChevronDown, ChevronUp, Search, Calendar, ArrowLeft, MessageCircle, Printer } from 'lucide-react';

interface TodaySalesScreenProps {
  onBack: () => void;
}

const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
const formatDateTime = (date: Date) => date.toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', year: '2-digit', hour: '2-digit', minute: '2-digit' });
const formatTime = (date: Date) => date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

const TodaySalesScreen: React.FC<TodaySalesScreenProps> = ({ onBack }) => {
  const [sales, setSales] = useState<Sale[]>([]);
  const [expandedSaleId, setExpandedSaleId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    const fetchSales = async () => {
      const allSales = await db.getAll('sales');
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      const todaySales = allSales
        .filter(sale => new Date(sale.date) >= today)
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

      setSales(todaySales);
    };
    fetchSales();
  }, []);

  const handlePrintReceipt = (sale: Sale) => {
    const printWindow = window.open('', '', 'width=300,height=600');
    if (!printWindow) return;

    const itemsHtml = sale.items.map(item => `
        <tr>
            <td style="padding: 2px 0;">${item.productName.substring(0, 20)}</td>
            <td style="text-align: center;">${item.quantity.toFixed(2)}</td>
            <td style="text-align: right;">${formatCurrency(item.total)}</td>
        </tr>
    `).join('');

    const paymentsHtml = sale.payments.map(p => `
        <div style="display: flex; justify-content: space-between; font-size: 10px;">
            <span>${p.method.toUpperCase()}:</span>
            <span>${formatCurrency(p.amount)}</span>
        </div>
    `).join('');

    printWindow.document.write(`
        <html>
        <head>
            <style>
                body { font-family: 'Courier New', Courier, monospace; font-size: 12px; width: 80mm; margin: 0; padding: 10px; }
                .header { text-align: center; font-weight: bold; border-bottom: 1px dashed #000; padding-bottom: 5px; margin-bottom: 5px; }
                table { width: 100%; border-collapse: collapse; }
                .total-area { border-top: 1px dashed #000; margin-top: 5px; padding-top: 5px; font-weight: bold; }
                .payment-area { margin-top: 5px; padding-top: 5px; border-top: 1px solid #eee; }
                @media print { @page { margin: 0; } }
            </style>
        </head>
        <body>
            <div class="header">
                BEM ESTAR<br>RECIBO DE VENDA<br>
                <small>${formatDateTime(new Date(sale.date))}</small><br>
                <small>ID: ${sale.id.split('-')[0].toUpperCase()}</small>
            </div>
            <table>
                <thead>
                    <tr>
                        <th style="text-align: left;">DESC</th>
                        <th style="text-align: center;">QTD</th>
                        <th style="text-align: right;">TOTAL</th>
                    </tr>
                </thead>
                <tbody>${itemsHtml}</tbody>
            </table>
            <div class="total-area">
                <div style="display: flex; justify-content: space-between;">
                    <span>SUBTOTAL:</span>
                    <span>${formatCurrency(sale.subtotal)}</span>
                </div>
                ${sale.totalDiscount > 0 ? `
                <div style="display: flex; justify-content: space-between; color: #666;">
                    <span>DESCONTO:</span>
                    <span>-${formatCurrency(sale.totalDiscount)}</span>
                </div>` : ''}
                <div style="display: flex; justify-content: space-between; font-size: 14px;">
                    <span>TOTAL:</span>
                    <span>${formatCurrency(sale.totalAmount)}</span>
                </div>
            </div>
            <div class="payment-area">
                <strong>PAGAMENTOS:</strong>
                ${paymentsHtml}
                ${sale.change > 0 ? `<div style="display: flex; justify-content: space-between;"><span>TROCO:</span><span>${formatCurrency(sale.change)}</span></div>` : ''}
            </div>
            <div style="text-align: center; margin-top: 20px; font-size: 9px;">
                OBRIGADO PELA PREFERÊNCIA!<br>Volte sempre.
            </div>
            <script>window.onload = () => { window.print(); window.close(); }</script>
        </body>
        </html>
    `);
    printWindow.document.close();
  };

  const handleShareWhatsApp = async (sale: Sale) => {
    const line = "--------------------------------";
    let text = `*BEM ESTAR - RECIBO* 🧾\n`;
    text += `_${new Date(sale.date).toLocaleString('pt-BR')}_\n`;
    text += `*ID:* ${sale.id.split('-')[0].toUpperCase()}\n`;
    text += `${line}\n`;

    text += `*PRODUTOS:*\n`;
    sale.items.forEach(item => {
        text += `• ${item.quantity.toFixed(2)} x ${item.productName.toUpperCase()} = ${formatCurrency(item.total)}\n`;
    });

    text += `${line}\n`;
    text += `*SUBTOTAL:* ${formatCurrency(sale.subtotal)}\n`;
    if (sale.totalDiscount > 0) text += `*DESC:* -${formatCurrency(sale.totalDiscount)}\n`;
    text += `*TOTAL: ${formatCurrency(sale.totalAmount)}*\n`;
    text += `${line}\n`;

    text += `*PAGAMENTO:*\n`;
    sale.payments.forEach(p => {
        text += `• ${p.method.toUpperCase()}: ${formatCurrency(p.amount)}\n`;
    });

    if (sale.change > 0) text += `*TROCO:* ${formatCurrency(sale.change)}\n`;

    text += `\n*Agradecemos a preferência!* 🌿`;

    const encodedText = encodeURIComponent(text);

    let phone = "";
    if (sale.customerId) {
        const customer = await db.get('customers', sale.customerId);
        if (customer?.cellphone) phone = customer.cellphone.replace(/\D/g, '');
    }

    const whatsappUrl = phone 
        ? `https://wa.me/55${phone}?text=${encodedText}`
        : `https://wa.me/?text=${encodedText}`;

    window.open(whatsappUrl, '_blank');
  };

  const filteredSales = useMemo(() => {
    return sales.filter(s => 
      s.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
      s.customerCPF?.includes(searchTerm) ||
      s.items.some(i => i.productName.toLowerCase().includes(searchTerm.toLowerCase()))
    );
  }, [sales, searchTerm]);

  const dailyTotal = useMemo(() => {
    return filteredSales.reduce((acc, sale) => acc + sale.totalAmount, 0);
  }, [filteredSales]);

  return (
    <div className="h-full flex flex-col bg-gray-50 dark:bg-gray-900 p-4 md:p-6">
      <div className="max-w-5xl mx-auto w-full flex flex-col h-full space-y-6">

        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
              <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-100 flex items-center gap-3">
                <ReceiptText className="text-theme-primary" /> Vendas do Dia
              </h2>
              <div className="flex items-center gap-2 text-xs font-bold text-gray-500 uppercase mt-1">
                <Calendar size={12} /> {new Date().toLocaleDateString('pt-BR')}
              </div>
            </div>

            <div className="relative w-full md:w-80">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar por item, CPF ou ID..."
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 rounded-lg border dark:bg-gray-800 dark:border-gray-700"
              />
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <div className="bg-theme-primary/10 p-4 rounded-2xl border border-theme-primary/20">
            <p className="text-[10px] font-bold text-theme-primary uppercase">Faturamento Bruto</p>
            <p className="text-2xl font-black text-theme-primary">{formatCurrency(dailyTotal)}</p>
          </div>
          <div className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
            <p className="text-[10px] font-bold text-gray-500 uppercase">Qtd. Vendas</p>
            <p className="text-2xl font-black text-gray-800 dark:text-gray-100">{filteredSales.length}</p>
          </div>
          <div className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
            <p className="text-[10px] font-bold text-gray-500 uppercase">Ticket Médio</p>
            <p className="text-2xl font-black text-gray-800 dark:text-gray-100">
              {filteredSales.length > 0 ? formatCurrency(dailyTotal / filteredSales.length) : 'R$ 0,00'}
            </p>
          </div>
        </div>

        <div className="flex-grow overflow-y-auto space-y-3 pr-2 custom-scrollbar">
          {filteredSales.length === 0 ? (
            <div className="text-center py-20 text-gray-400">
              <ShoppingBag size={64} className="mx-auto mb-4 opacity-10" />
              <p className="text-lg font-medium">Nenhuma venda registrada até o momento.</p>
            </div>
          ) : (
            filteredSales.map(sale => (
              <div 
                key={sale.id} 
                className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl overflow-hidden transition-all shadow-sm hover:shadow-md"
              >
                <button 
                  onClick={() => setExpandedSaleId(expandedSaleId === sale.id ? null : sale.id)}
                  className="w-full flex items-center justify-between p-4 hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
                >
                  <div className="flex items-center gap-5 text-left">
                    <div className="p-3 bg-gray-100 dark:bg-gray-900 rounded-xl text-theme-primary">
                      <Clock size={20} />
                    </div>
                    <div>
                      <p className="font-black text-gray-800 dark:text-gray-100 text-lg leading-tight">{formatTime(new Date(sale.date))}</p>
                      <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest mt-1">
                        {sale.items.length} ITENS {sale.customerCPF ? `• CPF: ${sale.customerCPF}` : ''}
                      </p>
                    </div>
                  </div>

                  <div className="flex items-center gap-6">
                    <div className="text-right">
                      <p className="font-black text-xl text-theme-primary">{formatCurrency(sale.totalAmount)}</p>
                      <span className="text-[9px] text-gray-400 uppercase font-bold">ID: {sale.id.split('-')[0]}</span>
                    </div>
                    {expandedSaleId === sale.id ? <ChevronUp size={24} className="text-gray-400" /> : <ChevronDown size={24} className="text-gray-400" />}
                  </div>
                </button>

                {expandedSaleId === sale.id && (
                  <div className="p-5 bg-gray-50 dark:bg-gray-900/50 border-t border-gray-100 dark:border-gray-700 space-y-4 animate-in fade-in slide-in-from-top-1 duration-200">
                    <div className="space-y-2">
                      <div className="flex justify-between items-center mb-2">
                        <p className="text-[10px] font-bold text-gray-400 uppercase">Detalhamento dos Itens</p>
                        <div className="flex gap-2">
                            <button 
                                onClick={() => handlePrintReceipt(sale)}
                                className="flex items-center gap-1 px-2 py-1 bg-gray-200 hover:bg-gray-300 text-gray-700 text-[10px] font-bold rounded transition-colors"
                            >
                                <Printer size={12} /> IMPRIMIR
                            </button>
                            <button 
                                onClick={() => handleShareWhatsApp(sale)}
                                className="flex items-center gap-1 px-2 py-1 bg-green-500 hover:bg-green-600 text-white text-[10px] font-bold rounded transition-colors"
                            >
                                <MessageCircle size={12} /> WHATSAPP
                            </button>
                        </div>
                      </div>
                      {sale.items.map((item, idx) => (
                        <div key={idx} className="flex justify-between items-center text-sm p-2 bg-white dark:bg-gray-800 rounded-lg border border-gray-100 dark:border-gray-700">
                          <div className="flex gap-2">
                            <span className="font-bold text-theme-primary">{item.quantity}x</span>
                            <span className="text-gray-700 dark:text-gray-300">{item.productName}</span>
                          </div>
                          <span className="font-mono font-bold">{formatCurrency(item.total)}</span>
                        </div>
                      ))}
                    </div>

                    <div className="pt-4 border-t dark:border-gray-700 flex flex-wrap gap-2">
                      {sale.payments.map((p, idx) => (
                        <div key={idx} className="flex items-center gap-2 px-3 py-1.5 bg-theme-primary text-white rounded-lg text-xs font-bold shadow-sm">
                          <CreditCard size={14} />
                          <span className="uppercase">{p.method}</span>
                          <span className="bg-white/20 px-1.5 py-0.5 rounded">{formatCurrency(p.amount)}</span>
                        </div>
                      ))}
                      {sale.change > 0 && (
                        <div className="px-3 py-1.5 bg-blue-100 dark:bg-blue-900/50 text-blue-700 dark:text-blue-300 rounded-lg text-xs font-bold">
                          TROCO: {formatCurrency(sale.change)}
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>
            ))
          )}
        </div>

        <div className="pt-4 border-t dark:border-gray-800 flex justify-end shrink-0">
            <Button variant="secondary" onClick={onBack}>
              <ArrowLeft size={18} className="mr-2" /> Voltar ao Caixa
            </Button>
        </div>
      </div>
    </div>
  );
};

export default TodaySalesScreen;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { db } from '../../services/databaseService';
import type { Product, Category, Supplier, InventoryLot } from '../../types';
import Button from '../shared/Button';
import { ImageOff, ReceiptText, Save, History, TrendingUp, TrendingDown, Minus, Upload, X, ImageIcon } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface ProductFormPageProps {
  productId?: string;
  categories: Category[];
  onBack: () => void;
}

const ProductFormPage: React.FC<ProductFormPageProps> = ({ productId, categories, onBack }) => {
    const [formData, setFormData] = useState<Partial<Product>>({});
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [purchaseHistory, setPurchaseHistory] = useState<InventoryLot[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [imageError, setImageError] = useState(false);
    const [activeTab, setActiveTab] = useState('main');
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            const allSuppliers = await db.getAll('suppliers');
            setSuppliers(allSuppliers.sort((a,b) => a.name.localeCompare(b.name)));

            if (productId) {
                const [product, lots] = await Promise.all([
                    db.get('products', productId),
                    db.getAllFromIndex('inventoryLots', 'productId', productId)
                ]);

                if (product) {
                    const productData = { ...product };
                    if (productData.id === '2') {
                        productData.ncm = '12345678';
                    }
                    setFormData(productData);
                    setPurchaseHistory(lots.sort((a, b) => b.entryDate.getTime() - a.entryDate.getTime()));
                } else {
                    console.error("Product not found");
                    onBack();
                }
            } else {
                setFormData({
                    id: uuidv4(),
                    name: '',
                    price: 0,
                    costPrice: 0,
                    stock: 0,
                    minStock: 0,
                    isBulk: false,
                    scaleCode: '',
                    ncm: '',
                    cfop: '5102',
                    origin: '0',
                    csosn_cst: '102',
                    image: '',
                    categoryId: '',
                    supplierId: '',
                });
            }
            setIsLoading(false);
        };
        fetchData();
    }, [productId, onBack]);

    const supplierMap = useMemo(() => new Map(suppliers.map(s => [s.id, s.name])), [suppliers]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;

        if (type === 'checkbox') {
            const { checked } = e.target as HTMLInputElement;
            setFormData(prev => ({ ...prev, [name]: checked }));
        } else {
             setFormData(prev => ({ ...prev, [name]: type === 'number' ? parseFloat(value) : value }));
        }
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            if (file.size > 2 * 1024 * 1024) { // Limite de 2MB
                alert("A imagem é muito grande. Escolha uma imagem com menos de 2MB.");
                return;
            }
            const reader = new FileReader();
            reader.onloadend = () => {
                setFormData(prev => ({ ...prev, image: reader.result as string }));
                setImageError(false);
            };
            reader.readAsDataURL(file);
        }
    };

    const removeImage = () => {
        setFormData(prev => ({ ...prev, image: '' }));
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name || !formData.id || formData.price === undefined || formData.price < 0) {
            alert('Preencha os campos obrigatórios: ID, Nome e Preço de Venda.');
            return;
        }
        if (formData.isBulk && (!formData.scaleCode || formData.scaleCode.length !== 6)) {
            alert('Produtos a granel devem ter um "Código da Balança" de 6 dígitos.');
            return;
        }

        await db.put('products', formData as Product);
        onBack();
    };

    const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

    if (isLoading) {
        return <div className="text-center p-8">Carregando dados do produto...</div>;
    }

    const inputStyleClasses = "mt-1 block w-full rounded-md border border-gray-300 py-2 px-3 shadow-sm focus:border-theme-primary focus:ring-theme-primary dark:border-gray-600 dark:bg-gray-700";

    const TabButton: React.FC<{ tabId: string; icon?: React.ElementType; children: React.ReactNode }> = ({ tabId, icon: Icon, children }) => (
        <button
            type="button"
            onClick={() => setActiveTab(tabId)}
            className={`px-4 py-2 text-sm font-medium rounded-t-lg border-b-2 flex items-center gap-2 transition-colors ${activeTab === tabId ? 'border-theme-primary text-theme-primary bg-theme-primary/5' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300 dark:hover:border-gray-600'}`}
        >
            {Icon && <Icon size={16} />}
            {children}
        </button>
    );

    return (
         <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow">
            <div className="border-b border-gray-200 dark:border-gray-700 mb-6">
                <nav className="-mb-px flex space-x-2 overflow-x-auto" aria-label="Tabs">
                    <TabButton tabId="main">Dados Principais</TabButton>
                    <TabButton tabId="tax" icon={ReceiptText}>Tributação</TabButton>
                    {productId && <TabButton tabId="history" icon={History}>Histórico de Compras</TabButton>}
                </nav>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
                {/* Aba de Dados Principais */}
                <div className={activeTab === 'main' ? 'block' : 'hidden'}>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="md:col-span-1 space-y-4">
                            <div>
                                <label className="block text-sm font-medium">Nome do Produto</label>
                                <input type="text" name="name" value={formData.name} onChange={handleChange} required className={inputStyleClasses}/>
                            </div>
                            <div>
                                <label className="block text-sm font-medium">Código de Barras (ID)</label>
                                <input type="text" name="id" value={formData.id} required className={`${inputStyleClasses} bg-gray-100 dark:bg-gray-800 cursor-not-allowed`} readOnly/>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium">Preço de Venda (R$)</label>
                                    <input type="number" name="price" value={formData.price} onChange={handleChange} required min="0" step="0.01" className={inputStyleClasses}/>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium">Preço Custo Médio (R$)</label>
                                    <input type="number" name="costPrice" value={formData.costPrice || ''} readOnly className={`${inputStyleClasses} bg-gray-100 dark:bg-gray-800`}/>
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium">Categoria</label>
                                <select name="categoryId" value={formData.categoryId || ''} onChange={handleChange} className={inputStyleClasses}>
                                    <option value="">Nenhuma categoria</option>
                                    {categories.map(cat => (
                                        <option key={cat.id} value={cat.id}>{cat.name}</option>
                                    ))}
                                </select>
                            </div>
                        </div>

                        {/* SEÇÃO DE IMAGEM */}
                        <div className="md:col-span-1 space-y-2">
                            <label className="block text-sm font-medium">Imagem do Produto</label>
                            <div 
                                onClick={() => fileInputRef.current?.click()}
                                className="relative group cursor-pointer border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl aspect-video flex flex-col items-center justify-center bg-gray-50 dark:bg-gray-900 overflow-hidden hover:border-theme-primary transition-all"
                            >
                                {formData.image && !imageError ? (
                                    <>
                                        <img src={formData.image} alt="Preview" className="w-full h-full object-contain" onError={() => setImageError(true)}/>
                                        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                                            <span className="text-white font-bold flex items-center gap-2"><Upload size={20}/> Trocar Imagem</span>
                                        </div>
                                        <button 
                                            type="button" 
                                            onClick={(e) => { e.stopPropagation(); removeImage(); }}
                                            className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full hover:bg-red-600 shadow-lg z-10"
                                        >
                                            <X size={16} />
                                        </button>
                                    </>
                                ) : (
                                    <div className="text-center p-4">
                                        <ImageIcon className="w-12 h-12 text-gray-400 mx-auto mb-2" />
                                        <p className="text-sm font-bold text-gray-500">Clique para selecionar imagem</p>
                                        <p className="text-[10px] text-gray-400 uppercase mt-1">Recomendado: 800x800px (Máx 2MB)</p>
                                    </div>
                                )}
                                <input 
                                    ref={fileInputRef}
                                    type="file" 
                                    accept="image/*" 
                                    onChange={handleFileChange} 
                                    className="hidden"
                                />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Ou cole a URL da Imagem</label>
                                <input type="text" name="image" value={formData.image?.startsWith('data:') ? '' : (formData.image || '')} onChange={e => { handleChange(e); setImageError(false); }} placeholder="https://exemplo.com/imagem.jpg" className={inputStyleClasses + " text-xs"}/>
                            </div>
                        </div>

                        <div className="md:col-span-2 grid grid-cols-1 md:grid-cols-3 gap-4 border-t dark:border-gray-700 pt-4 mt-2">
                             <div>
                                <label className="block text-sm font-medium">Fornecedor Padrão (Último)</label>
                                <select name="supplierId" value={formData.supplierId || ''} onChange={handleChange} className={inputStyleClasses}>
