                }
        }
    };

    const getHeaderInfo = () => {
        if (currentErpView.type === 'module') {
            const label = menuModules.flatMap(m => m.items).find(i => i.id === currentErpView.id)?.label || 'Dashboard';
            return { title: label, activeModule: currentErpView.id, backAction: null as (() => void) | null };
        }

        switch(currentErpView.type) {
            case 'product_form': 
                return { title: 'Editar Produto', activeModule: 'products' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'products' }) };
            case 'customer_form': 
                return { title: 'Editar Cliente', activeModule: 'customers' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'customers' }) };
            case 'category_form': 
                return { title: 'Editar Categoria', activeModule: 'categories' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'categories' }) };
            case 'expense_form': 
                return { title: 'Editar Despesa', activeModule: 'expenses' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'expenses' }) };
            default:
                return { title: 'ERP', activeModule: 'dre' as ActiveModule, backAction: null as (() => void) | null };
        }
    };
    const { title, activeModule, backAction } = getHeaderInfo();

    return (
        <div className="flex flex-col md:flex-row h-full bg-gray-100 dark:bg-gray-900">
            <aside className="w-full md:w-64 bg-white dark:bg-gray-800 shadow-md md:shadow-none md:border-r dark:border-gray-700 flex flex-col order-1 shrink-0 overflow-y-auto">
                <div className="hidden md:block p-4 border-b dark:border-gray-700">
                    <h1 className="text-xl font-bold text-gray-800 dark:text-gray-100 uppercase tracking-tighter">Gestão BI</h1>
                    <span className="text-[10px] font-black text-theme-primary">USENATURAL v2.0</span>
                </div>
                <nav className="flex-grow md:p-2">
                    <ul className="flex flex-col md:p-0 gap-1">
                        {menuModules.map(module => {
                            const isExpanded = expandedSections.has(module.id);
                            return (
                                <li key={module.id} className="flex flex-col">
                                    <button onClick={() => toggleSection(module.id)} className="flex items-center justify-between w-full gap-3 px-4 py-2 rounded-md text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-theme-primary transition-all">
                                        <div className="flex items-center gap-3"><module.icon className="w-4 h-4" /><span>{module.label}</span></div>
                                        {isExpanded ? <ChevronUp size={12} /> : <ChevronDown size={12} />}
                                    </button>
                                    <ul className={`flex flex-col gap-1 pl-6 mt-1 mb-2 ${!isExpanded ? 'hidden' : ''}`}>
                                        {module.items.map(item => (
                                            <li key={item.id}>
                                                <a href="#" onClick={(e) => { e.preventDefault(); setCurrentErpView({ type: 'module', id: item.id }); }} 
                                                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${activeModule === item.id ? 'bg-theme-primary text-white' : 'text-gray-500 hover:bg-gray-50 dark:hover:bg-gray-700 dark:text-gray-400'}`}>
                                                    <span>{item.label}</span>
                                                </a>
                                            </li>
                                        ))}
                                    </ul>
                                </li>
                            );
                        })}
                    </ul>
                </nav>
            </aside>
            <main className="flex-1 flex flex-col overflow-hidden order-2 h-full">
                <header className="bg-white dark:bg-gray-800 shadow-sm p-4 flex items-center gap-4 shrink-0">
                    {backAction && <Button variant="secondary" onClick={backAction} className="!py-2 !px-3"><ArrowLeft size={16} className="mr-2"/> Voltar</Button>}
                    <h2 className="text-xl md:text-2xl font-black text-gray-800 dark:text-gray-100 capitalize truncate tracking-tight">{title}</h2>
                </header>
                <div className="flex-1 overflow-y-auto p-4 md:p-6">{renderActiveModule()}</div>
            </main>
        </div>
    );
};

export default ERPScreen;

import React, { useState, useEffect, useCallback } from 'react';
import { db } from '../../services/databaseService';
import type { DeliveryZone } from '../../types';
import Button from '../shared/Button';
import { PlusCircle, Edit, Trash2, MapPin, DollarSign } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

const DeliveryZones: React.FC = () => {
    const [zones, setZones] = useState<DeliveryZone[]>([]);
    const [editingZone, setEditingZone] = useState<Partial<DeliveryZone> | null>(null);

    const fetchZones = useCallback(async () => {
        const allZones = await db.getAll('deliveryZones');
        setZones(allZones.sort((a, b) => a.neighborhood.localeCompare(b.neighborhood)));
    }, []);

    useEffect(() => {
        fetchZones();
    }, [fetchZones]);

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!editingZone?.neighborhood || editingZone.fee === undefined) return;

        const zoneData: DeliveryZone = {
            id: editingZone.id || uuidv4(),
            neighborhood: editingZone.neighborhood.toUpperCase(),
            fee: editingZone.fee
        };

        await db.put('deliveryZones', zoneData);
        setEditingZone(null);
        fetchZones();
    };

    const handleDelete = async (id: string) => {
        if (confirm('Deseja realmente excluir esta taxa de frete?')) {
            await db.delete('deliveryZones', id);
            fetchZones();
        }
    };

    const formatCurrency = (v: number) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

    return (
        <div className="space-y-6 max-w-4xl mx-auto">
            <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                <div className="flex justify-between items-center mb-6">
                    <div>
                        <h2 className="text-xl font-black text-gray-800 dark:text-gray-100 uppercase tracking-tight">Taxas de Entrega</h2>
                        <p className="text-xs text-gray-500 font-bold uppercase tracking-widest mt-1">Gerencie valores de frete por bairro</p>
                    </div>
                    {!editingZone && (
                        <Button onClick={() => setEditingZone({ neighborhood: '', fee: 0 })}>
                            <PlusCircle size={18}/> Novo Bairro
                        </Button>
                    )}
                </div>

                {editingZone && (
                    <form onSubmit={handleSave} className="mb-8 p-4 bg-gray-50 dark:bg-gray-900/50 rounded-xl border border-dashed border-theme-primary/30 animate-in fade-in zoom-in-95">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Nome do Bairro</label>
                                <input 
                                    type="text" 
                                    value={editingZone.neighborhood}
                                    onChange={e => setEditingZone({...editingZone, neighborhood: e.target.value})}
                                    className="w-full p-2 border rounded-lg dark:bg-gray-800 dark:border-gray-700"
                                    required
                                    autoFocus
                                />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Valor do Frete (R$)</label>
                                <input 
                                    type="number" 
                                    step="0.01"
                                    value={editingZone.fee}
                                    onChange={e => setEditingZone({...editingZone, fee: parseFloat(e.target.value)})}
                                    className="w-full p-2 border rounded-lg dark:bg-gray-800 dark:border-gray-700 font-mono"
                                    required
                                />
                            </div>
                            <div className="flex items-end gap-2">
                                <Button type="submit" variant="primary" className="flex-1">Salvar</Button>
                                <Button type="button" variant="secondary" onClick={() => setEditingZone(null)}>Cancelar</Button>
                            </div>
                        </div>
                    </form>
                )}

                <div className="overflow-hidden border border-gray-100 dark:border-gray-700 rounded-xl">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-50 dark:bg-gray-900/80 text-[10px] uppercase font-black text-gray-400">
                            <tr>
                                <th className="px-6 py-4">Bairro / Região</th>
                                <th className="px-6 py-4 text-right">Taxa de Frete</th>
                                <th className="px-6 py-4 text-center">Ações</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                            {zones.map(zone => (
                                <tr key={zone.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors">
                                    <td className="px-6 py-4 font-bold text-gray-700 dark:text-gray-200 uppercase flex items-center gap-2">
                                        <MapPin size={14} className="text-theme-primary" />
                                        {zone.neighborhood}
                                    </td>
                                    <td className="px-6 py-4 text-right font-mono font-black text-theme-primary">
                                        {formatCurrency(zone.fee)}
                                    </td>
                                    <td className="px-6 py-4 text-center">
                                        <div className="flex justify-center gap-2">
                                            <Button variant="secondary" className="!p-2 h-auto" onClick={() => setEditingZone(zone)}>
                                                <Edit size={14}/>
                                            </Button>
                                            <Button variant="danger" className="!p-2 h-auto" onClick={() => handleDelete(zone.id)}>
                                                <Trash2 size={14}/>
                                            </Button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                            {zones.length === 0 && (
                                <tr>
                                    <td colSpan={3} className="p-12 text-center text-gray-400 font-bold uppercase text-xs tracking-widest">
                                        Nenhum bairro cadastrado
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

