                        {/* SEÇÃO DE IMAGEM */}
                        <div className="md:col-span-1 space-y-2">
                            <label className="block text-sm font-medium">Imagem do Produto</label>
                            <div 
                                onClick={() => fileInputRef.current?.click()}
                                className="relative group cursor-pointer border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl aspect-video flex flex-col items-center justify-center bg-gray-50 dark:bg-gray-900 overflow-hidden hover:border-theme-primary transition-all"
                            >
                                {formData.image && !imageError ? (
                                    <>
                                        <img src={formData.image} alt="Preview" className="w-full h-full object-contain" onError={() => setImageError(true)}/>
                                        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
