                        <Save size={16} className="mr-2"/>Salvar Produto
                    </Button>
                </div>
            </form>
        </div>
    );
};

export default ProductFormPage;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { db } from '../../services/databaseService';
import type { Product, Category, Supplier, InventoryLot } from '../../types';
import Button from '../shared/Button';
import { ImageOff, ReceiptText, Save, History, TrendingUp, TrendingDown, Minus, Upload, X, ImageIcon, Calendar, Boxes } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface ProductFormPageProps {
  productId?: string;
  categories: Category[];
  onBack: () => void;
}

const ProductFormPage: React.FC<ProductFormPageProps> = ({ productId, categories, onBack }) => {
    const [formData, setFormData] = useState<Partial<Product>>({});
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [purchaseHistory, setPurchaseHistory] = useState<InventoryLot[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [imageError, setImageError] = useState(false);
    const [activeTab, setActiveTab] = useState('main');

    // Estados para lote inicial (apenas na criação)
    const [initialLot, setInitialLot] = useState({
        number: 'LOTE-' + new Date().getFullYear() + '-' + Math.floor(Math.random() * 1000),
        expirationDate: '',
        initialStock: 0
    });

    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            const allSuppliers = await db.getAll('suppliers');
            setSuppliers(allSuppliers.sort((a,b) => a.name.localeCompare(b.name)));

            if (productId) {
                const [product, lots] = await Promise.all([
                    db.get('products', productId),
                    db.getAllFromIndex('inventoryLots', 'productId', productId)
                ]);

                if (product) {
                    setFormData(product);
                    setPurchaseHistory(lots.sort((a, b) => b.entryDate.getTime() - a.entryDate.getTime()));
                } else {
                    onBack();
                }
            } else {
                setFormData({
                    id: uuidv4(),
                    name: '',
                    price: 0,
                    costPrice: 0,
                    stock: 0,
                    minStock: 0,
                    isBulk: false,
                    scaleCode: '',
                    ncm: '',
                    cfop: '5102',
                    origin: '0',
                    csosn_cst: '102',
                    image: '',
                    categoryId: '',
                    supplierId: '',
                });
            }
            setIsLoading(false);
        };
        fetchData();
    }, [productId, onBack]);

    const supplierMap = useMemo(() => new Map(suppliers.map(s => [s.id, s.name])), [suppliers]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;
        if (type === 'checkbox') {
            const { checked } = e.target as HTMLInputElement;
            setFormData(prev => ({ ...prev, [name]: checked }));
        } else {
             setFormData(prev => ({ ...prev, [name]: type === 'number' ? parseFloat(value) : value }));
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name || !formData.id || formData.price === undefined || formData.price < 0) {
            alert('Preencha os campos obrigatórios.');
            return;
        }

        const tx = db.transaction(['products', 'inventoryLots'], 'readwrite');
        const productStore = tx.objectStore('products');
        const lotStore = tx.objectStore('inventoryLots');

        // Se for novo produto, aplica o estoque do lote inicial
        const finalProduct = { ...formData } as Product;
        if (!productId) {
            finalProduct.stock = initialLot.initialStock;
        }

        await productStore.put(finalProduct);

        // Se for novo produto, cria o primeiro lote
        if (!productId && initialLot.initialStock > 0) {
            await lotStore.put({
                id: uuidv4(),
                productId: finalProduct.id,
                supplierId: finalProduct.supplierId,
                quantity: initialLot.initialStock,
                entryDate: new Date(),
                expirationDate: initialLot.expirationDate ? new Date(initialLot.expirationDate + 'T12:00:00') : undefined,
                costPrice: finalProduct.costPrice || 0,
                lotNumber: initialLot.number // Note: adicionado lotNumber se desejar no futuro, mas o types.ts usa ID
            } as any);
        }

        await tx.done;
        onBack();
    };

    const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

    if (isLoading) return <div className="text-center p-8">Carregando...</div>;

    const inputStyle = "mt-1 block w-full rounded-md border border-gray-300 py-2 px-3 shadow-sm focus:border-theme-primary focus:ring-theme-primary dark:border-gray-600 dark:bg-gray-700";

    return (
         <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow">
            <div className="border-b border-gray-200 dark:border-gray-700 mb-6">
                <nav className="-mb-px flex space-x-2 overflow-x-auto">
                    <button onClick={() => setActiveTab('main')} className={`px-4 py-2 text-sm font-medium border-b-2 ${activeTab === 'main' ? 'border-theme-primary text-theme-primary' : 'border-transparent text-gray-500'}`}>Dados Principais</button>
                    {!productId && <button onClick={() => setActiveTab('inventory')} className={`px-4 py-2 text-sm font-medium border-b-2 ${activeTab === 'inventory' ? 'border-theme-primary text-theme-primary' : 'border-transparent text-gray-500'}`}>Lote e Validade Inicial</button>}
                    <button onClick={() => setActiveTab('tax')} className={`px-4 py-2 text-sm font-medium border-b-2 ${activeTab === 'tax' ? 'border-theme-primary text-theme-primary' : 'border-transparent text-gray-500'}`}>Tributação</button>
                    {productId && <button onClick={() => setActiveTab('history')} className={`px-4 py-2 text-sm font-medium border-b-2 ${activeTab === 'history' ? 'border-theme-primary text-theme-primary' : 'border-transparent text-gray-500'}`}>Histórico</button>}
                </nav>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
                {activeTab === 'main' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium">Nome do Produto</label>
                                <input type="text" name="name" value={formData.name} onChange={handleChange} required className={inputStyle}/>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium">Preço Venda</label>
                                    <input type="number" name="price" value={formData.price} onChange={handleChange} required step="0.01" className={inputStyle}/>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium">Preço Custo</label>
                                    <input type="number" name="costPrice" value={formData.costPrice} onChange={handleChange} step="0.01" className={inputStyle}/>
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium">Categoria</label>
                                <select name="categoryId" value={formData.categoryId || ''} onChange={handleChange} className={inputStyle}>
                                    <option value="">Selecione...</option>
                                    {categories.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
                                </select>
                            </div>
                        </div>
                        <div className="bg-gray-50 dark:bg-gray-900/50 p-4 rounded-xl border border-dashed border-gray-300 dark:border-gray-700 flex flex-col items-center justify-center">
                             {formData.image ? <img src={formData.image} className="h-32 object-contain mb-2"/> : <ImageIcon size={48} className="text-gray-300 mb-2"/>}
                             <p className="text-[10px] uppercase font-bold text-gray-400">Imagem do Produto</p>
                        </div>
                    </div>
                )}

                {activeTab === 'inventory' && !productId && (
                    <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                        <div className="p-4 bg-blue-50 dark:bg-blue-900/20 border-l-4 border-blue-500 text-blue-800 dark:text-blue-200 text-sm mb-4">
                            Defina o lote e a validade inicial para este produto. Outros lotes podem ser adicionados via Importação de NF-e ou Inventário.
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div>
                                <label className="block text-sm font-medium flex items-center gap-2"><Boxes size={14}/> Identificação do Lote</label>
                                <input type="text" value={initialLot.number} onChange={e => setInitialLot({...initialLot, number: e.target.value})} className={inputStyle}/>
                            </div>
                            <div>
                                <label className="block text-sm font-medium flex items-center gap-2"><Calendar size={14}/> Data de Validade</label>
                                <input type="date" value={initialLot.expirationDate} onChange={e => setInitialLot({...initialLot, expirationDate: e.target.value})} className={inputStyle}/>
                            </div>
                            <div>
                                <label className="block text-sm font-medium">Estoque Inicial</label>
                                <input type="number" value={initialLot.initialStock} onChange={e => setInitialLot({...initialLot, initialStock: parseFloat(e.target.value) || 0})} className={inputStyle}/>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'tax' && (
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <div><label className="block text-sm font-medium">NCM</label><input type="text" name="ncm" value={formData.ncm || ''} onChange={handleChange} className={inputStyle}/></div>
                        <div><label className="block text-sm font-medium">CFOP</label><input type="text" name="cfop" value={formData.cfop || ''} onChange={handleChange} className={inputStyle}/></div>
                        <div><label className="block text-sm font-medium">CST</label><input type="text" name="csosn_cst" value={formData.csosn_cst || ''} onChange={handleChange} className={inputStyle}/></div>
                    </div>
                )}

                <div className="flex justify-end gap-2 pt-6 border-t dark:border-gray-700">
                    <Button type="button" variant="secondary" onClick={onBack}>Cancelar</Button>
                    <Button type="submit" variant="primary"><Save size={16} className="mr-2"/>Salvar Produto</Button>
                </div>
            </form>
        </div>
    );
};

export default ProductFormPage;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { db } from '../../services/databaseService';
import type { Product, InventoryLot, InventoryAdjustment } from '../../types';
import Button from '../shared/Button';
import Modal from '../shared/Modal';
import AdjustmentHistoryModal from './AdjustmentHistoryModal';
import { ChevronDown, ChevronUp, History, Filter, Calendar, AlertTriangle, Search } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

const InventoryReport: React.FC = () => {
    const [products, setProducts] = useState<Product[]>([]);
    const [lots, setLots] = useState<InventoryLot[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [validityFilter, setValidityFilter] = useState<'ALL' | 'EXPIRED' | 'CRITICAL' | '30DAYS'>('ALL');
    const [expandedProducts, setExpandedProducts] = useState<Set<string>>(new Set());
    const [historyProductId, setHistoryProductId] = useState<string | null>(null);

    const fetchData = useCallback(async () => {
        const [allProducts, allLots] = await Promise.all([
            db.getAll('products'),
            db.getAll('inventoryLots')
        ]);
        setProducts(allProducts);
        setLots(allLots);
    }, []);

    useEffect(() => { fetchData(); }, [fetchData]);

    const getLotStatus = (lot: InventoryLot) => {
        if (!lot.expirationDate) return { type: 'OK', label: 'Sem validade' };
        const today = new Date(); today.setHours(0,0,0,0);
        const exp = new Date(lot.expirationDate); exp.setHours(0,0,0,0);
        const diff = Math.ceil((exp.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

        if (diff < 0) return { type: 'EXPIRED', label: `Vencido há ${Math.abs(diff)} dias`, color: 'text-red-600 bg-red-50' };
        if (diff <= 7) return { type: 'CRITICAL', label: `Vence em ${diff} dias!`, color: 'text-orange-600 bg-orange-50' };
        if (diff <= 30) return { type: 'WARNING', label: `Vence em ${diff} dias`, color: 'text-yellow-600 bg-yellow-50' };
        return { type: 'OK', label: `Vencimento: ${exp.toLocaleDateString('pt-BR')}` };
    };

    const filteredData = useMemo(() => {
        const today = new Date(); today.setHours(0,0,0,0);

        // Primeiro, filtra os lotes de acordo com a regra de validade
        const matchingLots = lots.filter(lot => {
            if (validityFilter === 'ALL') return true;
            if (!lot.expirationDate) return false;
            const exp = new Date(lot.expirationDate); exp.setHours(0,0,0,0);
            const diff = (exp.getTime() - today.getTime()) / (1000 * 60 * 60 * 24);

            if (validityFilter === 'EXPIRED') return diff < 0;
            if (validityFilter === 'CRITICAL') return diff >= 0 && diff <= 7;
            if (validityFilter === '30DAYS') return diff >= 0 && diff <= 30;
            return true;
        });

        const productIdsWithMatchingLots = new Set(matchingLots.map(l => l.productId));

        // Filtra os produtos que possuem os lotes que sobraram e batem com a busca de nome
        return products.filter(p => {
            const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.id.includes(searchTerm);
            const matchesValidity = productIdsWithMatchingLots.has(p.id) || (validityFilter === 'ALL');
            return matchesSearch && matchesValidity;
        });
    }, [products, lots, searchTerm, validityFilter]);

    const productLotsMap = useMemo(() => {
        const map = new Map<string, InventoryLot[]>();
        lots.forEach(lot => {
            const list = map.get(lot.productId) || [];
            list.push(lot);
            map.set(lot.productId, list);
        });
        return map;
    }, [lots]);

    const toggleProduct = (id: string) => {
        setExpandedProducts(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            return next;
        });
    };

    return (
        <div className="space-y-6">
            <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
                    <h2 className="text-xl font-black text-gray-800 dark:text-gray-100 uppercase tracking-tight flex items-center gap-2">
                        <Calendar className="text-theme-primary" /> Controle de Validades
                    </h2>
                    <div className="relative w-full md:w-80">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                        <input type="text" placeholder="Buscar produto..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 rounded-xl border dark:bg-gray-900 dark:border-gray-700"/>
                    </div>
                </div>

                <div className="flex flex-wrap gap-2 mb-6">
                    <button onClick={() => setValidityFilter('ALL')} className={`px-4 py-2 rounded-full text-xs font-black uppercase transition-all ${validityFilter === 'ALL' ? 'bg-gray-800 text-white' : 'bg-gray-100 text-gray-500'}`}>Todos</button>
                    <button onClick={() => setValidityFilter('EXPIRED')} className={`px-4 py-2 rounded-full text-xs font-black uppercase transition-all ${validityFilter === 'EXPIRED' ? 'bg-red-600 text-white' : 'bg-red-50 text-red-600'}`}>Vencidos</button>
                    <button onClick={() => setValidityFilter('CRITICAL')} className={`px-4 py-2 rounded-full text-xs font-black uppercase transition-all ${validityFilter === 'CRITICAL' ? 'bg-orange-500 text-white' : 'bg-orange-50 text-orange-600'}`}>Vencendo em 7 dias</button>
                    <button onClick={() => setValidityFilter('30DAYS')} className={`px-4 py-2 rounded-full text-xs font-black uppercase transition-all ${validityFilter === '30DAYS' ? 'bg-yellow-500 text-white' : 'bg-yellow-50 text-yellow-600'}`}>Vencendo em 30 dias</button>
                </div>

                <div className="overflow-hidden border border-gray-100 dark:border-gray-700 rounded-xl">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-50 dark:bg-gray-900/80 text-[10px] uppercase font-black text-gray-400">
                            <tr>
                                <th className="px-6 py-4 w-12"></th>
                                <th className="px-6 py-4">Produto</th>
                                <th className="px-6 py-4 text-right">Estoque Global</th>
                                <th className="px-6 py-4 text-center">Alertas</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                            {filteredData.map(product => {
                                const prodLots = productLotsMap.get(product.id) || [];
                                const hasAlert = prodLots.some(l => {
                                    const s = getLotStatus(l);
                                    return s.type === 'EXPIRED' || s.type === 'CRITICAL';
                                });

                                return (
                                    <React.Fragment key={product.id}>
                                        <tr className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors">
                                            <td className="px-6 py-4 cursor-pointer" onClick={() => toggleProduct(product.id)}>
                                                {expandedProducts.has(product.id) ? <ChevronUp size={16}/> : <ChevronDown size={16}/>}
                                            </td>
                                            <td className="px-6 py-4 font-bold text-gray-700 dark:text-gray-200">{product.name}</td>
                                            <td className="px-6 py-4 text-right font-mono font-bold text-theme-primary">{product.stock} {product.isBulk ? 'kg' : 'un'}</td>
                                            <td className="px-6 py-4 text-center">
                                                {hasAlert && <AlertTriangle size={18} className="text-red-500 inline animate-pulse" />}
                                            </td>
                                        </tr>
                                        {expandedProducts.has(product.id) && (
                                            <tr className="bg-gray-50/50 dark:bg-gray-900/30">
                                                <td colSpan={4} className="px-12 py-4">
                                                    <div className="space-y-2">
                                                        <p className="text-[10px] font-black text-gray-400 uppercase mb-2">Lotes em Estoque</p>
                                                        {prodLots.map(lot => {
                                                            const status = getLotStatus(lot);
                                                            return (
                                                                <div key={lot.id} className={`flex justify-between items-center p-3 rounded-xl border ${status.color || 'bg-white dark:bg-gray-800'}`}>
                                                                    <div>
                                                                        <p className="text-xs font-bold uppercase">{status.label}</p>
                                                                        <p className="text-[10px] text-gray-500">Quantidade: {lot.quantity}</p>
                                                                    </div>
                                                                    <Button variant="secondary" size="sm" onClick={() => setHistoryProductId(product.id)}><History size={12}/></Button>
                                                                </div>
                                                            );
                                                        })}
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </React.Fragment>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>

            {historyProductId && (
                <AdjustmentHistoryModal isOpen={!!historyProductId} onClose={() => setHistoryProductId(null)} productId={historyProductId} />
            )}
        </div>
    );
};

export default InventoryReport;

import React, { useState, useEffect } from 'react';
import { db } from '../../services/databaseService';
import { AlertTriangle, X, ArrowRight } from 'lucide-react';

const ValidityAlertBanner: React.FC<{ onAction: () => void }> = ({ onAction }) => {
    const [criticalCount, setCriticalCount] = useState(0);
    const [visible, setVisible] = useState(false);

    useEffect(() => {
        const checkValidades = async () => {
            const lots = await db.getAll('inventoryLots');
            const today = new Date(); today.setHours(0,0,0,0);

            const count = lots.filter(lot => {
                if (!lot.expirationDate) return false;
                const exp = new Date(lot.expirationDate);
                const diff = (exp.getTime() - today.getTime()) / (1000 * 60 * 60 * 24);
                return diff <= 7; // Vencidos ou vencendo em 7 dias
            }).length;

            if (count > 0) {
                setCriticalCount(count);
                setVisible(true);
            }
        };
        checkValidades();
    }, []);

    if (!visible) return null;

    return (
        <div className="bg-red-600 text-white p-4 rounded-2xl shadow-xl flex items-center justify-between mb-6 animate-in slide-in-from-top-4 duration-500">
            <div className="flex items-center gap-4">
                <div className="bg-white/20 p-2 rounded-full">
                    <AlertTriangle size={24} className="animate-pulse" />
                </div>
                <div>
                    <h3 className="font-black uppercase text-sm tracking-tight">Alerta de Validade Crítica</h3>
                    <p className="text-xs text-red-100 font-bold uppercase">Existem {criticalCount} lotes de produtos vencidos ou próximos do vencimento!</p>
                </div>
            </div>
            <div className="flex items-center gap-3">
                <button 
                    onClick={onAction}
                    className="bg-white text-red-600 px-4 py-2 rounded-xl text-xs font-black uppercase flex items-center gap-2 hover:bg-gray-100 transition-colors"
                >
                    Ver Detalhes <ArrowRight size={14} />
                </button>
                <button onClick={() => setVisible(false)} className="p-2 hover:bg-white/10 rounded-full">
                    <X size={18} />
                </button>
            </div>
        </div>
    );
};

