import React, { useState, useEffect, useMemo, useRef } from 'react';
import { db } from '../../services/databaseService';
import type { Product, Category, Supplier, InventoryLot } from '../../types';
import Button from '../shared/Button';
import { ImageOff, ReceiptText, Save, History, TrendingUp, TrendingDown, Minus, Upload, X, ImageIcon, Calendar, Boxes, Tag } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface ProductFormPageProps {
  productId?: string;
  categories: Category[];
  onBack: () => void;
}

const ProductFormPage: React.FC<ProductFormPageProps> = ({ productId, categories, onBack }) => {
    const [formData, setFormData] = useState<Partial<Product>>({});
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('main');

    // Estados para lote inicial (apenas na criação)
    const [initialLot, setInitialLot] = useState({
        number: 'LOTE-' + new Date().getFullYear() + '-' + Math.floor(Math.random() * 1000),
        expirationDate: '',
        initialStock: 0,
        costPrice: 0
    });

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            const allSuppliers = await db.getAll('suppliers');
            setSuppliers(allSuppliers.sort((a,b) => a.name.localeCompare(b.name)));

            if (productId) {
                const product = await db.get('products', productId);
                if (product) {
                    setFormData(product);
                } else {
                    onBack();
                }
            } else {
                setFormData({
                    id: uuidv4(),
                    name: '',
                    brand: '',
                    price: 0,
                    costPrice: 0,
                    stock: 0,
                    minStock: 0,
                    isBulk: false,
                    scaleCode: '',
                    ncm: '',
                    cfop: '5102',
                    origin: '0',
                    csosn_cst: '102',
                    image: '',
                    categoryId: '',
                    supplierId: '',
                });
            }
            setIsLoading(false);
        };
        fetchData();
    }, [productId, onBack]);

    const formatCurrencyInput = (value: string) => {
        const digits = value.replace(/\D/g, '');
        const numberValue = parseInt(digits || '0', 10) / 100;
        return numberValue.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;
        if (type === 'checkbox') {
            const { checked } = e.target as HTMLInputElement;
            setFormData(prev => ({ ...prev, [name]: checked }));
        } else if (name === 'price' || name === 'costPrice') {
            const formatted = formatCurrencyInput(value);
            const numericValue = parseFloat(formatted.replace(/\./g, '').replace(',', '.'));
            setFormData(prev => ({ ...prev, [name]: numericValue }));
        } else {
             setFormData(prev => ({ ...prev, [name]: type === 'number' ? parseFloat(value) : value }));
        }
    };

    const handleInitialLotChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        if (name === 'costPrice') {
            const formatted = formatCurrencyInput(value);
            const numericValue = parseFloat(formatted.replace(/\./g, '').replace(',', '.'));
            setInitialLot(prev => ({ ...prev, [name]: numericValue }));
        } else {
            setInitialLot(prev => ({ ...prev, [name]: name === 'initialStock' ? parseFloat(value) || 0 : value }));
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name || !formData.id || formData.price === undefined || formData.price < 0) {
            alert('Preencha os campos obrigatórios.');
            return;
        }

        const tx = db.transaction(['products', 'inventoryLots'], 'readwrite');
        const productStore = tx.objectStore('products');
        const lotStore = tx.objectStore('inventoryLots');

        const finalProduct = { ...formData } as Product;
        if (!productId) {
            finalProduct.stock = initialLot.initialStock;
        }

        await productStore.put(finalProduct);

        if (!productId && initialLot.initialStock > 0) {
            await lotStore.put({
                id: uuidv4(),
                productId: finalProduct.id,
                supplierId: finalProduct.supplierId,
                quantity: initialLot.initialStock,
                entryDate: new Date(),
                expirationDate: initialLot.expirationDate ? new Date(initialLot.expirationDate + 'T12:00:00') : undefined,
                costPrice: initialLot.costPrice || finalProduct.costPrice || 0,
            });
        }

        await tx.done;
        onBack();
    };

    if (isLoading) return <div className="text-center p-8">Carregando...</div>;

    const inputStyle = "mt-1 block w-full rounded-md border border-gray-300 py-2 px-3 shadow-sm focus:border-theme-primary focus:ring-theme-primary dark:border-gray-600 dark:bg-gray-700 transition-all";

    return (
         <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow">
            <div className="border-b border-gray-200 dark:border-gray-700 mb-6">
                <nav className="-mb-px flex space-x-2 overflow-x-auto">
                    <button onClick={() => setActiveTab('main')} className={`px-4 py-2 text-sm font-medium border-b-2 ${activeTab === 'main' ? 'border-theme-primary text-theme-primary' : 'border-transparent text-gray-500'}`}>Dados Principais</button>
                    {!productId && <button onClick={() => setActiveTab('inventory')} className={`px-4 py-2 text-sm font-medium border-b-2 ${activeTab === 'inventory' ? 'border-theme-primary text-theme-primary' : 'border-transparent text-gray-500'}`}>Lote e Validade Inicial</button>}
                    <button onClick={() => setActiveTab('tax')} className={`px-4 py-2 text-sm font-medium border-b-2 ${activeTab === 'tax' ? 'border-theme-primary text-theme-primary' : 'border-transparent text-gray-500'}`}>Tributação</button>
                </nav>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
                {activeTab === 'main' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium">Nome do Produto</label>
                                <input type="text" name="name" value={formData.name} onChange={handleChange} required className={inputStyle}/>
                            </div>
                            <div>
                                <label className="block text-sm font-medium flex items-center gap-1"><Tag size={14}/> Marca / Fabricante</label>
                                <input type="text" name="brand" value={formData.brand || ''} onChange={handleChange} placeholder="Ex: Nestlé, Integralmédica..." className={inputStyle}/>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium">Preço Venda (R$)</label>
                                    <input 
                                        type="text" 
                                        name="price" 
                                        value={formData.price?.toLocaleString('pt-BR', { minimumFractionDigits: 2 })} 
                                        onChange={handleChange} 
                                        required 
                                        className={inputStyle + " font-mono text-theme-primary font-bold"}
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium">Preço Custo (R$)</label>
                                    <input 
                                        type="text" 
                                        name="costPrice" 
                                        value={formData.costPrice?.toLocaleString('pt-BR', { minimumFractionDigits: 2 })} 
                                        onChange={handleChange} 
                                        className={inputStyle + " font-mono"}
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium">Categoria</label>
                                <select name="categoryId" value={formData.categoryId || ''} onChange={handleChange} className={inputStyle}>
                                    <option value="">Selecione...</option>
                                    {categories.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
                                </select>
                            </div>
                        </div>
                        <div className="bg-gray-50 dark:bg-gray-900/50 p-4 rounded-xl border border-dashed border-gray-300 dark:border-gray-700 flex flex-col items-center justify-center">
                             {formData.image ? <img src={formData.image} className="h-32 object-contain mb-2"/> : <ImageIcon size={48} className="text-gray-300 mb-2"/>}
                             <p className="text-[10px] uppercase font-bold text-gray-400">Imagem do Produto</p>
                        </div>
                    </div>
                )}

                {activeTab === 'inventory' && !productId && (
                    <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                        <div className="p-4 bg-blue-50 dark:bg-blue-900/20 border-l-4 border-blue-500 text-blue-800 dark:text-blue-200 text-sm mb-4">
                            Defina o lote e a validade inicial para este produto.
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium flex items-center gap-2"><Boxes size={14}/> Identificação do Lote</label>
                                <input type="text" name="number" value={initialLot.number} onChange={handleInitialLotChange} className={inputStyle}/>
                            </div>
                            <div>
                                <label className="block text-sm font-medium flex items-center gap-2"><Calendar size={14}/> Data de Validade</label>
                                <input type="date" name="expirationDate" value={initialLot.expirationDate} onChange={handleInitialLotChange} className={inputStyle}/>
                            </div>
                            <div>
                                <label className="block text-sm font-medium">Estoque Inicial (Qtd)</label>
                                <input type="number" name="initialStock" value={initialLot.initialStock} onChange={handleInitialLotChange} className={inputStyle}/>
                            </div>
                            <div>
                                <label className="block text-sm font-medium">Preço de Custo do Lote (R$)</label>
                                <input 
                                    type="text" 
                                    name="costPrice" 
                                    value={initialLot.costPrice.toLocaleString('pt-BR', { minimumFractionDigits: 2 })} 
                                    onChange={handleInitialLotChange} 
                                    className={inputStyle + " font-mono"}
                                />
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'tax' && (
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <div><label className="block text-sm font-medium">NCM</label><input type="text" name="ncm" value={formData.ncm || ''} onChange={handleChange} className={inputStyle}/></div>
                        <div><label className="block text-sm font-medium">CFOP</label><input type="text" name="cfop" value={formData.cfop || ''} onChange={handleChange} className={inputStyle}/></div>
                        <div><label className="block text-sm font-medium">CST</label><input type="text" name="csosn_cst" value={formData.csosn_cst || ''} onChange={handleChange} className={inputStyle}/></div>
                    </div>
                )}

                <div className="flex justify-end gap-2 pt-6 border-t dark:border-gray-700">
                    <Button type="button" variant="secondary" onClick={onBack}>Cancelar</Button>
                    <Button type="submit" variant="primary"><Save size={16} className="mr-2"/>Salvar Produto</Button>
                </div>
            </form>
        </div>
    );
};

export default ProductFormPage;

