import React, { useState, useEffect, useMemo, useRef } from 'react';
import { db } from '../../services/databaseService';
import type { Product, Category, Supplier, InventoryLot } from '../../types';
import Button from '../shared/Button';
import { ImageOff, ReceiptText, Save, History, TrendingUp, TrendingDown, Minus, Upload, X, ImageIcon, Calendar, Boxes, Tag } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface ProductFormPageProps {
  productId?: string;
  categories: Category[];
  onBack: () => void;
}

const ProductFormPage: React.FC<ProductFormPageProps> = ({ productId, categories, onBack }) => {
    const [formData, setFormData] = useState<Partial<Product>>({});
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('main');

    // Estados para lote inicial (apenas na criação)
    const [initialLot, setInitialLot] = useState({
        number: 'LOTE-' + new Date().getFullYear() + '-' + Math.floor(Math.random() * 1000),
        expirationDate: '',
        initialStock: 0,
        costPrice: 0
    });

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            const allSuppliers = await db.getAll('suppliers');
            setSuppliers(allSuppliers.sort((a,b) => a.name.localeCompare(b.name)));

            if (productId) {
                const product = await db.get('products', productId);
                if (product) {
                    setFormData(product);
                } else {
                    onBack();
                }
            } else {
                setFormData({
                    id: uuidv4(),
                    name: '',
                    brand: '',
                    price: 0,
                    costPrice: 0,
                    stock: 0,
                    minStock: 0,
                    isBulk: false,
                    scaleCode: '',
                    ncm: '',
                    cfop: '5102',
                    origin: '0',
                    csosn_cst: '102',
                    image: '',
                    categoryId: '',
                    supplierId: '',
                });
            }
            setIsLoading(false);
        };
        fetchData();
    }, [productId, onBack]);

    // Máscara Financeira (0,00)
    const formatCurrencyInput = (value: string) => {
        const digits = value.replace(/\D/g, '');
        const numberValue = parseInt(digits || '0', 10) / 100;
        return numberValue.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;
        if (type === 'checkbox') {
            const { checked } = e.target as HTMLInputElement;
            setFormData(prev => ({ ...prev, [name]: checked }));
        } else if (name === 'price' || name === 'costPrice') {
            const formatted = formatCurrencyInput(value);
            const numericValue = parseFloat(formatted.replace(/\./g, '').replace(',', '.'));
            setFormData(prev => ({ ...prev, [name]: numericValue }));
        } else {
             setFormData(prev => ({ ...prev, [name]: type === 'number' ? parseFloat(value) : value }));
        }
    };

    const handleInitialLotChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        if (name === 'costPrice') {
            const formatted = formatCurrencyInput(value);
            const numericValue = parseFloat(formatted.replace(/\./g, '').replace(',', '.'));
            setInitialLot(prev => ({ ...prev, [name]: numericValue }));
        } else {
            setInitialLot(prev => ({ ...prev, [name]: name === 'initialStock' ? parseFloat(value) || 0 : value }));
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name || !formData.id || formData.price === undefined || formData.price < 0) {
            alert('Preencha os campos obrigatórios.');
            return;
        }

        const tx = db.transaction(['products', 'inventoryLots'], 'readwrite');
        const productStore = tx.objectStore('products');
        const lotStore = tx.objectStore('inventoryLots');

        const finalProduct = { ...formData } as Product;
        if (!productId) {
            finalProduct.stock = initialLot.initialStock;
        }

        await productStore.put(finalProduct);

        if (!productId && initialLot.initialStock > 0) {
            await lotStore.put({
                id: uuidv4(),
                productId: finalProduct.id,
                supplierId: finalProduct.supplierId,
                quantity: initialLot.initialStock,
                entryDate: new Date(),
                expirationDate: initialLot.expirationDate ? new Date(initialLot.expirationDate + 'T12:00:00') : undefined,
                costPrice: initialLot.costPrice || finalProduct.costPrice || 0,
            });
        }

        await tx.done;
        onBack();
    };

    if (isLoading) return <div className="text-center p-8 text-gray-500 font-bold uppercase text-xs animate-pulse">Carregando ficha...</div>;

    const inputStyle = "mt-1 block w-full rounded-xl border border-gray-300 py-3 px-4 shadow-sm focus:border-theme-primary focus:ring-2 focus:ring-theme-primary/20 dark:border-gray-600 dark:bg-gray-700 transition-all outline-none";

    return (
         <div className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-lg border border-gray-100 dark:border-gray-700">
            <div className="border-b border-gray-100 dark:border-gray-700 mb-8">
                <nav className="-mb-px flex space-x-6 overflow-x-auto pb-2">
                    <button onClick={() => setActiveTab('main')} className={`px-4 py-3 text-xs font-black uppercase tracking-widest border-b-2 transition-all ${activeTab === 'main' ? 'border-theme-primary text-theme-primary' : 'border-transparent text-gray-400'}`}>1. Dados Básicos</button>
                    {!productId && <button onClick={() => setActiveTab('inventory')} className={`px-4 py-3 text-xs font-black uppercase tracking-widest border-b-2 transition-all ${activeTab === 'inventory' ? 'border-theme-primary text-theme-primary' : 'border-transparent text-gray-400'}`}>2. Lote Inicial</button>}
                    <button onClick={() => setActiveTab('tax')} className={`px-4 py-3 text-xs font-black uppercase tracking-widest border-b-2 transition-all ${activeTab === 'tax' ? 'border-theme-primary text-theme-primary' : 'border-transparent text-gray-400'}`}>3. Fiscal/NFC-e</button>
                </nav>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
                {activeTab === 'main' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-5">
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1">Nome Comercial</label>
                                <input type="text" name="name" value={formData.name} onChange={handleChange} required className={inputStyle} placeholder="Ex: Whey Protein Isolado 900g"/>
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1 flex items-center gap-1"><Tag size={12}/> Marca / Fabricante</label>
                                <input type="text" name="brand" value={formData.brand || ''} onChange={handleChange} placeholder="Ex: Max Titanium, Dux, Nestlé..." className={inputStyle}/>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1">Preço Venda (R$)</label>
                                    <div className="relative">
                                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">R$</span>
                                        <input 
                                            type="text" 
                                            name="price" 
                                            value={formData.price?.toLocaleString('pt-BR', { minimumFractionDigits: 2 })} 
                                            onChange={handleChange} 
                                            required 
                                            className={inputStyle + " pl-10 font-mono text-theme-primary font-black text-lg"}
                                        />
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1">Preço Custo (R$)</label>
                                    <div className="relative">
                                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">R$</span>
                                        <input 
                                            type="text" 
                                            name="costPrice" 
                                            value={formData.costPrice?.toLocaleString('pt-BR', { minimumFractionDigits: 2 })} 
                                            onChange={handleChange} 
                                            className={inputStyle + " pl-10 font-mono"}
                                        />
                                    </div>
                                </div>
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1">Categoria</label>
                                <select name="categoryId" value={formData.categoryId || ''} onChange={handleChange} className={inputStyle}>
                                    <option value="">Selecione...</option>
                                    {categories.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
                                </select>
                            </div>
                        </div>
                        <div className="bg-gray-50 dark:bg-gray-900/50 p-8 rounded-3xl border-2 border-dashed border-gray-200 dark:border-gray-700 flex flex-col items-center justify-center text-center">
                             {formData.image ? <img src={formData.image} className="h-48 w-48 object-contain rounded-2xl mb-4 shadow-sm"/> : <ImageIcon size={64} className="text-gray-300 mb-4"/>}
                             <p className="text-[10px] uppercase font-black text-gray-400 tracking-widest">Visualização do Produto</p>
                        </div>
                    </div>
                )}

                {activeTab === 'inventory' && !productId && (
                    <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-300">
                        <div className="p-4 bg-theme-primary/10 border-l-4 border-theme-primary text-theme-primary rounded-r-xl">
                            <p className="text-xs font-bold uppercase tracking-tight flex items-center gap-2">
                                <Boxes size={16}/> Rastreabilidade de Estoque
                            </p>
                            <p className="text-[10px] font-medium mt-1">Ao cadastrar um novo item, você deve informar o lote inicial para controle de validade.</p>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1">Identificação do Lote</label>
                                <input type="text" name="number" value={initialLot.number} onChange={handleInitialLotChange} className={inputStyle}/>
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1">Data de Validade</label>
                                <input type="date" name="expirationDate" value={initialLot.expirationDate} onChange={handleInitialLotChange} className={inputStyle}/>
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1">Estoque Inicial (Qtd)</label>
                                <input type="number" name="initialStock" value={initialLot.initialStock} onChange={handleInitialLotChange} className={inputStyle} placeholder="0"/>
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1">Custo deste Lote (R$)</label>
                                <div className="relative">
                                    <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">R$</span>
                                    <input 
                                        type="text" 
                                        name="costPrice" 
