                            />
                        </div>
                        <p className="text-[9px] text-gray-400 mt-1 ml-1">* Alterar a quantidade aqui atualizará automaticamente o estoque global do produto.</p>
                    </div>
                </div>

                <div className="flex justify-end gap-2 pt-4 border-t dark:border-gray-700">
                    <Button type="button" variant="secondary" onClick={onClose}>Cancelar</Button>
                    <Button type="submit" variant="primary" disabled={isSaving}>
                        <Save size={16} className="mr-2"/>
                        {isSaving ? 'Salvando...' : 'Confirmar Alterações'}
                    </Button>
                </div>
            </form>
        </Modal>
    );
};

export default EditLotModal;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { db } from '../../services/databaseService';
import type { Product, InventoryLot, InventoryAdjustment } from '../../types';
import Button from '../shared/Button';
import Modal from '../shared/Modal';
import AdjustmentHistoryModal from './AdjustmentHistoryModal';
import EditLotModal from './EditLotModal';
import { ChevronDown, ChevronUp, History, Filter, Calendar, AlertTriangle, Search, Pencil } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

const InventoryReport: React.FC = () => {
    const [products, setProducts] = useState<Product[]>([]);
    const [lots, setLots] = useState<InventoryLot[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [validityFilter, setValidityFilter] = useState<'ALL' | 'EXPIRED' | 'CRITICAL' | '30DAYS'>('ALL');
    const [expandedProducts, setExpandedProducts] = useState<Set<string>>(new Set());
    const [historyProductId, setHistoryProductId] = useState<string | null>(null);
    const [editingLot, setEditingLot] = useState<InventoryLot | null>(null);

    const fetchData = useCallback(async () => {
        const [allProducts, allLots] = await Promise.all([
            db.getAll('products'),
            db.getAll('inventoryLots')
        ]);
        setProducts(allProducts);
        setLots(allLots);
    }, []);

    useEffect(() => { fetchData(); }, [fetchData]);

    const getLotStatus = (lot: InventoryLot) => {
        if (!lot.expirationDate) return { type: 'OK', label: 'Sem validade' };
        const today = new Date(); today.setHours(0,0,0,0);
        const exp = new Date(lot.expirationDate); exp.setHours(0,0,0,0);
        const diff = Math.ceil((exp.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

        if (diff < 0) return { type: 'EXPIRED', label: `Vencido há ${Math.abs(diff)} dias`, color: 'text-red-600 bg-red-50' };
        if (diff <= 7) return { type: 'CRITICAL', label: `Vence em ${diff} dias!`, color: 'text-orange-600 bg-orange-50' };
        if (diff <= 30) return { type: 'WARNING', label: `Vence em ${diff} dias`, color: 'text-yellow-600 bg-yellow-50' };
        return { type: 'OK', label: `Vencimento: ${exp.toLocaleDateString('pt-BR')}` };
    };

    const filteredData = useMemo(() => {
        const today = new Date(); today.setHours(0,0,0,0);

        const matchingLots = lots.filter(lot => {
            if (validityFilter === 'ALL') return true;
            if (!lot.expirationDate) return false;
            const exp = new Date(lot.expirationDate); exp.setHours(0,0,0,0);
            const diff = (exp.getTime() - today.getTime()) / (1000 * 60 * 60 * 24);

            if (validityFilter === 'EXPIRED') return diff < 0;
            if (validityFilter === 'CRITICAL') return diff >= 0 && diff <= 7;
            if (validityFilter === '30DAYS') return diff >= 0 && diff <= 30;
            return true;
        });

        const productIdsWithMatchingLots = new Set(matchingLots.map(l => l.productId));

        return products.filter(p => {
            const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.id.includes(searchTerm);
            const matchesValidity = productIdsWithMatchingLots.has(p.id) || (validityFilter === 'ALL');
            return matchesSearch && matchesValidity;
        });
    }, [products, lots, searchTerm, validityFilter]);

    const productLotsMap = useMemo(() => {
        const map = new Map<string, InventoryLot[]>();
        lots.forEach(lot => {
            const list = map.get(lot.productId) || [];
            list.push(lot);
            map.set(lot.productId, list);
        });
        return map;
    }, [lots]);

    const toggleProduct = (id: string) => {
        setExpandedProducts(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            return next;
        });
    };

    return (
        <div className="space-y-6">
            <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
                    <h2 className="text-xl font-black text-gray-800 dark:text-gray-100 uppercase tracking-tight flex items-center gap-2">
                        <Calendar className="text-theme-primary" /> Controle de Validades
                    </h2>
                    <div className="relative w-full md:w-80">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                        <input type="text" placeholder="Buscar produto..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 rounded-xl border dark:bg-gray-900 dark:border-gray-700"/>
                    </div>
                </div>

                <div className="flex flex-wrap gap-2 mb-6">
                    <button onClick={() => setValidityFilter('ALL')} className={`px-4 py-2 rounded-full text-xs font-black uppercase transition-all ${validityFilter === 'ALL' ? 'bg-gray-800 text-white' : 'bg-gray-100 text-gray-500'}`}>Todos</button>
                    <button onClick={() => setValidityFilter('EXPIRED')} className={`px-4 py-2 rounded-full text-xs font-black uppercase transition-all ${validityFilter === 'EXPIRED' ? 'bg-red-600 text-white' : 'bg-red-50 text-red-600'}`}>Vencidos</button>
                    <button onClick={() => setValidityFilter('CRITICAL')} className={`px-4 py-2 rounded-full text-xs font-black uppercase transition-all ${validityFilter === 'CRITICAL' ? 'bg-orange-500 text-white' : 'bg-orange-50 text-orange-600'}`}>Vencendo em 7 dias</button>
                    <button onClick={() => setValidityFilter('30DAYS')} className={`px-4 py-2 rounded-full text-xs font-black uppercase transition-all ${validityFilter === '30DAYS' ? 'bg-yellow-500 text-white' : 'bg-yellow-50 text-yellow-600'}`}>Vencendo em 30 dias</button>
                </div>

                <div className="overflow-hidden border border-gray-100 dark:border-gray-700 rounded-xl">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-50 dark:bg-gray-900/80 text-[10px] uppercase font-black text-gray-400">
                            <tr>
                                <th className="px-6 py-4 w-12"></th>
                                <th className="px-6 py-4">Produto</th>
                                <th className="px-6 py-4 text-right">Estoque Global</th>
                                <th className="px-6 py-4 text-center">Alertas</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                            {filteredData.map(product => {
                                const prodLots = productLotsMap.get(product.id) || [];
                                const hasAlert = prodLots.some(l => {
                                    const s = getLotStatus(l);
                                    return s.type === 'EXPIRED' || s.type === 'CRITICAL';
                                });

                                return (
                                    <React.Fragment key={product.id}>
                                        <tr className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors">
                                            <td className="px-6 py-4 cursor-pointer" onClick={() => toggleProduct(product.id)}>
                                                {expandedProducts.has(product.id) ? <ChevronUp size={16}/> : <ChevronDown size={16}/>}
                                            </td>
                                            <td className="px-6 py-4 font-bold text-gray-700 dark:text-gray-200">{product.name}</td>
                                            <td className="px-6 py-4 text-right font-mono font-bold text-theme-primary">{product.stock} {product.isBulk ? 'kg' : 'un'}</td>
                                            <td className="px-6 py-4 text-center">
                                                {hasAlert && <AlertTriangle size={18} className="text-red-500 inline animate-pulse" />}
                                            </td>
                                        </tr>
                                        {expandedProducts.has(product.id) && (
                                            <tr className="bg-gray-50/50 dark:bg-gray-900/30">
                                                <td colSpan={4} className="px-12 py-4">
                                                    <div className="space-y-2">
                                                        <div className="flex justify-between items-center mb-2">
                                                            <p className="text-[10px] font-black text-gray-400 uppercase">Lotes em Estoque</p>
                                                            <Button variant="secondary" size="sm" onClick={() => setHistoryProductId(product.id)}>
                                                                <History size={12} className="mr-1"/> Histórico Geral
                                                            </Button>
                                                        </div>
                                                        {prodLots.map(lot => {
                                                            const status = getLotStatus(lot);
                                                            return (
                                                                <div key={lot.id} className={`flex justify-between items-center p-3 rounded-xl border ${status.color || 'bg-white dark:bg-gray-800'}`}>
                                                                    <div>
                                                                        <p className="text-xs font-bold uppercase">{status.label}</p>
                                                                        <p className="text-[10px] text-gray-500">Quantidade: <span className="font-bold text-gray-700 dark:text-gray-200">{lot.quantity}</span></p>
                                                                    </div>
                                                                    <div className="flex gap-2">
                                                                        <Button 
                                                                            variant="secondary" 
                                                                            size="sm" 
                                                                            onClick={() => setEditingLot(lot)}
                                                                            title="Editar lote/validade"
                                                                        >
                                                                            <Pencil size={12}/>
                                                                        </Button>
                                                                    </div>
                                                                </div>
                                                            );
                                                        })}
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </React.Fragment>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>

            {historyProductId && (
                <AdjustmentHistoryModal isOpen={!!historyProductId} onClose={() => setHistoryProductId(null)} productId={historyProductId} />
            )}

            <EditLotModal 
                isOpen={!!editingLot} 
                onClose={() => setEditingLot(null)} 
                lot={editingLot} 
                onSave={fetchData} 
            />
        </div>
    );
};

export default InventoryReport;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { db } from '../../services/databaseService';
import type { Product, InventoryLot } from '../../types';
import Button from '../shared/Button';
import AdjustmentHistoryModal from './AdjustmentHistoryModal';
import EditLotModal from './EditLotModal';
import { ChevronDown, ChevronUp, History, Calendar, AlertTriangle, Search, Pencil, Filter } from 'lucide-react';

type ValidityPeriod = 'ALL' | 'EXPIRED' | '7DAYS' | '15DAYS' | '30DAYS' | '60DAYS' | '90DAYS' | '180DAYS';

const InventoryReport: React.FC = () => {
    const [products, setProducts] = useState<Product[]>([]);
    const [lots, setLots] = useState<InventoryLot[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [validityFilter, setValidityFilter] = useState<ValidityPeriod>('ALL');
    const [expandedProducts, setExpandedProducts] = useState<Set<string>>(new Set());
    const [historyProductId, setHistoryProductId] = useState<string | null>(null);
    const [editingLot, setEditingLot] = useState<InventoryLot | null>(null);

    const fetchData = useCallback(async () => {
        const [allProducts, allLots] = await Promise.all([
            db.getAll('products'),
            db.getAll('inventoryLots')
        ]);
        setProducts(allProducts);
        setLots(allLots);
    }, []);

    useEffect(() => { fetchData(); }, [fetchData]);

    const getLotStatus = (lot: InventoryLot) => {
        if (!lot.expirationDate) return { type: 'OK', label: 'Sem validade' };
        const today = new Date(); today.setHours(0,0,0,0);
        const exp = new Date(lot.expirationDate); exp.setHours(0,0,0,0);
        const diff = Math.ceil((exp.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

        if (diff < 0) return { type: 'EXPIRED', label: `Vencido há ${Math.abs(diff)} dias`, color: 'text-red-600 bg-red-50 border-red-200' };
        if (diff <= 7) return { type: 'CRITICAL', label: `Vence em ${diff} dias!`, color: 'text-orange-600 bg-orange-50 border-orange-200' };
        if (diff <= 30) return { type: 'WARNING', label: `Vence em ${diff} dias`, color: 'text-yellow-600 bg-yellow-50 border-yellow-200' };
        return { type: 'OK', label: `Vencimento: ${exp.toLocaleDateString('pt-BR')}`, color: 'bg-white dark:bg-gray-800 border-gray-100' };
    };

    const filteredData = useMemo(() => {
        const today = new Date(); today.setHours(0,0,0,0);

        const daysMap: Record<ValidityPeriod, number | null> = {
            'ALL': null,
            'EXPIRED': -1,
            '7DAYS': 7,
            '15DAYS': 15,
            '30DAYS': 30,
            '60DAYS': 60,
            '90DAYS': 90,
            '180DAYS': 180
        };

        const maxDays = daysMap[validityFilter];

        const matchingLots = lots.filter(lot => {
            if (validityFilter === 'ALL') return true;
            if (!lot.expirationDate) return false;
            const exp = new Date(lot.expirationDate); exp.setHours(0,0,0,0);
            const diff = (exp.getTime() - today.getTime()) / (1000 * 60 * 60 * 24);

            if (validityFilter === 'EXPIRED') return diff < 0;
            if (maxDays !== null) return diff >= 0 && diff <= maxDays;
            return true;
        });

        const productIdsWithMatchingLots = new Set(matchingLots.map(l => l.productId));

        return products.filter(p => {
            const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.id.includes(searchTerm);
            const matchesValidity = productIdsWithMatchingLots.has(p.id) || (validityFilter === 'ALL');
            return matchesSearch && matchesValidity;
        });
    }, [products, lots, searchTerm, validityFilter]);

    const productLotsMap = useMemo(() => {
        const map = new Map<string, InventoryLot[]>();
        lots.forEach(lot => {
            const list = map.get(lot.productId) || [];
            list.push(lot);
            map.set(lot.productId, list);
        });
        return map;
    }, [lots]);

    const toggleProduct = (id: string) => {
        setExpandedProducts(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            return next;
        });
    };

    const filterOptions = [
        { id: 'ALL', label: 'Todos os Itens' },
        { id: 'EXPIRED', label: 'Já Vencidos' },
        { id: '7DAYS', label: 'Próximos 7 dias' },
        { id: '15DAYS', label: 'Próximos 15 dias' },
        { id: '30DAYS', label: 'Próximo 1 mês' },
        { id: '60DAYS', label: 'Próximos 2 meses' },
        { id: '90DAYS', label: 'Próximos 3 meses' },
        { id: '180DAYS', label: 'Próximos 6 meses' },
    ];

    return (
        <div className="space-y-6">
            <div className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
                    <div>
                        <h2 className="text-2xl font-black text-gray-800 dark:text-gray-100 uppercase tracking-tight flex items-center gap-3">
                            <Calendar className="text-theme-primary" size={28} /> Inteligência de Validade
                        </h2>
                        <p className="text-xs text-gray-400 font-bold uppercase mt-1 tracking-widest">Previsão e Monitoramento de Lotes</p>
                    </div>

                    <div className="flex flex-col md:flex-row gap-3 w-full md:w-auto">
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                            <input 
                                type="text" 
                                placeholder="Filtrar por nome do produto..." 
                                value={searchTerm} 
                                onChange={e => setSearchTerm(e.target.value)} 
                                className="w-full md:w-64 pl-10 pr-4 py-3 rounded-2xl border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 focus:ring-2 focus:ring-theme-primary outline-none transition-all"
                            />
                        </div>

                        <div className="relative">
                            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                            <select 
                                value={validityFilter} 
                                onChange={e => setValidityFilter(e.target.value as ValidityPeriod)}
                                className="w-full md:w-64 pl-10 pr-4 py-3 rounded-2xl border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 focus:ring-2 focus:ring-theme-primary outline-none appearance-none font-bold text-xs uppercase tracking-wider cursor-pointer"
                            >
                                {filterOptions.map(opt => (
                                    <option key={opt.id} value={opt.id}>{opt.label}</option>
                                ))}
                            </select>
                        </div>
                    </div>
                </div>

                <div className="overflow-hidden border border-gray-100 dark:border-gray-700 rounded-2xl">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-50 dark:bg-gray-900/80 text-[10px] uppercase font-black text-gray-400 border-b dark:border-gray-700">
                            <tr>
                                <th className="px-6 py-5 w-12"></th>
                                <th className="px-6 py-5">Produto / Descrição</th>
                                <th className="px-6 py-5 text-right">Saldo Global</th>
                                <th className="px-6 py-5 text-center">Status Crítico</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                            {filteredData.map(product => {
                                const prodLots = (productLotsMap.get(product.id) || []).sort((a,b) => {
                                    if (!a.expirationDate) return 1;
                                    if (!b.expirationDate) return -1;
                                    return new Date(a.expirationDate).getTime() - new Date(b.expirationDate).getTime();
                                });

                                const hasAlert = prodLots.some(l => {
                                    const s = getLotStatus(l);
                                    return s.type === 'EXPIRED' || s.type === 'CRITICAL';
                                });

                                return (
                                    <React.Fragment key={product.id}>
                                        <tr className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors group">
                                            <td className="px-6 py-4 cursor-pointer" onClick={() => toggleProduct(product.id)}>
                                                <div className={`p-1.5 rounded-lg transition-all ${expandedProducts.has(product.id) ? 'bg-theme-primary text-white' : 'bg-gray-100 text-gray-400 group-hover:bg-gray-200'}`}>
                                                    {expandedProducts.has(product.id) ? <ChevronUp size={16}/> : <ChevronDown size={16}/>}
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <p className="font-black text-gray-700 dark:text-gray-200 uppercase tracking-tight">{product.name}</p>
                                                <p className="text-[10px] text-gray-400 font-bold uppercase">{product.brand || 'Marca Própria'}</p>
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <span className="font-mono font-black text-theme-primary text-lg">
                                                    {product.stock.toFixed(2)}
                                                </span>
                                                <span className="ml-1 text-[10px] font-black text-gray-400 uppercase">{product.isBulk ? 'kg' : 'un'}</span>
                                            </td>
                                            <td className="px-6 py-4 text-center">
                                                {hasAlert && <AlertTriangle size={20} className="text-red-500 inline animate-pulse" />}
                                            </td>
                                        </tr>
                                        {expandedProducts.has(product.id) && (
                                            <tr className="bg-gray-50/30 dark:bg-gray-900/40">
                                                <td colSpan={4} className="px-10 py-6">
                                                    <div className="space-y-3">
                                                        <div className="flex justify-between items-center px-2">
                                                            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Rastreamento de Lotes Ativos</p>
                                                            <Button variant="secondary" size="sm" onClick={() => setHistoryProductId(product.id)} className="!text-[9px] !py-1 !px-2 rounded-lg">
                                                                <History size={12} className="mr-1"/> Ver Auditoria
                                                            </Button>
                                                        </div>
                                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                                            {prodLots.map(lot => {
                                                                const status = getLotStatus(lot);
                                                                return (
                                                                    <div key={lot.id} className={`flex justify-between items-center p-4 rounded-2xl border transition-all shadow-sm ${status.color}`}>
                                                                        <div className="flex items-center gap-4">
                                                                            <div className={`p-2 rounded-xl bg-white/50 dark:bg-black/20 ${status.type === 'EXPIRED' ? 'text-red-600' : 'text-gray-500'}`}>
                                                                                <Calendar size={18} />
                                                                            </div>
                                                                            <div>
                                                                                <p className="text-xs font-black uppercase leading-tight">{status.label}</p>
                                                                                <p className="text-[10px] font-bold text-gray-500/80 mt-0.5">Qtd: {lot.quantity.toFixed(3)} | Custo: {lot.costPrice.toLocaleString('pt-BR', {style: 'currency', currency:'BRL'})}</p>
                                                                            </div>
                                                                        </div>
                                                                        <button 
                                                                            onClick={() => setEditingLot(lot)}
                                                                            className="p-2 hover:bg-white/50 dark:hover:bg-black/20 rounded-xl transition-colors text-gray-400 hover:text-theme-primary"
                                                                            title="Editar lote/validade"
                                                                        >
                                                                            <Pencil size={14}/>
                                                                        </button>
                                                                    </div>
                                                                );
                                                            })}
                                                        </div>
                                                        {prodLots.length === 0 && (
                                                            <div className="p-4 text-center border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-2xl text-gray-400 uppercase text-[10px] font-black">
                                                                Nenhum lote vinculado a este produto
                                                            </div>
                                                        )}
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </React.Fragment>
                                );
                            })}
                        </tbody>
                    </table>
                </div>

                {filteredData.length === 0 && (
                    <div className="text-center py-20">
                         <div className="inline-block p-6 bg-gray-100 dark:bg-gray-900 rounded-full mb-4">
                            <Search size={48} className="text-gray-300" />
                         </div>
                         <p className="text-gray-400 font-black uppercase text-xs tracking-widest">Nenhum item encontrado para este período</p>
                    </div>
                )}
            </div>

            {historyProductId && (
                <AdjustmentHistoryModal isOpen={!!historyProductId} onClose={() => setHistoryProductId(null)} productId={historyProductId} />
            )}

            <EditLotModal 
                isOpen={!!editingLot} 
                onClose={() => setEditingLot(null)} 
                lot={editingLot} 
                onSave={fetchData} 
            />
        </div>
    );
};

export default InventoryReport;

// services/databaseService.ts
import { openDB, type IDBPDatabase, type DBSchema } from 'idb';
import type { Product, Sale, CashSession, Supplier, Customer, Expense, Segment, Campaign, AutomationRule, InventoryLot, InventoryAdjustment, ParkedSale, Category, Coupon, FiscalConfig, SyncJob, Employee, AuditLog, FinancialEntry, HistoricalCashEntry, DeliveryZone, StoreSettings } from '../types';
import { v4 as uuidv4 } from 'uuid';

interface AppDB extends DBSchema {
  products: { key: string; value: Product; indexes: { name: string; scaleCode: string; categoryId: string; supplierId: string; }; };
  sales: { key: string; value: Sale; indexes: { date: Date; customerId: string }; };
  parkedSales: { key: string; value: ParkedSale; indexes: { createdAt: Date }; };
  cashSessions: { key: string; value: CashSession; indexes: { startDate: Date }; };
  categories: { key: string; value: Category; indexes: { name: string; }; };
  suppliers: { key: string; value: Supplier; indexes: { name: string, cnpj: string }; };
  customers: { key: string; value: Customer; indexes: { name: string; cpf: string }; };
  expenses: { key: string; value: Expense; indexes: { dueDate: Date; status: string }; };
  inventoryLots: { key: string; value: InventoryLot; indexes: { productId: string; expirationDate: string }; };
  inventoryAdjustments: { key: string; value: InventoryAdjustment; indexes: { productId: string; date: Date }; };
  segments: { key: string; value: Segment; indexes: { name: string }; };
  campaigns: { key: string; value: Campaign; indexes: { name: string; status: string }; };
  automationRules: { key: string; value: AutomationRule; indexes: { trigger: string; isActive: number }; };
  coupons: { key: string; value: Coupon; indexes: { code: string }; };
  fiscalConfig: { key: string; value: FiscalConfig; };
  syncQueue: { key: string; value: SyncJob; indexes: { status: string, type: string }; };
  employees: { key: string; value: Employee; indexes: { status: string }; };
  historicalCash: { key: string; value: HistoricalCashEntry; indexes: { date: Date, terminal: string }; };
  auditLogs: { key: string; value: AuditLog; indexes: { timestamp: Date, module: string }; };
  financialEntries: { key: string; value: FinancialEntry; indexes: { date: Date, type: string, category: string }; };
  deliveryZones: { key: string; value: DeliveryZone; indexes: { neighborhood: string }; };
  storeSettings: { key: string; value: StoreSettings; };
}

let db: IDBPDatabase<AppDB>;

export async function initDB() {
  if (db) return; 

  db = await openDB<AppDB>('BemEstarPDV', 19, {
    upgrade(database, oldVersion, newVersion, transaction) {
      if (oldVersion < 1) {
        database.createObjectStore('products', { keyPath: 'id' }).createIndex('name', 'name');
        database.createObjectStore('sales', { keyPath: 'id' }).createIndex('date', 'date');
        database.createObjectStore('cashSessions', { keyPath: 'id' }).createIndex('startDate', 'startDate');
        database.createObjectStore('suppliers', { keyPath: 'id' }).createIndex('cnpj', 'cnpj');
        database.createObjectStore('customers', { keyPath: 'id' }).createIndex('cpf', 'cpf');
        database.createObjectStore('expenses', { keyPath: 'id' }).createIndex('dueDate', 'dueDate');
        database.createObjectStore('segments', { keyPath: 'id' }).createIndex('name', 'name');
        database.createObjectStore('campaigns', { keyPath: 'id' }).createIndex('name', 'name');
        database.createObjectStore('automationRules', { keyPath: 'id' });
        database.createObjectStore('inventoryLots', { keyPath: 'id' }).createIndex('productId', 'productId');
        database.createObjectStore('inventoryAdjustments', { keyPath: 'id' }).createIndex('productId', 'productId');
        database.createObjectStore('parkedSales', { keyPath: 'id' }).createIndex('createdAt', 'createdAt');
        database.createObjectStore('categories', { keyPath: 'id' }).createIndex('name', 'name');
        database.createObjectStore('coupons', { keyPath: 'id' }).createIndex('code', 'code');
        database.createObjectStore('fiscalConfig', { keyPath: 'id' });
        database.createObjectStore('syncQueue', { keyPath: 'id' }).createIndex('status', 'status');
        database.createObjectStore('employees', { keyPath: 'id' }).createIndex('status', 'status');
        const cashStore = database.createObjectStore('historicalCash', { keyPath: 'id' });
        cashStore.createIndex('date', 'date');
        cashStore.createIndex('terminal', 'terminal');
        database.createObjectStore('auditLogs', { keyPath: 'id' }).createIndex('timestamp', 'timestamp');
        database.createObjectStore('financialEntries', { keyPath: 'id' }).createIndex('date', 'date');
      }

      if (!database.objectStoreNames.contains('deliveryZones')) {
        database.createObjectStore('deliveryZones', { keyPath: 'id' }).createIndex('neighborhood', 'neighborhood');
      }
      if (!database.objectStoreNames.contains('storeSettings')) {
        database.createObjectStore('storeSettings', { keyPath: 'id' });
      }
    },
  });
  await seedInitialData();
}

async function seedInitialData() {
    try {
        const productCount = await db.count('products');
        if (productCount === 0) {
            const tx = db.transaction(['categories', 'products', 'inventoryLots'], 'readwrite');
            const catGranelId = uuidv4();
            const catEmpacotadosId = uuidv4();

            await tx.objectStore('categories').put({ id: catGranelId, name: 'Produtos a Granel' });
            await tx.objectStore('categories').put({ id: catEmpacotadosId, name: 'Cereais & Matinais' });

            const today = new Date();
            const futureVal = new Date();
            futureVal.setMonth(futureVal.getMonth() + 8);

            const seedProducts = [
                { name: "Castanha do Pará Inteira", brand: "Bem Estar", price: 89.90, cost: 45.00, isBulk: true },
                { name: "Nozes Quartos Extra", brand: "Importação Direct", price: 110.00, cost: 65.00, isBulk: true },
                { name: "Castanha de Caju W1 Salgada", brand: "Bem Estar", price: 78.50, cost: 40.00, isBulk: true },
                { name: "Amêndoa Chilena Crua", brand: "Naturals", price: 95.00, cost: 52.00, isBulk: true },
                { name: "Pistache com Casca Torrado", brand: "Naturals", price: 135.00, cost: 80.00, isBulk: true },
                { name: "Aveia em Flocos Finos 500g", brand: "Qualitá", price: 12.90, cost: 6.50, isBulk: false },
                { name: "Granola Artesanal com Mel", brand: "Cozinha Natural", price: 42.00, cost: 22.00, isBulk: true },
                { name: "Quinoa em Grãos Branca", brand: "Andes Food", price: 35.00, cost: 18.00, isBulk: true },
                { name: "Mix de Sementes Omega 3", brand: "Bem Estar", price: 55.00, cost: 28.00, isBulk: true },
                { name: "Cereal de Milho Sem Açúcar", brand: "CornFit", price: 24.90, cost: 11.00, isBulk: true }
            ];

            for (const item of seedProducts) {
                const pid = uuidv4();
                await tx.objectStore('products').put({
                    id: pid,
                    name: item.name,
                    brand: item.brand,
                    price: item.price,
                    costPrice: item.cost,
                    stock: 50,
                    isBulk: item.isBulk,
                    categoryId: item.isBulk ? catGranelId : catEmpacotadosId
                });

                await tx.objectStore('inventoryLots').put({
                    id: uuidv4(),
                    productId: pid,
                    quantity: 50,
                    entryDate: today,
                    expirationDate: futureVal,
                    costPrice: item.cost
                });
            }

            await tx.done;
        }
    } catch (e) {
        console.warn("Erro ao realizar seed de produtos naturais:", e);
    }
}

export { db };

