interface ERPScreenProps {
    setView: (view: 'pos' | 'erp' | 'crm' | 'fiscal') => void;
}

type ActiveModule = 'products' | 'categories' | 'customers' | 'suppliers' | 'financial' | 'expenses' | 'reports' | 'nfeImport' | 'inventory' | 'generateOrder' | 'dre' | 'hr' | 'cashAudit' | 'deliveryZones' | 'generalSettings';

type ERPView = 
  | { type: 'module', id: ActiveModule }
  | { type: 'product_form', productId?: string }
  | { type: 'customer_form', customerId?: string }
  | { type: 'category_form', categoryId?: string }
  | { type: 'expense_form', expenseId?: string }
  | { type: 'supplier_form', supplierId?: string };


interface MenuItem { id: ActiveModule; label: string; }
interface MenuModule { id: string; label: string; icon: React.ElementType; items: MenuItem[]; }

const menuModules: MenuModule[] = [
    {
        id: 'estrategico',
        label: 'Gestão Estratégica',
        icon: BrainCircuit,
        items: [
            { id: 'dre', label: 'Painel DRE / Lucro' },
            { id: 'cashAudit', label: 'Controle de Caixa' },
            { id: 'hr', label: 'Equipe e RH' },
        ],
    },
    {
        id: 'estoque',
        label: 'Estoque',
        icon: Boxes,
        items: [
            { id: 'products', label: 'Produtos' },
            { id: 'categories', label: 'Categorias' },
            { id: 'inventory', label: 'Inventário e Validade' },
        ],
    },
    {
        id: 'compras',
        label: 'Compras & Suprimentos',
        icon: ShoppingCart,
        items: [
            { id: 'suppliers', label: 'Fornecedores' },
            { id: 'generateOrder', label: 'Sugestão de Pedidos' },
            { id: 'nfeImport', label: 'Importar NF-e XML' },
        ],
    },
    {
        id: 'clientes',
        label: 'Clientes',
        icon: Users,
        items: [ { id: 'customers', label: 'Base de Clientes' } ],
    },
    {
        id: 'financeiro',
        label: 'Financeiro',
        icon: BarChart,
        items: [
            { id: 'expenses', label: 'Contas a Pagar' },
        ],
    },
    {
        id: 'configuracoes',
        label: 'Configurações',
        icon: Settings2,
        items: [
            { id: 'generalSettings', label: 'Backup e WhatsApp' },
            { id: 'deliveryZones', label: 'Bairros e Fretes' },
        ],
    },
];

const ERPScreen: React.FC<ERPScreenProps> = ({ setView }) => {
    const [currentErpView, setCurrentErpView] = useState<ERPView>({ type: 'module', id: 'dre' }); 
    const [expandedSections, setExpandedSections] = useState<Set<string>>(new Set(['estrategico', 'estoque', 'compras', 'financeiro', 'configuracoes']));
    const [categories, setCategories] = useState<Category[]>([]);

    useEffect(() => {
        db.getAll('categories').then(cats => setCategories(cats.sort((a,b) => a.name.localeCompare(b.name))));
    }, []);

    const toggleSection = (sectionId: string) => {
        setExpandedSections(prev => {
            const newSet = new Set(prev);
            if (newSet.has(sectionId)) newSet.delete(sectionId);
            else newSet.add(sectionId);
            return newSet;
        });
    };

    const renderActiveModule = () => {
        switch(currentErpView.type) {
            case 'product_form': return <ProductFormPage productId={currentErpView.productId} categories={categories} onBack={() => setCurrentErpView({ type: 'module', id: 'products' })} />;
            case 'customer_form': return <CustomerFormPage customerId={currentErpView.customerId} onBack={() => setCurrentErpView({ type: 'module', id: 'customers' })} />;
            case 'category_form': return <CategoryFormPage categoryId={currentErpView.categoryId} onBack={() => setCurrentErpView({ type: 'module', id: 'categories' })} />;
            case 'expense_form': return <ExpenseFormPage expenseId={currentErpView.expenseId} onBack={() => setCurrentErpView({ type: 'module', id: 'expenses' })} />;
            case 'supplier_form': return <SupplierFormPage supplierId={currentErpView.supplierId} onBack={() => setCurrentErpView({ type: 'module', id: 'suppliers' })} />;
            case 'module':
                switch(currentErpView.id) {
                    case 'dre': return <DREDashboard />;
                    case 'hr': return <HRManagement />;
                    case 'cashAudit': return <CashAudit />;
                    case 'deliveryZones': return <DeliveryZones />;
                    case 'generalSettings': return <GeneralSettings />;
                    case 'products': return <ProductManagement onNewProduct={() => setCurrentErpView({ type: 'product_form' })} onEditProduct={(id) => setCurrentErpView({ type: 'product_form', productId: id })} onImportXML={() => setCurrentErpView({ type: 'module', id: 'nfeImport' })} />;
                    case 'categories': return <CategoryManagement onNewCategory={() => setCurrentErpView({ type: 'category_form' })} onEditCategory={(id) => setCurrentErpView({ type: 'category_form', categoryId: id })} />;
                    case 'customers': return <CustomerManagement onNewCustomer={() => setCurrentErpView({ type: 'customer_form' })} onEditCustomer={(id) => setCurrentErpView({ type: 'customer_form', customerId: id })} />;
                    case 'suppliers': return <SupplierManagement onNewSupplier={() => setCurrentErpView({ type: 'supplier_form' })} onEditSupplier={(id) => setCurrentErpView({ type: 'supplier_form', supplierId: id })} />;
                    case 'expenses': return <ExpenseManagement onNewExpense={() => setCurrentErpView({ type: 'expense_form' })} onEditExpense={(id) => setCurrentErpView({ type: 'expense_form', expenseId: id })} />;
                    case 'nfeImport': return <NFeImport />;
                    case 'generateOrder': return <GenerateOrder />;
                    case 'inventory': return <InventoryReport />;
                    default: return <div className="p-8">Módulo em construção</div>;
                }
        }
    };

    const getHeaderInfo = () => {
        if (currentErpView.type === 'module') {
            const label = menuModules.flatMap(m => m.items).find(i => i.id === currentErpView.id)?.label || 'Dashboard';
            return { title: label, activeModule: currentErpView.id, backAction: null as (() => void) | null };
        }

        switch(currentErpView.type) {
            case 'product_form': 
                return { title: 'Editar Produto', activeModule: 'products' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'products' }) };
            case 'customer_form': 
                return { title: 'Editar Cliente', activeModule: 'customers' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'customers' }) };
            case 'category_form': 
                return { title: 'Editar Categoria', activeModule: 'categories' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'categories' }) };
            case 'expense_form': 
                return { title: 'Editar Despesa', activeModule: 'expenses' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'expenses' }) };
            case 'supplier_form':
                return { title: 'Editar Fornecedor', activeModule: 'suppliers' as ActiveModule, backAction: () => setCurrentErpView({ type: 'module', id: 'suppliers' }) };
            default:
                return { title: 'ERP', activeModule: 'dre' as ActiveModule, backAction: null as (() => void) | null };
        }
    };
    const { title, activeModule, backAction } = getHeaderInfo();

    return (
        <div className="flex flex-col md:flex-row h-full bg-gray-100 dark:bg-gray-900">
            <aside className="w-full md:w-64 bg-white dark:bg-gray-800 shadow-md md:shadow-none md:border-r dark:border-gray-700 flex flex-col order-1 shrink-0 overflow-y-auto">
                <div className="hidden md:block p-4 border-b dark:border-gray-700">
                    <h1 className="text-xl font-bold text-gray-800 dark:text-gray-100 uppercase tracking-tighter">Gestão BI</h1>
                    <span className="text-[10px] font-black text-theme-primary">BEMESTAR v2.0</span>
                </div>
                <nav className="flex-grow md:p-2">
                    <ul className="flex flex-col md:p-0 gap-1">
                        {menuModules.map(module => {
                            const isExpanded = expandedSections.has(module.id);
                            return (
                                <li key={module.id} className="flex flex-col">
                                    <button onClick={() => toggleSection(module.id)} className="flex items-center justify-between w-full gap-3 px-4 py-2 rounded-md text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-theme-primary transition-all">
                                        <div className="flex items-center gap-3"><module.icon className="w-4 h-4" /><span>{module.label}</span></div>
                                        {isExpanded ? <ChevronUp size={12} /> : <ChevronDown size={12} />}
                                    </button>
                                    <ul className={`flex flex-col gap-1 pl-6 mt-1 mb-2 ${!isExpanded ? 'hidden' : ''}`}>
                                        {module.items.map(item => (
                                            <li key={item.id}>
                                                <a href="#" onClick={(e) => { e.preventDefault(); setCurrentErpView({ type: 'module', id: item.id }); }} 
                                                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${activeModule === item.id ? 'bg-theme-primary text-white' : 'text-gray-500 hover:bg-gray-50 dark:hover:bg-gray-700 dark:text-gray-400'}`}>
                                                    <span>{item.label}</span>
                                                </a>
                                            </li>
                                        ))}
                                    </ul>
                                </li>
                            );
                        })}
                    </ul>
                </nav>
            </aside>
            <main className="flex-1 flex flex-col overflow-hidden order-2 h-full">
                <header className="bg-white dark:bg-gray-800 shadow-sm p-4 flex items-center gap-4 shrink-0">
                    {backAction && <Button variant="secondary" onClick={backAction} className="!py-2 !px-3"><ArrowLeft size={16} className="mr-2"/> Voltar</Button>}
                    <h2 className="text-xl md:text-2xl font-black text-gray-800 dark:text-gray-100 capitalize truncate tracking-tight">{title}</h2>
                </header>
                <div className="flex-1 overflow-y-auto p-4 md:p-6">
                    {activeModule === 'dre' && <ValidityAlertBanner onAction={() => setCurrentErpView({ type: 'module', id: 'inventory' })} />}
                    {renderActiveModule()}
                </div>
            </main>
        </div>
    );
};

export default ERPScreen;

import React, { useState, useEffect, useCallback } from 'react';
import { db } from '../../services/databaseService';
import type { Supplier } from '../../types';
import Button from '../shared/Button';
import { PlusCircle, Edit, Trash2, Search, Truck, Phone, Mail, Globe } from 'lucide-react';

interface SupplierManagementProps {
    onNewSupplier: () => void;
    onEditSupplier: (id: string) => void;
}

const SupplierManagement: React.FC<SupplierManagementProps> = ({ onNewSupplier, onEditSupplier }) => {
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [searchTerm, setSearchTerm] = useState('');

    const fetchSuppliers = useCallback(async () => {
        const all = await db.getAll('suppliers');
        setSuppliers(all.sort((a, b) => a.name.localeCompare(b.name)));
    }, []);

    useEffect(() => {
        fetchSuppliers();
    }, [fetchSuppliers]);

    const handleDelete = async (id: string) => {
        // Verifica se existem produtos vinculados
        const products = await db.getAll('products');
        const hasProducts = products.some(p => p.supplierId === id);

        if (hasProducts) {
            alert('Não é possível excluir este fornecedor pois existem produtos vinculados a ele.');
            return;
        }

        if (confirm('Tem certeza que deseja excluir este fornecedor?')) {
            await db.delete('suppliers', id);
            fetchSuppliers();
        }
    };

    const filteredSuppliers = suppliers.filter(s => 
        s.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        s.cnpj.includes(searchTerm) ||
        s.contactPerson?.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="space-y-4">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700">
                <div className="relative w-full md:w-96">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                    <input 
                        type="text" 
                        placeholder="Nome, CNPJ ou Contato..."
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 rounded-lg border dark:bg-gray-800 dark:border-gray-700 outline-none focus:ring-2 focus:ring-theme-primary"
                    />
                </div>
                <Button onClick={onNewSupplier}>
                    <PlusCircle size={18}/> Novo Fornecedor
                </Button>
            </div>

            <div className="bg-white dark:bg-gray-800 rounded-xl shadow border border-gray-100 dark:border-gray-700 overflow-hidden">
                <table className="w-full text-sm text-left">
                    <thead className="bg-gray-50 dark:bg-gray-700/50 text-[10px] uppercase font-black text-gray-400">
                        <tr>
                            <th className="px-6 py-4">Razão Social / Nome</th>
                            <th className="px-6 py-4 text-center">CNPJ</th>
                            <th className="px-6 py-4">Contato / Representante</th>
                            <th className="px-6 py-4 text-center">Ações</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                        {filteredSuppliers.map(supplier => (
                            <tr key={supplier.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors group">
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-gray-100 dark:bg-gray-900 rounded-lg text-gray-500">
                                            <Truck size={18} />
                                        </div>
                                        <div>
                                            <p className="font-bold text-gray-800 dark:text-gray-100 uppercase tracking-tight">{supplier.name}</p>
                                            {supplier.email && (
                                                <div className="flex items-center gap-1 text-[10px] text-gray-400 font-bold">
                                                    <Mail size={10} /> {supplier.email}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </td>
                                <td className="px-6 py-4 text-center font-mono text-xs text-gray-500">
                                    {supplier.cnpj}
                                </td>
                                <td className="px-6 py-4">
                                    <p className="font-bold text-gray-600 dark:text-gray-300 text-xs">{supplier.contactPerson || 'Não informado'}</p>
                                    {supplier.phone && (
                                        <div className="flex items-center gap-1 text-[10px] text-theme-primary font-black uppercase">
                                            <Phone size={10} /> {supplier.phone}
                                        </div>
                                    )}
                                </td>
                                <td className="px-6 py-4 text-center">
                                    <div className="flex justify-center gap-2">
                                        <Button variant="secondary" className="!p-2 h-auto" onClick={() => onEditSupplier(supplier.id)}>
                                            <Edit size={16}/>
                                        </Button>
                                        <Button variant="danger" className="!p-2 h-auto" onClick={() => handleDelete(supplier.id)}>
                                            <Trash2 size={16}/>
                                        </Button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {filteredSuppliers.length === 0 && (
                    <div className="p-20 text-center text-gray-400 flex flex-col items-center gap-4">
                        <Truck size={48} className="opacity-10" />
                        <p className="font-bold uppercase text-xs tracking-widest">Nenhum fornecedor cadastrado</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default SupplierManagement;

import React, { useState, useEffect } from 'react';
import { db } from '../../services/databaseService';
import type { Supplier } from '../../types';
import Button from '../shared/Button';
import { Save, Truck, Building, User, Phone, Mail, MapPin, Hash } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface SupplierFormPageProps {
  supplierId?: string;
  onBack: () => void;
}

const SupplierFormPage: React.FC<SupplierFormPageProps> = ({ supplierId, onBack }) => {
    const [formData, setFormData] = useState<Partial<Supplier>>({});
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const fetchSupplier = async () => {
            if (supplierId) {
                const data = await db.get('suppliers', supplierId);
                if (data) setFormData(data);
            } else {
                setFormData({
                    id: uuidv4(),
                    name: '',
                    cnpj: '',
                    contactPerson: '',
                    phone: '',
                    email: ''
                });
            }
            setIsLoading(false);
        };
        fetchSupplier();
    }, [supplierId]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name || !formData.cnpj) {
            alert('Nome e CNPJ são campos obrigatórios.');
            return;
        }

        await db.put('suppliers', formData as Supplier);
        onBack();
    };

    if (isLoading) return <div className="text-center p-12 animate-pulse text-gray-400 uppercase font-black text-xs">Carregando formulário...</div>;

    const inputStyle = "mt-1 block w-full rounded-xl border border-gray-200 py-3 px-4 shadow-sm focus:border-theme-primary focus:ring-2 focus:ring-theme-primary/20 dark:border-gray-700 dark:bg-gray-800 transition-all outline-none";

    return (
        <div className="max-w-4xl mx-auto">
            <div className="bg-white dark:bg-gray-800 p-8 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                <div className="flex items-center gap-3 mb-8 text-theme-primary">
                    <div className="p-3 bg-theme-primary/10 rounded-2xl">
                        <Truck size={28} />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black uppercase tracking-tight text-gray-800 dark:text-gray-100">Ficha do Fornecedor</h2>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Gestão de Compras e Suprimentos</p>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="md:col-span-2">
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 flex items-center gap-1">
                                <Building size={12}/> Razão Social / Nome de Fantasia
                            </label>
                            <input 
                                type="text" 
                                name="name" 
                                value={formData.name || ''} 
                                onChange={handleChange} 
                                required 
                                className={inputStyle} 
                                placeholder="Ex: DISTRIBUIDORA DE PRODUTOS NATURAIS LTDA"
                            />
                        </div>

                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 flex items-center gap-1">
                                <Hash size={12}/> CNPJ
                            </label>
                            <input 
                                type="text" 
                                name="cnpj" 
                                value={formData.cnpj || ''} 
                                onChange={handleChange} 
                                required 
                                className={inputStyle + " font-mono"} 
                                placeholder="00.000.000/0000-00"
                            />
                        </div>

                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 flex items-center gap-1">
                                <User size={12}/> Pessoa de Contato / Vendedor
                            </label>
                            <input 
                                type="text" 
                                name="contactPerson" 
                                value={formData.contactPerson || ''} 
                                onChange={handleChange} 
                                className={inputStyle} 
                                placeholder="Ex: João da Distribuidora"
                            />
                        </div>

                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 flex items-center gap-1">
                                <Phone size={12}/> Telefone / WhatsApp
                            </label>
                            <input 
                                type="text" 
                                name="phone" 
                                value={formData.phone || ''} 
                                onChange={handleChange} 
                                className={inputStyle + " font-mono"} 
                                placeholder="(00) 00000-0000"
                            />
                        </div>

                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 flex items-center gap-1">
                                <Mail size={12}/> E-mail Comercial
                            </label>
                            <input 
                                type="email" 
                                name="email" 
                                value={formData.email || ''} 
                                onChange={handleChange} 
                                className={inputStyle} 
                                placeholder="vendas@fornecedor.com.br"
                            />
                        </div>
                    </div>

                    <div className="pt-8 border-t dark:border-gray-700 flex justify-end gap-3">
                        <Button type="button" variant="secondary" onClick={onBack} className="px-8 rounded-2xl">Descartar</Button>
                        <Button type="submit" variant="primary" className="px-10 rounded-2xl shadow-lg shadow-theme-primary/30">
                            <Save size={18} className="mr-2"/> Salvar Fornecedor
                        </Button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default SupplierFormPage;

// types.ts
export enum PaymentMethod {
  DINHEIRO = 'Dinheiro',
  PIX = 'PIX',
  DEBITO = 'Débito',
  CREDITO = 'Crédito',
  NOTINHA = 'Notinha', 
}

export enum OrderType {
  RETIRADA = 'Retirada',
  ENTREGA = 'Entrega'
}

export interface Product {
  id: string; // Código Interno do Produto
  barcode?: string; // Código de Barras (EAN/GTIN)
  name: string; 
  brand?: string; 
  price: number; 
  costPrice?: number; 
  isBulk: boolean; 
  scaleCode?: string; 
  stock: number; 
  minStock?: number; 
  ncm?: string; 
  cfop?: string; 
  origin?: string; 
  csosn_cst?: string; 
  image?: string; 
  categoryId?: string; 
  supplierId?: string; 
}

export interface SaleItem {
  productId: string; 
  productName: string; 
  productImage?: string; 
  unitPrice: number; 
  quantity: number; 
  discount: number; 
  total: number; 
  lotNumber?: string; 
  expirationDate?: Date; 
}

export interface Payment {
  method: PaymentMethod; 
  amount: number; 
  customerId?: string; 
}

export interface Sale {
  id: string; 
  date: Date; 
  items: SaleItem[]; 
  subtotal: number; 
  totalDiscount: number; 
  totalAmount: number; 
  payments: Payment[]; 
  change: number; 
  customerCPF?: string; 
  customerId?: string; 
  isSynced: boolean; 
  couponCodeApplied?: string; 
  manualDiscountType?: 'PERCENTAGE' | 'FIXED_AMOUNT'; 
  manualDiscountValue?: number; 
}

export interface Employee {
    id: string;
    name: string;
    roleId: string; 
    salary: number;
    status: 'ACTIVE' | 'INACTIVE';
    hireDate: Date;
    contractEndDate?: Date;
    lastVacationDate?: Date;
    shiftStart?: string; 
    lunchStart?: string; 
    lunchEnd?: string;   
    shiftEnd?: string;   
}

export interface HistoricalCashEntry {
    id: string;
    date: Date;
    terminal: string; 
    cash: number;
    pix: number;
    credit: number;
    debit: number;
    withdrawal: number;
    totalGross: number;
    totalNet: number;
}

export interface FinancialEntry {
    id: string;
    date: Date;
    type: 'REVENUE' | 'EXPENSE';
    category: string; 
    amount: number;
    referenceId?: string;
}

export interface AuditLog {
    id: string;
    timestamp: Date;
    module: string;
    action: string;
    details: string;
    userId?: string;
}

export interface DeliveryZone {
    id: string;
    neighborhood: string;
    fee: number;
}

export interface StoreSettings {
    id: 'main';
    whatsappNumber: string;
    storeName: string;
}

export interface ParkedSale { 
  id: string; 
  createdAt: Date; 
  items: SaleItem[]; 
  total: number; 
  type: OrderType; 
  customerId?: string; 
  customerName?: string; 
  deliveryAddress?: string; 
  contactPhone?: string; 
  notes?: string;
  deliveryFee?: number;
  neighborhood?: string;
}

export interface CashTransaction { type: 'SUPRIMENTO' | 'SANGRIA' | 'REFORCO'; amount: number; date: Date; description: string; }
