                { name: "Cereal de Milho Sem Açúcar", brand: "CornFit", price: 24.90, cost: 11.00, isBulk: true }
            ];

            for (const item of seedProducts) {
                const pid = uuidv4();
                await tx.objectStore('products').put({
                    id: pid,
