                )}
            </div>

            {/* Modal de Detalhes de Contas do Fornecedor */}
            <Modal
                isOpen={!!selectedSupplier}
                onClose={() => setSelectedSupplier(null)}
                title={`Histórico de Contas: ${selectedSupplier?.name}`}
