                        <div className="p-4 bg-theme-primary/10 text-theme-primary rounded-2xl">
                            <User size={32} />
                        </div>
                        <div>
                            <h2 className="text-2xl font-black uppercase tracking-tight text-gray-800 dark:text-gray-100">
                                {employeeId ? 'Atualizar Colaborador' : 'Nova Contratação'}
                            </h2>
                            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Registro Funcional Completo</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        <span className="text-[10px] font-black text-gray-400 uppercase">Estado Atual:</span>
                        <select 
                            name="status" 
                            value={formData.status} 
                            onChange={handleChange}
                            className="bg-gray-100 dark:bg-gray-700 px-4 py-2 rounded-xl text-[10px] font-black uppercase outline-none border-none cursor-pointer"
                        >
                            <option value="ACTIVE">Em Atividade</option>
                            <option value="INACTIVE">Desligado / Inativo</option>
                        </select>
                    </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                    {/* COLUNA 1 & 2: DADOS E CONTRATO */}
                    <div className="lg:col-span-2 space-y-6">

                        <div className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                            <h3 className="flex items-center gap-2 text-xs font-black text-gray-500 uppercase tracking-widest mb-6 pb-2 border-b">
                                <Briefcase size={16} className="text-theme-primary"/> Dados Pessoais e Profissionais
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                <div className="md:col-span-2">
                                    <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1">Nome Completo do Funcionário</label>
                                    <input type="text" name="name" value={formData.name} onChange={handleChange} required className={inputStyle} placeholder="Nome social completo" />
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black text-gray-400 uppercase ml-1 mb-1">Cargo / Responsabilidade</label>
